import React, { useState, useRef, useCallback, useEffect } from "react";
import { open } from "@tauri-apps/plugin-dialog";
import { getCurrentWindow } from "@tauri-apps/api/window";
import { invoke } from "@tauri-apps/api/core";
import { listen } from "@tauri-apps/api/event";

// ── Types ────────────────────────────────────────────────────
type FileStatus = "queued" | "processing" | "done" | "error";
type Units = "auto" | "metric" | "imperial";
type DateFormat = "DMY" | "MDY";
type ExMode = "Auto" | "LocalAI" | "Pattern";

interface QueueFile {
  path: string;
  name: string;
  status: FileStatus;
  msg?: string;
  pageProgress?: string;
  outputPath?: string;
}
interface LogLine {
  text: string;
  kind: "info" | "ok" | "err" | "warn";
}
interface FileResult {
  name: string;
  status: string;
  detail: string;
}
interface BatchSummary {
  total: number;
  succeeded: number;
  failed: number;
  results: FileResult[];
}

const LANGUAGES: Record<string, string> = {
  eng: "English", tha: "Thai", vie: "Vietnamese", mya: "Myanmar (Burmese)",
  khm: "Khmer", lao: "Lao", ind: "Indonesian", msa: "Malay",
  fil: "Filipino (Tagalog)", jav: "Javanese",
  chi_sim: "Chinese (Simplified)", chi_tra: "Chinese (Traditional)",
  jpn: "Japanese", kor: "Korean",
  hin: "Hindi", tam: "Tamil", ben: "Bengali", ara: "Arabic",
  fra: "French", deu: "German", spa: "Spanish", por: "Portuguese",
  ita: "Italian", nld: "Dutch", rus: "Russian",
};

// ── Main App ─────────────────────────────────────────────────
export default function App() {
  // State
  const [files, setFiles] = useState<QueueFile[]>([]);
  const [dragOver, setDragOver] = useState(false);
  const [outputDir, setOutputDir] = useState("");
  const [processing, setProcessing] = useState(false);
  const [log, setLog] = useState<LogLine[]>([]);
  const [summary, setSummary] = useState<BatchSummary | null>(null);
  const [lang, setLang] = useState("eng");
  // Load saved language on mount
  React.useEffect(() => {
    invoke<string>("get_saved_language").then(l => { if (l) setLang(l); }).catch(() => {});
  }, []);
  // Save language when changed
  React.useEffect(() => {
    invoke("set_saved_language", { lang }).catch(() => {});
  }, [lang]);

  // ── Tauri native drag-and-drop (provides real file paths) ──
  React.useEffect(() => {
    const win = getCurrentWindow();
    const unlisten = win.onDragDropEvent((event: any) => {
      const t = event.payload.type;
      if (t === "enter" || t === "over") {
        setDragOver(true);
      } else if (t === "leave" || t === "cancel") {
        setDragOver(false);
      } else if (t === "drop") {
        setDragOver(false);
        if (processing) return;
        const paths: string[] = event.payload.paths || [];
        const valid = paths.filter((p: string) => {
          const ext = p.split(".").pop()?.toLowerCase() || "";
          return ALLOWED_EXT.has(ext);
        });
        if (valid.length === 0) return;
        setFiles((prev) => {
          const existing = new Set(prev.map((f) => f.path));
          const added = valid.filter((p: string) => !existing.has(p)).map((p: string) => ({
            path: p, name: p.split(/[\\/]/).pop() || "file", status: "queued" as FileStatus,
          }));
          return [...prev, ...added];
        });
      }
    });
    return () => { unlisten.then((fn: any) => fn()); };
  }, [processing]);
  const [units, setUnits] = useState<Units>("auto");
  const [dateFmt, setDateFmt] = useState<DateFormat>("DMY");
  const [exMode, setExMode] = useState<ExMode>("Auto");
  const [elapsed, setElapsed] = useState(0);
  const [dictStats, setDictStats] = useState<{
    terms_count: number; ocr_fixes_count: number;
    legends_count: number; crs_default: string;
    depth_patterns_count?: number; metadata_keys_count?: number;
    exclude_terms_count?: number; project_name?: string; company?: string;
  } | null>(null);
  const [hwTier, setHwTier] = useState<{
    tier: number; name: string; model: string | null;
  } | null>(null);

  const [advice, setAdvice] = useState<Record<string, { suggestions: string[]; explanation: string } | null>>({});
  const [preview, setPreview] = useState<{hole_id: string; layers: any[]; spts: any[]; quality?: number; completeness?: string} | null>(null);
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const logRef = useRef<HTMLDivElement>(null);

  const addLog = useCallback((text: string, kind: LogLine["kind"] = "info") => {
    setLog((prev) => [...prev.slice(-600), { text, kind }]);
  }, []);

  // ── Init ─────────────────────────────────────────────────
  useEffect(() => {
    invoke("get_dictionary_stats_v2").then((s: any) => setDictStats(s)).catch(() => invoke("get_dictionary_stats").then((s: any) => setDictStats(s)).catch(() => {}));
    invoke("get_hw_profile").then((p: any) => {
      setHwTier({ tier: p.selected_tier || 0, name: p.tier_name || "Unknown", model: p.model || null });
    }).catch(() => {});
    invoke("get_extraction_mode").then((m: any) => {
      try {
        const parsed = JSON.parse(m);
        if (["Auto", "LocalAI", "Pattern"].includes(parsed)) setExMode(parsed);
      } catch {}
    }).catch(() => {});
  }, []);

  // ── Block F5/Ctrl+R — prevent accidental reset ──────────
  useEffect(() => {
    const block = (e: KeyboardEvent) => {
      if (e.key === "F5" || (e.ctrlKey && e.key === "r") || (e.metaKey && e.key === "r")) {
        e.preventDefault();
        e.stopPropagation();
      }
    };
    window.addEventListener("keydown", block, true);
    return () => window.removeEventListener("keydown", block, true);
  }, []);

  // ── Progress events from backend ────────────────────────
  useEffect(() => {
    const unsub = listen<{ file: string; message: string; kind: string }>("progress", (e) => {
      const { file, message, kind } = e.payload;
      addLog(`[${file}] ${message}`, kind as LogLine["kind"]);

      if (kind === "info" && message === "Starting...") {
        setFiles((prev) => prev.map((f) => f.name === file ? { ...f, status: "processing" as FileStatus } : f));
      }
      if (kind === "info" && message.startsWith("OCR page")) {
        setFiles((prev) => prev.map((f) => f.name === file ? { ...f, status: "processing" as FileStatus, pageProgress: message } : f));
      }
      // Capture output path from "Output written to ..." events
      if (kind === "info" && message.startsWith("Output written to ")) {
        const outPath = message.replace("Output written to ", "").trim();
        setFiles((prev) => prev.map((f) => f.name === file ? { ...f, outputPath: outPath } : f));
      }
      if (kind === "ok" || kind === "err") {
        setFiles((prev) => prev.map((f) => f.name === file
          ? { ...f, status: kind === "ok" ? "done" : "error", msg: message, pageProgress: undefined } : f));
      }
    });
    return () => { unsub.then((fn) => fn()); };
  }, [addLog]);

  // Auto-scroll log
  useEffect(() => {
    if (logRef.current) logRef.current.scrollTop = logRef.current.scrollHeight;
  }, [log]);

  // ── Actions ──────────────────────────────────────────────
  // ── Drag and drop ────────────────────────────────────────
  const ALLOWED_EXT = new Set(["pdf","png","jpg","jpeg","tif","tiff","bmp","webp","xlsx","xls","ags"]);
  function handleDrop(e: React.DragEvent) {
    e.preventDefault();
    setDragOver(false);
    if (processing) return;
    const dropped = Array.from(e.dataTransfer.files);
    const valid = dropped.filter(f => {
      const ext = f.name.split(".").pop()?.toLowerCase() || "";
      return ALLOWED_EXT.has(ext);
    });
    if (valid.length === 0) return;
    // Tauri exposes the native file path via webkitRelativePath or we use the File name
    // In Tauri 2, dropped files have a .path property on the dataTransfer
    const paths: string[] = valid.map((f: any) => f.path || f.name);
    setFiles((prev) => {
      const existing = new Set(prev.map((f) => f.path));
      const added = paths.filter((p) => p && !existing.has(p)).map((p) => ({
        path: p, name: p.split(/[\\/]/).pop() || "file", status: "queued" as FileStatus,
      }));
      return [...prev, ...added];
    });
  }

  async function pickFiles() {
    const sel = await open({
      multiple: true,
      filters: [
        { name: "Borehole Reports", extensions: ["pdf", "png", "jpg", "jpeg", "tif", "tiff", "bmp", "webp", "xlsx", "xls", "ags"] },
        { name: "All Files", extensions: ["*"] },
      ],
    });
    if (!sel) return;
    const raw = Array.isArray(sel) ? sel : [sel];
    const paths: string[] = raw.map((f: any) => typeof f === "string" ? f : (f.path || String(f)));
    setFiles((prev) => {
      const existing = new Set(prev.map((f) => f.path));
      const added = paths.filter((p) => p && !existing.has(p)).map((p) => ({
        path: p, name: p.split(/[\\/]/).pop() || "file", status: "queued" as FileStatus,
      }));
      return [...prev, ...added];
    });
  }

  async function loadPreview(filePath: string) {
    // Find the stored output path for this file
    const fileEntry = files.find(f => f.path === filePath);
    if (!fileEntry?.outputPath) return;
    const outFolder = fileEntry.outputPath;
    // Use backslash on Windows paths, forward slash otherwise
    const sep = outFolder.includes("\\") ? "\\" : "/";
    const manifestPath = outFolder + sep + "manifest.json";
    try {
      const content = await invoke<string>("read_output_file", { path: manifestPath });
      const mf = JSON.parse(content);
      const geolPath = outFolder + sep + "geol.csv";
      let layers: any[] = [];
      try {
        const csv = await invoke<string>("read_output_file", { path: geolPath });
        const csvLines = csv.trim().split("\n");
        if (csvLines.length > 1) {
          const headers = csvLines[0].split(",");
          layers = csvLines.slice(1).map(line => {
            const vals = line.split(",");
            const obj: any = {};
            headers.forEach((h: string, i: number) => obj[h.trim()] = vals[i]?.trim() || "");
            return obj;
          });
        }
      } catch {}
      setPreview({
        hole_id: mf.hole_id || outFolder.split(/[\\/]/).pop() || "unknown",
        layers,
        spts: [],
        quality: mf.quality_score,
        completeness: mf.completeness,
      });
    } catch { setPreview(null); }
  }

  async function pickOutput() {
    const dir = await open({ directory: true, multiple: false });
    if (!dir) return;
    const dirPath = typeof dir === "string" ? dir : (dir as any).path || String(dir);
    if (dirPath) setOutputDir(dirPath);
  }

  async function changeExMode(mode: ExMode) {
    setExMode(mode);
    try { await invoke("set_extraction_mode", { mode }); } catch {}
  }

  async function getAdvice(fileName: string, errorDetail: string) {
    const ext = fileName.split(".").pop() || "";
    try {
      const result = await invoke<{ suggestions: string[]; explanation: string }>("suggest_fix", {
        errorMsg: errorDetail, fileExt: ext, extractionMode: exMode,
        ocrTextLen: 0, layerCount: 0, warnings: [],
      });
      setAdvice((prev) => ({ ...prev, [fileName]: result }));
    } catch { setAdvice((prev) => ({ ...prev, [fileName]: { suggestions: ["Check the log for details."], explanation: "" } })); }
  }

  async function startProcessing() {
    setAdvice({});
    if (files.length === 0 || outputDir === "") return;
    setProcessing(true);
    setSummary(null);
    setElapsed(0);
    addLog("=== JOB STARTED ===", "info");
    setFiles((prev) => prev.map((f) => ({ ...f, status: "queued" as FileStatus, msg: undefined, pageProgress: undefined })));

    timerRef.current = setInterval(() => setElapsed((t) => t + 1), 1000);

    try {
      const r = await invoke<BatchSummary>("process_files", {
        params: { paths: files.map((f) => f.path), outputDir, lang, units, dateFormat: dateFmt },
      });
      setSummary(r);
      if (r.failed === 0) addLog(`COMPLETE: ${r.succeeded}/${r.total} OK`, "ok");
      else addLog(`${r.succeeded} OK, ${r.failed} FAILED of ${r.total}`, "warn");
    } catch (e) {
      addLog(`FATAL: ${e}`, "err");
    }

    if (timerRef.current) { clearInterval(timerRef.current); timerRef.current = null; }
    setProcessing(false);
  }

  // ── Derived ──────────────────────────────────────────────
  const canRun = files.length > 0 && outputDir.length > 0 && !processing;
  const statusColor: Record<FileStatus, string> = {
    queued: "#555", processing: "#4ca8ff", done: "#4cff91", error: "#ff4c4c",
  };
  const confColor = (c: number) => c >= 0.8 ? "#4cff91" : c >= 0.5 ? "#ffcc00" : "#ff4c4c";
  const confLabel = (c: number) => c >= 0.8 ? "HIGH" : c >= 0.5 ? "MED" : "LOW";
  const logColor: Record<LogLine["kind"], string> = {
    info: "#bbb", ok: "#4cff91", err: "#ff4c4c", warn: "#ffcc00",
  };
  const timerText = `${Math.floor(elapsed / 60)}:${String(elapsed % 60).padStart(2, "0")}`;

  // ── Render ───────────────────────────────────────────────
  return (
    <div style={{ display: "grid", gridTemplateRows: "auto 1fr auto auto", height: "100vh", padding: "20px", gap: "14px", maxWidth: "980px", margin: "0 auto" }}>
      {/* Header */}
      <header style={{ display: "flex", alignItems: "baseline", gap: "12px", borderBottom: "1px solid #303030", paddingBottom: "10px", flexWrap: "wrap" }}>
        <span style={{ fontSize: "16px", fontWeight: 700, letterSpacing: "0.05em" }}>
          BOREHOLE<span style={{ color: "#666" }}>IQ</span>
        </span>

        <span style={{ marginLeft: "auto", display: "flex", gap: "8px", alignItems: "center", fontSize: "10px", flexWrap: "wrap" }}>
          <select value={lang} onChange={(e) => setLang(e.target.value)} disabled={processing}>
            {Object.entries(LANGUAGES).map(([c, l]) => (<option key={c} value={c}>{l.toUpperCase()}</option>))}
          </select>
          <select value={units} onChange={(e) => setUnits(e.target.value as Units)} disabled={processing}>
            <option value="auto">UNITS:AUTO</option><option value="metric">METRIC</option><option value="imperial">IMPERIAL</option>
          </select>
          <select value={dateFmt} onChange={(e) => setDateFmt(e.target.value as DateFormat)} disabled={processing}>
            <option value="DMY">DD/MM/YYYY</option><option value="MDY">MM/DD/YYYY</option>
          </select>
          <select value={exMode} onChange={(e) => changeExMode(e.target.value as ExMode)} disabled={processing}
            style={{ background: exMode === "Pattern" ? "#1a2a1a" : exMode === "LocalAI" ? "#1a1a2e" : "#1a1a1a" }}>
            <option value="Auto">AUTO</option>
            <option value="LocalAI">AI ONLY</option>
            <option value="Pattern">REGEX</option>
          </select>
        </span>
      </header>

      {/* Main Content */}
      <main style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "14px", overflow: "hidden" }}>
        {/* Left: File Queue */}
        <div style={{ display: "flex", flexDirection: "column", gap: "10px", overflow: "hidden" }}>
          <div style={{ display: "flex", gap: "6px" }}>
            <button onClick={pickFiles} disabled={processing}>+ Files</button>
            <button onClick={() => setFiles([])} disabled={processing} className="danger">Clear</button>
            <span style={{ marginLeft: "auto", color: "#999", fontSize: "10px" }}>{files.length} file(s)</span>
          </div>
          {files.length === 0 && (
            <div
              onDragOver={(e) => { e.preventDefault(); setDragOver(true); }}
              onDragLeave={() => setDragOver(false)}
              onDrop={handleDrop}
              style={{
                border: dragOver ? "2px solid #4cff91" : "1px dashed #444",
                background: dragOver ? "#0a1f0a" : "transparent",
                padding: "28px", textAlign: "center", color: dragOver ? "#4cff91" : "#777",
                fontSize: "10px", lineHeight: 2.5, transition: "all 0.2s",
              }}
            >
              PDF / PNG / JPG / TIF / BMP / WEBP / XLSX / AGS<br />
              {dragOver ? "DROP FILES HERE" : "DRAG FILES HERE OR CLICK +FILES"}
            </div>
          )}
          <div
            onDragOver={(e) => { e.preventDefault(); setDragOver(true); }}
            onDragLeave={() => setDragOver(false)}
            onDrop={handleDrop}
            style={{ flex: 1, overflowY: "auto", display: "flex", flexDirection: "column", gap: "3px",
                     border: dragOver ? "2px solid #4cff91" : "none", transition: "border 0.2s" }}>
            {files.map((f) => (
              <div key={f.path} style={{ border: "1px solid #252525", background: "#0d0d0d" }}>
                <div style={{ display: "flex", alignItems: "center", gap: "8px", padding: "5px 8px" }}>
                  <span style={{ width: 5, height: 5, borderRadius: "50%", background: statusColor[f.status], flexShrink: 0 }} />
                  <span style={{ flex: 1, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", color: "#bbb", fontSize: "11px" }} title={f.path}>{f.name}</span>
                  {f.status === "error" && !processing && (
                    <span onClick={() => getAdvice(f.name, f.msg || "")}
                      style={{ cursor: "pointer", fontSize: "11px", color: "#ffcc00", padding: "0 4px" }}
                      title="Get advice on this error">?</span>
                  )}
                  <span style={{ fontSize: "9px", color: statusColor[f.status] }}>
                    <span onClick={() => f.status === "done" && loadPreview(f.path)} title={f.status === "done" ? "Click to preview" : ""}>{f.status === "processing" && f.pageProgress ? f.pageProgress : f.status.toUpperCase()}</span>
                  </span>
                </div>
                {advice[f.name] && f.status === "error" && (
                  <div style={{ padding: "4px 8px 6px 20px", borderTop: "1px solid #1a1a1a", fontSize: "10px" }}>
                    {advice[f.name]!.suggestions.map((s, i) => (
                      <div key={i} style={{ color: "#cda", lineHeight: 1.6 }}>{s}</div>
                    ))}
                    {advice[f.name]!.explanation && (
                      <div style={{ color: "#666", marginTop: "3px", fontStyle: "italic" }}>{advice[f.name]!.explanation}</div>
                    )}
                  </div>
                )}
              </div>
            ))}
          </div>
          <div style={{ borderTop: "1px solid #252525", paddingTop: "10px", display: "flex", flexDirection: "column", gap: "5px" }}>
            {/* ── Output Preview Panel ── */}
            {preview && (
              <div style={{ background: "#0d0d0d", border: "1px solid #333", borderRadius: 4, padding: "8px 10px", marginBottom: 8, maxHeight: 180, overflow: "auto" }}>
                <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 4 }}>
                  <span style={{ color: "#4cff91", fontWeight: "bold", fontSize: 11 }}>{preview.hole_id}</span>
                  <span style={{ fontSize: 9, color: preview.quality && preview.quality >= 70 ? "#4cff91" : preview.quality && preview.quality >= 40 ? "#ffcc00" : "#ff4c4c" }}>
                    Q: {preview.quality || "?"}/100 {preview.completeness && `| ${preview.completeness}`}
                  </span>
                  <button onClick={() => setPreview(null)} style={{ background: "none", border: "none", color: "#ff4c4c", cursor: "pointer", fontSize: 10 }}>✕</button>
                </div>
                {preview.layers.length > 0 && (
                  <table style={{ width: "100%", fontSize: 9, borderCollapse: "collapse" }}>
                    <thead><tr style={{ color: "#4ca8ff", borderBottom: "1px solid #333" }}>
                      <th style={{ textAlign: "left", padding: "2px 4px" }}>Top</th>
                      <th style={{ textAlign: "left", padding: "2px 4px" }}>Base</th>
                      <th style={{ textAlign: "left", padding: "2px 4px" }}>Description</th>
                      <th style={{ textAlign: "left", padding: "2px 4px" }}>Legend</th>
                    </tr></thead>
                    <tbody>{preview.layers.map((l: any, i: number) => (
                      <tr key={i} style={{ borderBottom: "1px solid #1a1a1a" }}>
                        <td style={{ padding: "2px 4px", color: "#ccc" }}>{l.GEOL_TOP || l.top || ""}</td>
                        <td style={{ padding: "2px 4px", color: "#ccc" }}>{l.GEOL_BASE || l.base || ""}</td>
                        <td style={{ padding: "2px 4px", color: "#eee" }}>{l.GEOL_DESC || l.description || ""}</td>
                        <td style={{ padding: "2px 4px", color: "#888" }}>{l.GEOL_LEG || l.legend || ""}</td>
                      </tr>
                    ))}</tbody>
                  </table>
                )}
                {preview.layers.length === 0 && <div style={{ color: "#888", fontSize: 9 }}>No layers in output</div>}
              </div>
            )}

            <div style={{ display: "flex", gap: "6px", alignItems: "center" }}>
              <button onClick={pickOutput} disabled={processing}>Choose</button>
              {outputDir && <span style={{ flex: 1, fontSize: "9px", color: "#aaa", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }} title={outputDir}>{outputDir}</span>}
            </div>
          </div>
          <button className="primary" onClick={startProcessing} disabled={!canRun} style={{ padding: "11px", fontSize: "11px", letterSpacing: "0.15em" }}>
            {processing ? `PROCESSING... ${timerText}` : "PROCESS"}
          </button>
          {summary && (
            <div style={{ padding: "8px", border: "1px solid #303030", fontSize: "10px" }}>
              <div style={{ color: summary.failed === 0 ? "#4cff91" : "#ffcc00", marginBottom: summary.results?.length ? "6px" : 0 }}>
                RESULT: {summary.succeeded}/{summary.total} OK{summary.failed > 0 && ` | ${summary.failed} FAILED`}
              </div>
              {summary.results?.filter((r: FileResult) => r.status === "error").map((r: FileResult, i: number) => (
                <div key={i} style={{ color: "#ff4c4c", paddingLeft: "8px" }}>{r.name}: {r.detail}</div>
              ))}
            </div>
          )}
        </div>

        {/* Right: Log */}
        <div style={{ display: "flex", flexDirection: "column", border: "1px solid #141414", overflow: "hidden" }}>
          <div style={{ padding: "7px 10px", borderBottom: "1px solid #252525", fontSize: "9px", color: "#999", letterSpacing: "0.1em", display: "flex", justifyContent: "space-between" }}>
            <span>EXTRACTION LOG</span>
            <span style={{ cursor: "pointer", color: "#777" }} onClick={() => setLog([])}>CLEAR</span>
          </div>
          <div ref={logRef} style={{ flex: 1, overflowY: "auto", padding: "8px 10px", fontSize: "10px", lineHeight: 1.9 }}>
            {log.map((l, i) => <div key={i} style={{ color: logColor[l.kind] }}>{l.text}</div>)}
          </div>
        </div>
      </main>

