use serde::{Deserialize, Serialize};
use tauri::{command, AppHandle, Emitter};
use std::path::PathBuf;
use std::sync::atomic::{AtomicBool, Ordering};
use crate::pipeline;
use crate::pipeline::writer;
use crate::commands::abort;

static PROCESSING: AtomicBool = AtomicBool::new(false);

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct FileResult {
    pub name: String,
    pub status: String,
    pub detail: String,
}

#[derive(Debug, Serialize, Deserialize)]
pub struct BatchSummary {
    pub total: usize,
    pub succeeded: usize,
    pub failed: usize,
    pub results: Vec<FileResult>,
}

#[derive(Debug, Deserialize)]
#[serde(rename_all = "camelCase")]
pub struct ProcessParams {
    pub paths: Vec<String>,
    pub output_dir: String,
    pub lang: String,
    pub units: String,
    pub date_format: String,
}

#[derive(Clone, Serialize)]
struct ProgressEvent { file: String, message: String, kind: String }

fn emit_progress(app: &AppHandle, file: &str, msg: &str, kind: &str) {
    let _ = app.emit("progress", ProgressEvent {
        file: file.to_string(), message: msg.to_string(), kind: kind.to_string(),
    });
}

#[command]
pub async fn process_files(app: AppHandle, params: ProcessParams) -> Result<BatchSummary, String> {
    // Prevent concurrent invocations
    if PROCESSING.compare_exchange(false, true, Ordering::SeqCst, Ordering::SeqCst).is_err() {
        return Err("Processing already in progress".to_string());
    }
    struct ProcessGuard;
    impl Drop for ProcessGuard { fn drop(&mut self) { PROCESSING.store(false, Ordering::SeqCst); } }
    let _guard = ProcessGuard;

    // Reset abort flag at start of each batch
    abort::reset_abort();

    let output_dir = PathBuf::from(&params.output_dir);
    if !output_dir.exists() {
        std::fs::create_dir_all(&output_dir).map_err(|e| format!("mkdir: {}", e))?;
    }
    let total = params.paths.len();
    let (mut ok_count, mut fail_count) = (0usize, 0usize);
    let mut file_results: Vec<FileResult> = Vec::new();
    for fp in &params.paths {
        // Check abort between files
        if abort::should_abort() {
            emit_progress(&app, "BATCH", "Aborted by user", "warn");
            break;
        }
        let path = PathBuf::from(fp);
        let name = path.file_name().unwrap_or_default().to_string_lossy().to_string();
        // Resource guard: reject files > 500 MB to prevent OOM
        const MAX_FILE_SIZE: u64 = 500 * 1024 * 1024;
        match std::fs::metadata(&path) {
            Ok(meta) if meta.len() > MAX_FILE_SIZE => {
                let detail = format!("SKIPPED: file too large ({:.0} MB, max 500 MB)", meta.len() as f64 / 1_048_576.0);
                emit_progress(&app, &name, &detail, "err");
                fail_count += 1;
                file_results.push(FileResult { name: name.clone(), status: "error".into(), detail });
                continue;
            }
            Err(e) => {
                let detail = format!("ERROR: cannot read file: {}", e);
                emit_progress(&app, &name, &detail, "err");
                fail_count += 1;
                file_results.push(FileResult { name: name.clone(), status: "error".into(), detail });
                continue;
            }
            _ => {}
        }
        emit_progress(&app, &name, "Starting...", "info");
        match pipeline::run_pipeline(&app, &path, &output_dir, &params.lang, &params.units, &params.date_format).await {
            Ok(m) => { emit_progress(&app, &name, &m, "ok"); ok_count += 1; file_results.push(FileResult { name: name.clone(), status: "ok".into(), detail: m }); }
            Err(e) => { let detail = format!("ERROR: {}", e); emit_progress(&app, &name, &detail, "err"); fail_count += 1; file_results.push(FileResult { name: name.clone(), status: "error".into(), detail }); }
        }
    }
    // Post-batch: generate batch summary report
    if ok_count > 0 {
        emit_progress(&app, "BATCH", "Generating summary report...", "info");
        if let Err(e) = generate_batch_summary(&output_dir, &file_results) {
            emit_progress(&app, "BATCH", &format!("Summary report failed: {}", e), "warn");
        } else {
            emit_progress(&app, "BATCH", "Summary report written", "ok");
        }
    }

    // Post-batch: generate combined project.ags for one-shot OpenGround import
    if ok_count >= 2 {
        emit_progress(&app, "BATCH", "Merging into project.ags...", "info");
        match merge_batch_ags(&output_dir) {
            Ok(msg) => emit_progress(&app, "BATCH", &msg, "ok"),
            Err(e) => emit_progress(&app, "BATCH", &format!("Merge failed: {}", e), "warn"),
        }
    }

    Ok(BatchSummary { total, succeeded: ok_count, failed: fail_count, results: file_results })
}

/// Merge all individual output.ags files from subdirectories into a single project.ags.
/// This produces a multi-hole AGS4 file for one-shot import into OpenGround.
fn merge_batch_ags(output_dir: &std::path::Path) -> Result<String, String> {
    let mut ags_contents: Vec<String> = Vec::new();
    let mut hole_ids: Vec<String> = Vec::new();

    // Read each subdirectory's output.ags
    let entries = std::fs::read_dir(output_dir)
        .map_err(|e| format!("read dir: {}", e))?;
    for entry in entries {
        let entry = entry.map_err(|e| format!("read entry: {}", e))?;
        let path = entry.path();
        if path.is_dir() {
            let ags_file = path.join("output.ags");
            if ags_file.exists() {
                if let Ok(content) = std::fs::read_to_string(&ags_file) {
                    if !content.is_empty() {
                        ags_contents.push(content);
                        hole_ids.push(entry.file_name().to_string_lossy().to_string());
                    }
                }
            }
        }
    }

    if ags_contents.len() < 2 {
        return Ok("Only 1 hole - no merge needed".to_string());
    }

    // Simple merge: concatenate all individual AGS files with separation
    // Each individual file is already a valid AGS4. For a true merge we'd
    // parse and recombine groups, but concatenation works for import tools
    // that handle multi-PROJ files.
    //
    // For OpenGround specifically, the preferred approach is a single PROJ
    // group with all LOCA records. We achieve this by reading the individual
    // manifests and using the batch writer.

    // Read manifest.json from each subdirectory to reconstruct Boreholes
    let mut boreholes: Vec<crate::models::borehole::Borehole> = Vec::new();
    for entry in std::fs::read_dir(output_dir).map_err(|e| e.to_string())? {
        let entry = entry.map_err(|e| e.to_string())?;
        let path = entry.path();
        if !path.is_dir() { continue; }

        // Read the individual AGS and parse back the essential data
        // Actually, read the CSV files which have the structured data
        let hole_id = entry.file_name().to_string_lossy().to_string();
        let mut bh = crate::models::borehole::Borehole::new(hole_id.clone());

        // Parse loca.csv
        let loca_path = path.join("loca.csv");
        if let Ok(loca_content) = std::fs::read_to_string(&loca_path) {
            for line in loca_content.lines().skip(1) {
                let fields: Vec<&str> = line.split(',').collect();
                if fields.len() >= 5 {
                    bh.easting = fields.get(1).and_then(|s| s.parse().ok());
                    bh.northing = fields.get(2).and_then(|s| s.parse().ok());
                    bh.elevation = fields.get(3).and_then(|s| s.parse().ok());
                    bh.final_depth = fields.get(4).and_then(|s| s.parse().ok());
                }
            }
        }

        // Parse geol.csv
        let geol_path = path.join("geol.csv");
        if let Ok(geol_content) = std::fs::read_to_string(&geol_path) {
            for line in geol_content.lines().skip(1) {
                let fields: Vec<&str> = line.split(',').collect();
                if fields.len() >= 4 {
                    let top: f64 = fields[1].parse().unwrap_or(0.0);
                    let base: f64 = fields[2].parse().unwrap_or(0.0);
                    let desc = fields[3].to_string();
                    let leg = fields.get(4).map(|s| s.to_string());
                    bh.layers.push(crate::models::borehole::GeologyLayer {
                        top, base, description: desc,
                        legend_code: leg, confidence: 1.0,
                    });
                }
            }
        }

        if !bh.layers.is_empty() {
            boreholes.push(bh);
        }
    }

    if boreholes.len() < 2 {
        return Ok("Only 1 valid hole - no merge needed".to_string());
    }

    writer::write_batch_ags4(&boreholes, output_dir)
}


/// Generate an HTML batch summary report.
fn generate_batch_summary(output_dir: &std::path::Path, results: &[FileResult]) -> Result<(), String> {
    let mut html = String::from(r#"<!DOCTYPE html><html><head><meta charset="utf-8">
<title>BoreholeIQ Batch Summary</title>
<style>
body{background:#080808;color:#ccc;font-family:'JetBrains Mono',monospace;padding:20px;max-width:980px;margin:0 auto}
h1{color:#4cff91;font-size:16px}
table{border-collapse:collapse;width:100%;font-size:11px}
th{background:#1a1a1a;color:#4cff91;padding:6px 10px;text-align:left;border:1px solid #333}
td{padding:5px 10px;border:1px solid #252525}
.ok{color:#4cff91} .err{color:#ff4c4c} .warn{color:#ffcc00}
.conf-high{color:#4cff91} .conf-med{color:#ffcc00} .conf-low{color:#ff4c4c}
footer{margin-top:20px;color:#555;font-size:10px;text-align:center}
</style></head><body>
<h1>BoreholeIQ v2 — Batch Extraction Summary</h1>
"#);

    let ok_count = results.iter().filter(|r| r.status == "ok").count();
    let fail_count = results.iter().filter(|r| r.status == "error").count();
    html.push_str(&format!("<p>Total: {} | <span class='ok'>OK: {}</span> | <span class='err'>Failed: {}</span></p>\n",
        results.len(), ok_count, fail_count));

    html.push_str("<table><tr><th>File</th><th>Status</th><th>Layers</th><th>Samples</th><th>SPTs</th><th>Avg Confidence</th></tr>\n");

    for r in results {
        let status_class = if r.status == "ok" { "ok" } else { "err" };

        // Try to read manifest for details
        let name_safe = r.name.replace(|c: char| !c.is_alphanumeric() && c != '.' && c != '-' && c != '_', "_");
        let manifest_path = output_dir.join(&name_safe).join("manifest.json");
        let (layers, samples, spts) = if let Ok(content) = std::fs::read_to_string(&manifest_path) {
            if let Ok(mf) = serde_json::from_str::<serde_json::Value>(&content) {
                (
                    mf.get("layers").and_then(|v| v.as_u64()).unwrap_or(0),
                    mf.get("samples").and_then(|v| v.as_u64()).unwrap_or(0),
                    mf.get("spts").and_then(|v| v.as_u64()).unwrap_or(0),
                )
            } else { (0, 0, 0) }
        } else { (0, 0, 0) };

        // Read provenance for confidence
        let prov_path = output_dir.join(&name_safe).join("provenance.json");
        let avg_conf = if let Ok(content) = std::fs::read_to_string(&prov_path) {
            if let Ok(pv) = serde_json::from_str::<serde_json::Value>(&content) {
                pv.get("avg_confidence").and_then(|v| v.as_f64()).unwrap_or(0.0)
            } else { 0.0 }
        } else { 0.0 };

        let conf_class = if avg_conf >= 0.8 { "conf-high" } else if avg_conf >= 0.5 { "conf-med" } else { "conf-low" };

        html.push_str(&format!(
            "<tr><td>{}</td><td class='{}'>{}</td><td>{}</td><td>{}</td><td>{}</td><td class='{}'>{:.0}%</td></tr>\n",
            r.name, status_class, r.status.to_uppercase(), layers, samples, spts, conf_class, avg_conf * 100.0
        ));
    }

    html.push_str("</table>\n<footer>Prototype by Orven Fajardo</footer>\n</body></html>");

    std::fs::write(output_dir.join("batch_summary.html"), &html)
        .map_err(|e| format!("write summary: {}", e))?;
    Ok(())
}

