use crate::models::borehole::*;

/// AGS output variant. Controls version header and regional field requirements.
#[derive(Debug, Clone, PartialEq)]
pub enum AgsVariant {
    Ags4Generic,    // AGS 4.0 (default)
    Ags4Au,         // AGS 4.1.0 AU 1.1 (Australian)
    Ags4Nz,         // AGS 4 NZ (New Zealand)
    Ags31,          // AGS 3.1 (legacy UK)
}

impl Default for AgsVariant {
    fn default() -> Self { AgsVariant::Ags4Generic }
}

/// Read the active AGS variant from user defaults.
pub fn active_variant() -> AgsVariant {
    let dict = crate::models::userdict::get();
    match dict.defaults.ags_variant.as_deref() {
        Some("4.1.0_AU") | Some("au") => AgsVariant::Ags4Au,
        Some("4_NZ") | Some("nz") => AgsVariant::Ags4Nz,
        Some("3.1") | Some("31") => AgsVariant::Ags31,
        _ => AgsVariant::Ags4Generic,
    }
}


use std::collections::BTreeSet;

/// Format a single AGS4 line: all fields quoted, comma-separated, CRLF.
fn ags_line(fields: &[&str]) -> String {
    fields.iter().map(|f| {
        let safe = f.replace('"', "'").replace('|', "-");
        format!("\"{}\"", safe)
    }).collect::<Vec<_>>().join(",")
}

/// Get today's date as yyyy-mm-dd.
fn today() -> String {
    let d = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default()
        .as_secs();
    // Simple epoch-to-date (no chrono dependency)
    let days = d / 86400;
    let mut y = 1970u32;
    let mut remaining = days as u32;
    loop {
        let leap = y % 4 == 0 && (y % 100 != 0 || y % 400 == 0);
        let ydays = if leap { 366 } else { 365 };
        if remaining < ydays { break; }
        remaining -= ydays;
        y += 1;
    }
    let leap = y % 4 == 0 && (y % 100 != 0 || y % 400 == 0);
    let mdays = [31, if leap {29} else {28}, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
    let mut m = 0u32;
    for md in &mdays {
        if remaining < *md { break; }
        remaining -= md;
        m += 1;
    }
    format!("{}-{:02}-{:02}", y, m + 1, remaining + 1)
}

/// Map a method string to an AGS4 LOCA_TYPE abbreviation code.
fn method_to_loca_type(method: &str) -> &'static str {
    let m = method.to_uppercase();
    if m.contains("ROTARY") || m.contains("CORE") || m.contains("PEMBORAN") { return "RC"; }
    if m.contains("CABLE") || m.contains("PERCUSS") { return "CP"; }
    if m.contains("WINDOW") { return "WS"; }
    if m.contains("TRIAL") || m.contains("TP") { return "TP"; }
    if m.contains("CPT") || m.contains("SONDIR") { return "CPT"; }
    if m.contains("DYNAMIC") || m.contains("DP") { return "DP"; }
    if m.contains("HAND") || m.contains("AUGER") { return "HA"; }
    if m.contains("SONIC") { return "SC"; }
    ""
}

/// Map a method abbreviation code to its full description for ABBR group.
fn loca_type_desc(code: &str) -> &'static str {
    match code {
        "RC" => "Rotary coring",
        "CP" => "Cable percussion",
        "WS" => "Window sampling",
        "TP" => "Trial pit",
        "CPT" => "Cone penetration test",
        "DP" => "Dynamic probing",
        "HA" => "Hand auger",
        "SC" => "Sonic coring",
        _ => "",
    }
}

/// Map sample type codes to descriptions for ABBR group.
fn samp_type_desc(code: &str) -> &'static str {
    match code {
        "D" => "Disturbed sample",
        "U" => "Undisturbed sample",
        "B" => "Bulk sample",
        "W" => "Water sample",
        "ES" => "Environmental sample",
        _ => "Sample",
    }
}

/// Generate an AGS4 file that will pass OpenGround validation.
/// Includes mandatory groups: TRAN, PROJ, LOCA, GEOL, SAMP, ISPT, ABBR, TYPE, UNIT.
pub fn borehole_to_ags4(bh: &Borehole) -> String {
    let mut sections: Vec<String> = Vec::new();

    // Collect all abbreviations, types, and units used in this file
    let mut abbrs: BTreeSet<(String, String)> = BTreeSet::new(); // (code, description)
    let mut types: BTreeSet<String> = BTreeSet::new();
    let mut units: BTreeSet<String> = BTreeSet::new();

    // Standard types always present
    for t in &["ID", "X", "DT", "2DP", "0DP", "PA"] {
        types.insert(t.to_string());
    }
    // Standard units always present
    for u in &["m", "yyyy-mm-dd"] {
        units.insert(u.to_string());
    }

    // ── TRAN: Transmittal (mandatory) ────────────────────────
    let tran_date = today();
    sections.push([
        ags_line(&["GROUP", "TRAN"]),
        ags_line(&["HEADING", "TRAN_ISNO", "TRAN_DATE", "TRAN_PROD", "TRAN_STAT", "TRAN_DESC", "TRAN_AGS"]),
        ags_line(&["UNIT", "", "yyyy-mm-dd", "", "", "", ""]),
        ags_line(&["TYPE", "X", "DT", "X", "X", "X", "X"]),
        ags_line(&["DATA", "1", &tran_date, "BoreholeIQ v2", "PRELIMINARY", "Auto-extracted from borehole report", "4.1.1"]),
    ].join("\r\n"));

    // ── PROJ: Project (mandatory, single DATA row) ───────────
    // PROJ_ID should be project-level, not borehole-level.
    // Use user defaults if available, otherwise derive from hole_id.
    let proj_id = {
        let dict = crate::models::userdict::get();
        dict.defaults.project_name.clone()
            .unwrap_or_else(|| {
                // Derive project ID: strip trailing numbers/suffixes from hole_id
                let id = &bh.hole_id;
                if id.len() > 6 {
                    // Take first meaningful part (e.g., "BH TIM 05 STA 28+050" -> "BH TIM")
                    id.split_whitespace().take(2).collect::<Vec<_>>().join(" ")
                } else {
                    id.clone()
                }
            })
    };
    let proj_loc = {
        let dict = crate::models::userdict::get();
        dict.defaults.project_location.clone().unwrap_or_default()
    };
    sections.push([
        ags_line(&["GROUP", "PROJ"]),
        ags_line(&["HEADING", "PROJ_ID", "PROJ_NAME", "PROJ_LOC", "PROJ_MEMO"]),
        ags_line(&["UNIT", "", "", "", ""]),
        ags_line(&["TYPE", "ID", "X", "X", "X"]),
        ags_line(&["DATA", &proj_id, "BoreholeIQ Extraction", &proj_loc, "Auto-extracted by BoreholeIQ v2"]),
    ].join("\r\n"));

    // ── LOCA: Location (mandatory) ───────────────────────────
    let e = bh.easting.map(|v| format!("{:.2}", v)).unwrap_or_default();
    let n = bh.northing.map(|v| format!("{:.2}", v)).unwrap_or_default();
    let gl = bh.elevation.map(|v| format!("{:.2}", v)).unwrap_or_default();
    let fd = bh.final_depth.map(|v| format!("{:.2}", v)).unwrap_or_default();
    let ds = bh.date_start.as_deref().unwrap_or("");
    let de = bh.date_end.as_deref().unwrap_or("");
    let raw_method = bh.method.as_deref().unwrap_or("");
    let loca_type = method_to_loca_type(raw_method);
    let gref = bh.crs.as_deref().unwrap_or("");

    if !loca_type.is_empty() {
        abbrs.insert((loca_type.to_string(), loca_type_desc(loca_type).to_string()));
    }

    sections.push([
        ags_line(&["GROUP", "LOCA"]),
        ags_line(&["HEADING", "LOCA_ID", "LOCA_NATE", "LOCA_NATN", "LOCA_GL", "LOCA_FDEP", "LOCA_TYPE", "LOCA_STAR", "LOCA_ENDD", "LOCA_GREF"]),
        ags_line(&["UNIT", "", "m", "m", "m", "m", "", "yyyy-mm-dd", "yyyy-mm-dd", ""]),
        ags_line(&["TYPE", "ID", "2DP", "2DP", "2DP", "2DP", "PA", "DT", "DT", "X"]),
        ags_line(&["DATA", &bh.hole_id, &e, &n, &gl, &fd, loca_type, ds, de, gref]),
    ].join("\r\n"));

    // ── GEOL: Geology (child of LOCA) ────────────────────────
    if !bh.layers.is_empty() {
        let mut lines = vec![
            ags_line(&["GROUP", "GEOL"]),
            ags_line(&["HEADING", "LOCA_ID", "GEOL_TOP", "GEOL_BASE", "GEOL_DESC", "GEOL_LEG", "GEOL_GEOL"]),
            ags_line(&["UNIT", "", "m", "m", "", "", ""]),
            ags_line(&["TYPE", "ID", "2DP", "2DP", "X", "PA", "X"]),
        ];
        for l in &bh.layers {
            let leg = l.legend_code.as_deref().unwrap_or("");
            // GEOL_GEOL: short geological formation name (from legend)
            let geol = if !leg.is_empty() { leg } else { "" };
            lines.push(ags_line(&[
                "DATA", &bh.hole_id,
                &format!("{:.2}", l.top), &format!("{:.2}", l.base),
                &l.description, leg, geol,
            ]));
            if !leg.is_empty() {
                abbrs.insert((leg.to_string(), leg.to_string()));
            }
        }
        sections.push(lines.join("\r\n"));
    }

    // ── SAMP: Samples (child of LOCA) ────────────────────────
    if !bh.samples.is_empty() {
        let mut lines = vec![
            ags_line(&["GROUP", "SAMP"]),
            ags_line(&["HEADING", "LOCA_ID", "SAMP_TOP", "SAMP_TYPE", "SAMP_REF", "SAMP_ID"]),
            ags_line(&["UNIT", "", "m", "", "", ""]),
            ags_line(&["TYPE", "ID", "2DP", "PA", "X", "ID"]),
        ];
        for (i, s) in bh.samples.iter().enumerate() {
            let fallback_id = format!("{}-S{}", bh.hole_id, i + 1);
            let sid = s.sample_id.as_deref().unwrap_or(&fallback_id);
            let depth = format!("{:.2}", s.depth_top);
            let ref_num = format!("{}", i + 1);
            lines.push(ags_line(&[
                "DATA", &bh.hole_id, &depth,
                s.sample_type.as_str(), &ref_num, sid,
            ]));
            let st = s.sample_type.as_str();
            abbrs.insert((st.to_string(), samp_type_desc(st).to_string()));
        }
        sections.push(lines.join("\r\n"));
    }

    // ── ISPT: SPT Results (child of LOCA) ────────────────────
    if !bh.spts.is_empty() {
        let mut lines = vec![
            ags_line(&["GROUP", "ISPT"]),
            ags_line(&["HEADING", "LOCA_ID", "ISPT_TOP", "ISPT_SEAT", "ISPT_MAIN", "ISPT_NVAL", "ISPT_REP"]),
            ags_line(&["UNIT", "", "m", "", "", "", ""]),
            ags_line(&["TYPE", "ID", "2DP", "X", "X", "0DP", "X"]),
        ];
        for s in &bh.spts {
            let nv = s.n_value.unwrap_or(0);
            let seat = s.seating.as_deref().unwrap_or("");
            let main = s.main.as_deref().unwrap_or("");
            lines.push(ags_line(&[
                "DATA", &bh.hole_id,
                &format!("{:.2}", s.depth),
                seat, main,
                &format!("{}", nv),
                &format!("N={}", nv),
            ]));
        }
        sections.push(lines.join("\r\n"));
    }

    // ── ABBR: Abbreviation Definitions (mandatory) ───────────
    {
        let mut lines = vec![
            ags_line(&["GROUP", "ABBR"]),
            ags_line(&["HEADING", "ABBR_HDNG", "ABBR_CODE", "ABBR_DESC"]),
            ags_line(&["UNIT", "", "", ""]),
            ags_line(&["TYPE", "X", "X", "X"]),
        ];
        for (code, desc) in &abbrs {
            if !code.is_empty() && !desc.is_empty() {
                lines.push(ags_line(&["DATA", "GEOL_LEG", code, desc]));
            }
        }
        // Add LOCA_TYPE abbreviation if present
        if !loca_type.is_empty() {
            lines.push(ags_line(&["DATA", "LOCA_TYPE", loca_type, loca_type_desc(loca_type)]));
        }
        // Add sample type abbreviations
        let mut samp_types: BTreeSet<String> = BTreeSet::new();
        for s in &bh.samples {
            samp_types.insert(s.sample_type.clone());
        }
        for st in &samp_types {
            lines.push(ags_line(&["DATA", "SAMP_TYPE", st, samp_type_desc(st)]));
        }
        sections.push(lines.join("\r\n"));
    }

    // ── TYPE: Data Type Definitions (mandatory) ──────────────
    {
        let mut lines = vec![
            ags_line(&["GROUP", "TYPE"]),
            ags_line(&["HEADING", "TYPE_TYPE", "TYPE_DESC"]),
            ags_line(&["UNIT", "", ""]),
            ags_line(&["TYPE", "X", "X"]),
        ];
        let type_defs = [
            ("ID", "Unique identifier"),
            ("X", "Text"),
            ("DT", "Date and time"),
            ("2DP", "Value to 2 decimal places"),
            ("0DP", "Value to 0 decimal places"),
            ("PA", "Pick from abbreviation list"),
        ];
        for (code, desc) in &type_defs {
            lines.push(ags_line(&["DATA", code, desc]));
        }
        sections.push(lines.join("\r\n"));
    }

    // ── WSTB: Water Strike (if water level available) ───────
    if let Some(wl) = bh.water_level {
        let mut lines = vec![
            ags_line(&["GROUP", "WSTB"]),
            ags_line(&["HEADING", "LOCA_ID", "WSTB_TOP", "WSTB_DTIM", "WSTB_SEAL"]),
            ags_line(&["UNIT", "", "m", "yyyy-mm-dd", ""]),
            ags_line(&["TYPE", "ID", "2DP", "DT", "X"]),
        ];
        lines.push(ags_line(&["DATA", &bh.hole_id, &format!("{:.2}", wl), "", ""]));
        sections.push(lines.join("\r\n"));
    }

    // ── UNIT: Unit Definitions (mandatory) ───────────────────
    {
        let mut lines = vec![
            ags_line(&["GROUP", "UNIT"]),
            ags_line(&["HEADING", "UNIT_UNIT", "UNIT_DESC"]),
            ags_line(&["UNIT", "", ""]),
            ags_line(&["TYPE", "X", "X"]),
        ];
        let unit_defs = [
            ("m", "metre"),
            ("yyyy-mm-dd", "date"),
        ];
        for (code, desc) in &unit_defs {
            lines.push(ags_line(&["DATA", code, desc]));
        }
        sections.push(lines.join("\r\n"));
    }

    sections.join("\r\n\r\n") + "\r\n"
}

/// Generate a combined AGS4 file containing multiple boreholes.
/// Merges all LOCA, GEOL, SAMP, ISPT records into a single file
/// suitable for one-shot import into OpenGround.
pub fn boreholes_to_ags4(boreholes: &[Borehole]) -> String {
    if boreholes.is_empty() { return String::new(); }
    if boreholes.len() == 1 { return borehole_to_ags4(&boreholes[0]); }

    let mut sections: Vec<String> = Vec::new();

    // ── PROJ: use first borehole's date range for project ────────
    {
        let first = &boreholes[0];
        let mut lines = vec![
            ags_line(&["GROUP", "PROJ"]),
            ags_line(&["HEADING", "PROJ_ID", "PROJ_NAME", "PROJ_LOC", "PROJ_DATE", "PROJ_MEMO"]),
            ags_line(&["UNIT", "", "", "", "yyyy-mm-dd", ""]),
            ags_line(&["TYPE", "X", "X", "X", "DT", "X"]),
        ];
        let proj_id = format!("BIQ-BATCH-{}", &today()[..10]);
        let hole_list: Vec<&str> = boreholes.iter().map(|b| b.hole_id.as_str()).collect();
        let memo = format!("BoreholeIQ batch: {} holes", boreholes.len());
        lines.push(ags_line(&["DATA", &proj_id,
            &format!("BoreholeIQ Batch Export ({} holes)", boreholes.len()),
            &hole_list.join(", "),
            &today(), &memo]));
        sections.push(lines.join("\r\n"));
    }

    // ── LOCA: all borehole locations ─────────────────────────────
    {
        let mut lines = vec![
            ags_line(&["GROUP", "LOCA"]),
            ags_line(&["HEADING", "LOCA_ID", "LOCA_NATE", "LOCA_NATN", "LOCA_GL",
                        "LOCA_FDEP", "LOCA_TYPE", "LOCA_STAR", "LOCA_ENDD"]),
            ags_line(&["UNIT", "", "m", "m", "m", "m", "", "yyyy-mm-dd", "yyyy-mm-dd"]),
            ags_line(&["TYPE", "ID", "2DP", "2DP", "2DP", "2DP", "PA", "DT", "DT"]),
        ];
        for bh in boreholes {
            let loca_type = bh.method.as_deref().map(method_to_loca_type).unwrap_or("");
            lines.push(ags_line(&["DATA", &bh.hole_id,
                &bh.easting.map(|v| format!("{:.2}", v)).unwrap_or_default(),
                &bh.northing.map(|v| format!("{:.2}", v)).unwrap_or_default(),
                &bh.elevation.map(|v| format!("{:.2}", v)).unwrap_or_default(),
                &bh.final_depth.map(|v| format!("{:.2}", v)).unwrap_or_default(),
                loca_type,
                bh.date_start.as_deref().unwrap_or(""),
                bh.date_end.as_deref().unwrap_or(""),
            ]));
        }
        sections.push(lines.join("\r\n"));
    }

    // ── GEOL: all geology layers ─────────────────────────────────
    {
        let mut lines = vec![
            ags_line(&["GROUP", "GEOL"]),
            ags_line(&["HEADING", "LOCA_ID", "GEOL_TOP", "GEOL_BASE", "GEOL_DESC", "GEOL_LEG"]),
            ags_line(&["UNIT", "", "m", "m", "", ""]),
            ags_line(&["TYPE", "ID", "2DP", "2DP", "X", "PA"]),
        ];
        for bh in boreholes {
            for l in &bh.layers {
                lines.push(ags_line(&["DATA", &bh.hole_id,
                    &format!("{:.2}", l.top), &format!("{:.2}", l.base),
                    &l.description, l.legend_code.as_deref().unwrap_or(""),
                ]));
            }
        }
        sections.push(lines.join("\r\n"));
    }

    // ── SAMP: all samples ────────────────────────────────────────
    let has_samples = boreholes.iter().any(|b| !b.samples.is_empty());
    if has_samples {
        let mut lines = vec![
            ags_line(&["GROUP", "SAMP"]),
            ags_line(&["HEADING", "LOCA_ID", "SAMP_TOP", "SAMP_TYPE", "SAMP_REF"]),
            ags_line(&["UNIT", "", "m", "", ""]),
            ags_line(&["TYPE", "ID", "2DP", "PA", "X"]),
        ];
        for bh in boreholes {
            for s in &bh.samples {
                lines.push(ags_line(&["DATA", &bh.hole_id,
                    &format!("{:.2}", s.depth_top), &s.sample_type,
                    s.sample_id.as_deref().unwrap_or(""),
                ]));
            }
        }
        sections.push(lines.join("\r\n"));
    }

    // ── ISPT: all SPT results ────────────────────────────────────
    let has_spts = boreholes.iter().any(|b| !b.spts.is_empty());
    if has_spts {
        let mut lines = vec![
            ags_line(&["GROUP", "ISPT"]),
            ags_line(&["HEADING", "LOCA_ID", "ISPT_TOP", "ISPT_NVAL", "ISPT_SEAT", "ISPT_MAIN"]),
            ags_line(&["UNIT", "", "m", "", "", ""]),
            ags_line(&["TYPE", "ID", "2DP", "0DP", "X", "X"]),
        ];
        for bh in boreholes {
            for t in &bh.spts {
                lines.push(ags_line(&["DATA", &bh.hole_id,
                    &format!("{:.2}", t.depth),
                    &t.n_value.map(|v| v.to_string()).unwrap_or_default(),
                    t.seating.as_deref().unwrap_or(""),
                    t.main.as_deref().unwrap_or(""),
                ]));
            }
        }
        sections.push(lines.join("\r\n"));
    }

    // ── ABBR: collect all abbreviations used ─────────────────────
    {
        let mut codes = BTreeSet::new();
        for bh in boreholes {
            if let Some(m) = &bh.method {
                let code = method_to_loca_type(m);
                if !code.is_empty() { codes.insert(code); }
            }
        }
        if !codes.is_empty() {
            let mut lines = vec![
                ags_line(&["GROUP", "ABBR"]),
                ags_line(&["HEADING", "ABBR_HDNG", "ABBR_CODE", "ABBR_DESC"]),
                ags_line(&["UNIT", "", "", ""]),
                ags_line(&["TYPE", "X", "X", "X"]),
            ];
            for code in &codes {
                lines.push(ags_line(&["DATA", "LOCA_TYPE", code, loca_type_desc(code)]));
            }
            sections.push(lines.join("\r\n"));
        }
    }

    // ── TYPE + UNIT (same as single-hole) ────────────────────────
    {
        let mut lines = vec![
            ags_line(&["GROUP", "TYPE"]),
            ags_line(&["HEADING", "TYPE_TYPE", "TYPE_DESC"]),
            ags_line(&["UNIT", "", ""]),
            ags_line(&["TYPE", "X", "X"]),
        ];
        let type_defs = [
            ("ID", "Unique identifier"),
            ("X", "Text"),
            ("DT", "Date and time"),
            ("2DP", "Value to 2 decimal places"),
            ("0DP", "Value to 0 decimal places"),
            ("PA", "Pick from abbreviation list"),
        ];
        for (code, desc) in &type_defs {
            lines.push(ags_line(&["DATA", code, desc]));
        }
        sections.push(lines.join("\r\n"));
    }
    {
        let mut lines = vec![
            ags_line(&["GROUP", "UNIT"]),
            ags_line(&["HEADING", "UNIT_UNIT", "UNIT_DESC"]),
            ags_line(&["UNIT", "", ""]),
            ags_line(&["TYPE", "X", "X"]),
        ];
        let unit_defs = [("m", "metre"), ("yyyy-mm-dd", "date")];
        for (code, desc) in &unit_defs {
            lines.push(ags_line(&["DATA", code, desc]));
        }
        sections.push(lines.join("\r\n"));
    }

    sections.join("\r\n\r\n") + "\r\n"
}

