#![cfg_attr(not(debug_assertions), windows_subsystem = "windows")]

fn main() {
    let args: Vec<String> = std::env::args().collect();

    // CLI batch mode: boreholeiq.exe --batch input_dir --output output_dir [--lang eng]
    if args.iter().any(|a| a == "--batch") {
        env_logger::init();
        let input = args.iter().position(|a| a == "--batch")
            .and_then(|i| args.get(i + 1)).map(|s| s.as_str())
            .unwrap_or(".");
        let output = args.iter().position(|a| a == "--output")
            .and_then(|i| args.get(i + 1)).map(|s| s.as_str())
            .unwrap_or("./output");
        let lang = args.iter().position(|a| a == "--lang")
            .and_then(|i| args.get(i + 1)).map(|s| s.as_str())
            .unwrap_or("eng");

        println!("BoreholeIQ v2 - Batch Mode");
        println!("  Input:  {}", input);
        println!("  Output: {}", output);
        println!("  Lang:   {}", lang);

        let input_path = std::path::Path::new(input);
        let output_path = std::path::Path::new(output);
        std::fs::create_dir_all(output_path).expect("Cannot create output directory");

        // Collect input files
        let extensions = ["pdf", "png", "jpg", "jpeg", "tif", "tiff", "bmp", "webp", "xlsx", "ags"];
        let files: Vec<_> = if input_path.is_file() {
            vec![input_path.to_path_buf()]
        } else {
            std::fs::read_dir(input_path)
                .expect("Cannot read input directory")
                .filter_map(|e| e.ok())
                .map(|e| e.path())
                .filter(|p| {
                    p.extension()
                        .and_then(|e| e.to_str())
                        .map(|e| extensions.contains(&e.to_lowercase().as_str()))
                        .unwrap_or(false)
                })
                .collect()
        };

        println!("  Files:  {}", files.len());
        let (mut ok, mut fail) = (0usize, 0usize);

        let rt = tokio::runtime::Runtime::new().expect("Cannot create runtime");
        for file in &files {
            let name = file.file_name().unwrap_or_default().to_string_lossy().to_string();
            print!("  Processing {}... ", name);

            // Create a dummy AppHandle — CLI mode doesn't need events
            // Instead, call pipeline components directly
            let ext = file.extension().and_then(|e| e.to_str()).unwrap_or("").to_lowercase();

            let result = match ext.as_str() {
                "xlsx" | "xls" => {
                    borehole_iq_lib::pipeline::xlsx::try_parse_xlsx(file)
                        .and_then(|bh| {
                            borehole_iq_lib::pipeline::writer::write_outputs(&bh, output_path, "metric", "DMY")
                        })
                }
                "ags" => {
                    borehole_iq_lib::pipeline::ags_reader::parse_ags4_file(file)
                        .and_then(|bhs| {
                            for bh in &bhs {
                                borehole_iq_lib::pipeline::writer::write_outputs(bh, output_path, "metric", "DMY")?;
                            }
                            Ok(())
                        })
                }
                _ => {
                    // PDF/image: need full pipeline with OCR — requires AppHandle for events
                    // In CLI mode, we skip the event system
                    Err("CLI mode for PDF/images requires the GUI pipeline (use the app)".into())
                }
            };

            match result {
                Ok(()) => { println!("OK"); ok += 1; }
                Err(e) => { println!("FAILED: {}", e); fail += 1; }
            }
        }

        println!("\n  Results: {} OK, {} failed of {}", ok, fail, files.len());
        std::process::exit(if fail > 0 { 1 } else { 0 });
    }

    // Normal GUI mode
    borehole_iq_lib::models::userdict::ensure_folder();
    borehole_iq_lib::run()
}

