#[derive(Clone, serde::Serialize)]
struct ProgressEvent { file: String, message: String, kind: String }

fn emit(app: &AppHandle, file: &str, msg: &str, kind: &str) {
    let _ = app.emit("progress", ProgressEvent {
        file: file.to_string(), message: msg.to_string(), kind: kind.to_string() });
}

/// Extraction mode — persisted in user settings
#[derive(Clone, Debug, serde::Serialize, serde::Deserialize, PartialEq)]
pub enum ExtractionMode {
    Auto,       // Try local AI → regex (best available)
    LocalAI,    // Ollama only, regex fallback
    Pattern,    // Regex only (fastest, always offline)
}

impl Default for ExtractionMode {
    fn default() -> Self { ExtractionMode::Auto }
}

pub async fn run_pipeline(
    app: &AppHandle, input: &Path, output_dir: &Path,
    lang: &str, units: &str, date_format: &str,
) -> Result<String, String> {
    let nm = input.file_name().unwrap_or_default().to_string_lossy().to_string();

    emit(app, &nm, "Preprocessing...", "info");
    let preprocess_result = preprocess::preprocess(input).map_err(|e| format!("Pre: {}", e))?;
    let pgs = &preprocess_result.pages;
    emit(app, &nm, &format!("{} page(s)", pgs.len()), "info");

    // Fast path: try extracting text layer from born-digital PDFs (no OCR needed)
    let ext = input.extension().and_then(|e| e.to_str()).unwrap_or("").to_lowercase();

    // ── Direct parsers for structured formats (no OCR needed) ────
    match ext.as_str() {
        "xlsx" | "xls" => {
            emit(app, &nm, "Parsing Excel spreadsheet...", "info");
            match xlsx::try_parse_xlsx(input) {
                Ok(bh) => {
                    emit(app, &nm, &format!("Excel: {} layers, {} SPTs", bh.layers.len(), bh.spts.len()), "ok");
                    writer::write_outputs(&bh, output_dir, units, date_format).map_err(|e| format!("Write: {}", e))?;
                    return Ok(format!("{} layers {} samples {} SPTs (from Excel)", bh.layers.len(), bh.samples.len(), bh.spts.len()));
                }
                Err(e) => {
                    emit(app, &nm, &format!("Excel parse issue: {} — trying as text extraction", e), "warn");
                    // Fall through to OCR pipeline (treat as generic file)
                }
            }
        }
        "ags" => {
            emit(app, &nm, "Parsing AGS4 file...", "info");
            let bhs = ags_reader::parse_ags4_file(input).map_err(|e| format!("AGS: {}", e))?;
            for bh in &bhs {
                writer::write_outputs(bh, output_dir, units, date_format).map_err(|e| format!("Write: {}", e))?;
            }
            let total_layers: usize = bhs.iter().map(|b| b.layers.len()).sum();
            emit(app, &nm, &format!("AGS: {} holes, {} total layers", bhs.len(), total_layers), "ok");
            return Ok(format!("{} holes from AGS4", bhs.len()));
        }
        _ => {} // Continue to OCR pipeline for PDF/images
    }

    let mut txt = String::new();
    let mut used_text_layer = false;
    if ext == "pdf" {
        if let Some(text) = ocr::try_pdf_text_layer(input) {
            emit(app, &nm, &format!("Text layer found ({} chars) — skipping OCR", text.len()), "info");
            txt = text;
            used_text_layer = true;
        }
    }

    if !used_text_layer {
        for (i, pg) in pgs.iter().enumerate() {
            if crate::commands::abort::should_abort() {
                return Err("Aborted by user".into());
            }
            emit(app, &nm, &format!("OCR page {}/{}", i+1, pgs.len()), "info");
            match ocr::ocr_page(pg, lang) {
                Ok(page_text) => txt.push_str(&page_text),
                Err(_e) => {
                    emit(app, &nm, &format!("OCR retry page {}/{}", i+1, pgs.len()), "warn");
                    match ocr::ocr_page(pg, lang) {
                        Ok(page_text) => txt.push_str(&page_text),
                        Err(e2) => {
                            emit(app, &nm, &format!("OCR page {} failed after retry: {} — skipping page", i+1, e2), "warn");
                            // Continue with other pages instead of aborting
                        }
                    }
                }
            }
        }

        // ── Smart re-OCR: detect language mismatch ────────────
        // If the OCR text has very few recognizable words, the language might be wrong.
        // Use whatlang to detect actual language and re-OCR if different.
        let meaningful_chars = txt.chars().filter(|c| c.is_alphanumeric()).count();
        if meaningful_chars > 50 && txt.len() > 100 {
            if let Some(detected_lang) = ocr::detect_language(&txt) {
                if detected_lang != lang && detected_lang != "eng" {
                    emit(app, &nm, &format!("Language mismatch: selected '{}', detected '{}' — re-running OCR", lang, detected_lang), "warn");
                    let mut txt2 = String::new();
                    for (i, pg) in pgs.iter().enumerate() {
                        if let Ok(page_text) = ocr::ocr_page(pg, &detected_lang) {
                            txt2.push_str(&page_text);
                        }
                    }
                    // Use re-OCR result if it produced more meaningful content
                    let meaningful2 = txt2.chars().filter(|c| c.is_alphanumeric()).count();
                    if meaningful2 > meaningful_chars {
                        emit(app, &nm, &format!("Re-OCR improved: {} -> {} meaningful chars", meaningful_chars, meaningful2), "ok");
                        txt = txt2;
                    } else {
                        emit(app, &nm, "Re-OCR did not improve results, keeping original", "info");
                    }
                }
            }
        }
    }

    // ── Page classification: filter out non-borehole pages ──
    // Research validates this as "the quality-determining first step"
    if !used_text_layer && pgs.len() > 1 {
        // Re-OCR each page individually for classification
        let mut page_texts: Vec<(usize, String)> = Vec::new();
        let mut offset = 0usize;
        for (i, pg) in pgs.iter().enumerate() {
            // Estimate page text from the concatenated txt
            // Simple approach: split txt roughly by page count
            let page_len = txt.len() / pgs.len().max(1);
            let start = offset;
            let end = (offset + page_len).min(txt.len());
            let page_text = txt[start..end].to_string();
            page_texts.push((i + 1, page_text));
            offset = end;
        }

        let classified = page_classifier::filter_borehole_pages(&page_texts);
        let excluded_count = page_texts.len() - classified.len();
        if excluded_count > 0 {
            emit(app, &nm, &format!("Page classification: {} of {} pages are borehole data ({} excluded)",
                classified.len(), page_texts.len(), excluded_count), "info");
            // Reconstruct txt from only borehole pages
            txt = classified.iter().map(|(_, text, _)| text.as_str()).collect::<Vec<_>>().join("
");
        }
    }

    // Load user's preferred extraction mode (default: Auto)
    let mode = load_extraction_mode();
    emit(app, &nm, &format!("Extraction mode: {:?}", mode), "info");

    let mut bh = match mode {
        ExtractionMode::Auto => {
            // Try local AI → regex
            if let Some(b) = try_local_ai(&txt, &nm, app).await {
                b
            } else {
                // Try spatial extraction first for PDFs (table geometry)
                let mut spatial_result: Option<Borehole> = None;
                if ext == "pdf" {
                    emit(app, &nm, "Trying spatial table extraction...", "info");
                    if let Some(spatial_rows) = spatial::try_spatial_extraction(input) {
                        let layers = spatial::spatial_rows_to_layers(&spatial_rows);
                        if layers.len() >= 2 {
                            emit(app, &nm, &format!("Spatial: {} layers from table geometry", layers.len()), "ok");
                            let mut bh = parser::parse_borehole_text(&txt, &nm).unwrap_or_else(|_| {
                                Borehole::new(nm.clone())
                            });
                            if layers.len() > bh.layers.len() {
                                bh.layers = layers;
                            }
                            for row in &spatial_rows {
                                if let (Some(depth), Some(n)) = (row.depth_top, row.spt_n) {
                                    if !bh.spts.iter().any(|s| (s.depth - depth).abs() < 0.1) {
                                        bh.spts.push(SptResult { depth, n_value: Some(n), ..Default::default() });
                                    }
                                }
                            }
                            spatial_result = Some(bh);
                        }
                    }
                }
                if let Some(bh) = spatial_result {
                    bh
                } else {
                    emit(app, &nm, "Using pattern matching", "info");
                    let parse_start = std::time::Instant::now();
                    let result = match parser::parse_borehole_text(&txt, &nm) {
                        Ok(bh) => bh,
                        Err(e) => {
                            emit(app, &nm, &format!("Pattern matching had issues: {} — producing partial result", e), "warn");
                            Borehole::new(nm.clone())
                        }
                    };
                    let parse_ms = parse_start.elapsed().as_millis();
                    emit(app, &nm, &format!("Pattern matching done ({} ms)", parse_ms), "info");
                    result
                }
            }
        },
        ExtractionMode::LocalAI => {
            if let Some(b) = try_local_ai(&txt, &nm, app).await {
                b
            } else {
                emit(app, &nm, "Local AI unavailable, using patterns", "warn");
                match parser::parse_borehole_text(&txt, &nm) {
                    Ok(bh) => bh,
                    Err(e) => {
                        emit(app, &nm, &format!("Pattern matching had issues: {} — partial result", e), "warn");
                        Borehole::new(nm.clone())
                    }
                }
            }
        },
        ExtractionMode::Pattern => {
            emit(app, &nm, "Pattern matching (fastest)", "info");
            match parser::parse_borehole_text(&txt, &nm) {
                Ok(bh) => bh,
                Err(e) => {
                    emit(app, &nm, &format!("Pattern matching had issues: {} — partial result", e), "warn");
                    Borehole::new(nm.clone())
                }
            }
        },
    };

    // Report what we found and what's missing
    if bh.layers.is_empty() {
        emit(app, &nm, "WARNING: No geology layers extracted — output will be incomplete. Check OCR quality or language setting.", "warn");
    }
    emit(app, &nm, &format!("Parsed: {} layers, {} samples, {} SPTs", bh.layers.len(), bh.samples.len(), bh.spts.len()), "info");
    if bh.easting.is_none() { emit(app, &nm, "Note: No coordinates found — add manually to output CSV", "info"); }
    if bh.date_start.is_none() { emit(app, &nm, "Note: No dates found", "info"); }
    let ws = validator::validate_and_repair(&mut bh);
    for w in &ws { emit(app, &nm, &format!("WARN: {}", w), "warn"); }

    // Apply user project defaults as fallbacks
    {
        let dict = crate::models::userdict::get();
        let defs = &dict.defaults;
        if bh.crs.is_none() {
            bh.crs = defs.crs.clone();
        }
        if bh.method.is_none() {
            bh.method = defs.default_method.clone();
        }
    }

    // Apply metadata extracted using user-defined metadata keys
    {
        let dict = crate::models::userdict::get();
        if !dict.metadata_keys.is_empty() {
            for line in txt.lines() {
                // Match "KEY : VALUE" or "KEY: VALUE" patterns
                if let Some(colon_pos) = line.find(':') {
                    let key_part = line[..colon_pos].trim();
                    let val_part = line[colon_pos+1..].trim();
                    if val_part.is_empty() || key_part.len() > 40 { continue; }
                    if let Some(standard_key) = dict.lookup_metadata_key(key_part) {
                        match standard_key.as_str() {
                            "location" => {
                                // Store as project location (available in output)
                                emit(app, &nm, &format!("META location: {}", val_part), "info");
                            },
                            "water_level" => {
                                emit(app, &nm, &format!("META water level: {}", val_part), "info");
                            },
                            "operator" => {
                                emit(app, &nm, &format!("META operator: {}", val_part), "info");
                            },
                            "hole_id" if bh.hole_id == nm => {
                                // Only override if hole_id is still the filename fallback
                                let id = val_part.trim().to_string();
                                if id.len() >= 2 && id.len() <= 40 {
                                    emit(app, &nm, &format!("META hole_id override: {}", id), "info");
                                    bh.hole_id = id;
                                }
                            },
                            _ => {}
                        }
                    }
                }
            }
        }
    }

    writer::write_outputs(&bh, output_dir, units, date_format).map_err(|e| format!("Write: {}", e))?;
    emit(app, &nm, &format!("Output written to {}/{}", output_dir.display(), bh.hole_id), "info");

    // Save successful extraction as few-shot example for future LLM calls
    llm::save_example(&txt, &bh);

    // Auto-learn: record matched terms for frequency tracking
    {
        let dict = crate::models::userdict::get();
        for layer in &bh.layers {
            let words: Vec<&str> = layer.description.split_whitespace().collect();
            for word in &words {
                let upper = word.to_uppercase();
                if dict.terms.contains_key(&upper) {
                    dict.record_match(&upper);
                }
                // Check for OCR near-misses and auto-fix
                dict.check_ocr_near_miss(&upper);
            }
        }
        // Propagate project defaults from first successful extraction
        dict.propagate_defaults(
            bh.crs.as_deref(),
            None, // project name not extracted yet
            None, // company not extracted yet
        );
    }

    drop(preprocess_result);
    Ok(format!("{} layers {} samples {} SPTs", bh.layers.len(), bh.samples.len(), bh.spts.len()))
}

async fn try_local_ai(text: &str, file_name: &str, app: &AppHandle) -> Option<Borehole> {
    if !llm::is_available().await {
        emit(app, file_name, "Local AI not available, skipping", "info");
        return None;
    }
    emit(app, file_name, "Local AI extracting (this may take 30-60s on CPU)...", "info");
    let ai_start = std::time::Instant::now();
    match llm::extract_with_llm(text, file_name).await {
        Ok(bh) => {
            let secs = ai_start.elapsed().as_secs();
            emit(app, file_name, &format!("Local AI complete ({} s, {} layers)", secs, bh.layers.len()), "ok");
            Some(bh)
        }
        Err(e) => {
            let secs = ai_start.elapsed().as_secs();
            emit(app, file_name, &format!("Local AI failed after {} s: {}", secs, e), "warn");
            None
        }
    }
}

fn load_extraction_mode() -> ExtractionMode {
    let dir = if let Some(d) = std::env::var_os("LOCALAPPDATA") {
        std::path::PathBuf::from(d).join("BoreholeIQ")
    } else {
        std::path::PathBuf::from(".")
    };
    let path = dir.join("extraction_mode.json");
    std::fs::read_to_string(&path)
        .ok()
        .and_then(|s| serde_json::from_str(&s).ok())
        .unwrap_or_default()
}

