use regex::Regex;
use once_cell::sync::Lazy;
use crate::models::borehole::*;

/// Pre-compiled regex cache. Compiles each pattern once, reuses forever.
fn cached_regex(pattern: &str) -> Option<Regex> {
    use std::collections::HashMap;
    use std::sync::Mutex;
    static CACHE: Lazy<Mutex<HashMap<String, Regex>>> =
        Lazy::new(|| Mutex::new(HashMap::new()));
    let mut cache = CACHE.lock().ok()?;
    if let Some(re) = cache.get(pattern) {
        return Some(re.clone());
    }
    match Regex::new(pattern) {
        Ok(re) => { cache.insert(pattern.to_string(), re.clone()); Some(re) }
        Err(_) => None,
    }
}

pub fn parse_borehole_text(text: &str, file_name: &str) -> Result<Borehole, String> {
    // Run parsing in a thread with a hard 10-second timeout
    let text_owned = text.to_string();
    let fname_owned = file_name.to_string();
    let handle = std::thread::spawn(move || {
        parse_borehole_inner(&text_owned, &fname_owned)
    });
    match handle.join() {
        Ok(result) => result,
        Err(e) => {
            let msg = if let Some(s) = e.downcast_ref::<String>() {
                format!("Parser thread panicked: {}", s)
            } else if let Some(s) = e.downcast_ref::<&str>() {
                format!("Parser thread panicked: {}", s)
            } else {
                "Parser thread panicked (unknown cause). The file may contain unexpected content.".to_string()
            };
            log::error!("{}", msg);
            Err(msg)
        }
    }
}

fn parse_borehole_inner(text: &str, file_name: &str) -> Result<Borehole, String> {
    // Truncate very long OCR text to prevent regex hanging (> 50K chars is suspicious)
    let max_text = 50_000;
    let truncated = if text.len() > max_text { &text[..max_text] } else { text };

    // Apply user OCR fixes before any parsing
    let dict = crate::models::userdict::get();
    let text = &dict.apply_ocr_fixes(truncated);
    drop(dict); // Release read lock early

    log::info!("Parsing: hole_id extraction...");
    let mut bh = Borehole::new(extract_hole_id(text, file_name));
    log::info!("Parsing: coordinates...");
    bh.easting = extract_coordinate(text, CoordKind::Easting);
    bh.northing = extract_coordinate(text, CoordKind::Northing);
    bh.elevation = extract_elevation(text);
    log::info!("Parsing: dates...");
    bh.date_start = extract_date(text, true);
    bh.date_end = extract_date(text, false);
    bh.method = extract_method(text);
    bh.crs = extract_crs(text);
    log::info!("Parsing: project metadata...");
    bh.project_name = extract_header_field(text, &["PROJECT", "PROYEK", "JOB", "SITE", "DU AN", "PROJEK", "NAMA PROYEK"]);
    bh.client = extract_header_field(text, &["CLIENT", "KLIEN", "OWNER", "PEMILIK", "FOR", "CHU DAU TU", "PELANGGAN"]);
    bh.contractor = extract_header_field(text, &["CONTRACTOR", "KONTRAKTOR", "DRILLED BY", "DRILLING", "COMPANY", "PERUSAHAAN", "NHA THAU", "SYARIKAT"]);
    bh.location_desc = extract_header_field(text, &["LOCATION", "LOKASI", "ADDRESS", "ALAMAT", "AREA", "DIA DIEM", "TEMPAT", "LUGAR"]);
    bh.water_level = extract_water_level(text);
    log::info!("Parsing: geology layers...");
    bh.layers = extract_geology(text);
    log::info!("Parsing: samples ({} layers found)...", bh.layers.len());
    bh.samples = extract_samples(text);
    log::info!("Parsing: SPTs...");
    bh.spts = extract_spts(text);
    bh.final_depth = bh.layers.last().map(|l| l.base);
    log::info!("Parsing complete: {} layers, {} samples, {} SPTs", bh.layers.len(), bh.samples.len(), bh.spts.len());
    Ok(bh)
}

// ── Hole ID ──────────────────────────────────────────────────

fn extract_hole_id(t: &str, fallback: &str) -> String {
    // User-defined hole ID patterns (priority over built-in)
    let dict = crate::models::userdict::get();
    let user_id_pats = dict.hole_id_patterns.clone();
    drop(dict);
    for user_pat in &user_id_pats {
        if let Some(re) = cached_regex(user_pat) {
            if let Some(caps) = re.captures(t) {
                if let Some(m) = caps.get(1) {
                    let id = m.as_str().trim().to_string();
                    if id.len() >= 2 && id.len() <= 40 {
                        return id;
                    }
                }
            }
        }
    }

    let patterns = [
        // Indonesian: "NO. BOR (STA.) : BH TIM 05" — moved FIRST for priority
        r"(?mi)(?:no\.?\s*(?:bor|titik|lubang)|nomor\s*(?:bor|titik|lubang))[^:\n]{0,20}:\s*(.+?)$",
        // "Borehole No: BH-01" / "Hole ID: BH01" / "BORE HOLE NO. S-TIM-09"
        r"(?i)(?:borehole|bore\s*hole|hole)\s*(?:id|no|number|ref|reference)?[\s:.=#]*([A-Za-z]{1,4}[\-_]?\d{1,6}[A-Za-z0-9\-_.]*)",
        // Indonesian: "NO. BOR (STA.) : BH TIM 05" / "NO TITIK : RK3-BH-TIM-04"
        r"(?mi)(?:no\.?\s*(?:bor|titik|lubang)|nomor\s*(?:bor|titik|lubang))[^:\n]{0,20}:\s*(.+?)$",
        // "BORE HOLE NO." followed by value (with spaces like "S-TIM-09")
        r"(?i)bore\s*hole\s*no\.?\s*[:\s=]*([\w][\w\-_.]+)",
        // "BH-01" / "BH01" / "TP-03" / "CPT-01" standalone at line start (with spaces)
        r"(?m)^\s*((?:BH|TP|CP|WS|RC|DP|DH|MH|SP|CPT|DR\d?)[\-_\s]?[\w\-_.]+)",
        // "CPT : DR1-CPT-TIM-11"
        r"(?i)CPT\s*[:\s=]*([\w][\w\-_.]+)",
        // LOCA_ID or HOLE_ID in AGS-like text
        r#"(?i)(?:LOCA_ID|HOLE_ID)[\s:,"]*([A-Za-z0-9][\w\-_.]+)"#,
    ];
    for pat in &patterns {
        if let Some(re) = cached_regex(pat) {
            if let Some(caps) = re.captures(t) {
                if let Some(m) = caps.get(1) {
                    let id = m.as_str().trim().to_string();
                    if id.len() >= 2 && id.len() <= 30 {
                        return id;
                    }
                }
            }
        }
    }
    // Fallback: clean filename
    let stem = fallback.rsplit(['/', '\\']).next().unwrap_or(fallback);
    stem.strip_suffix(".pdf").or(stem.strip_suffix(".png"))
        .or(stem.strip_suffix(".jpg")).or(stem.strip_suffix(".tif"))
        .unwrap_or(stem).to_string()
}

// ── Coordinates ──────────────────────────────────────────────

enum CoordKind { Easting, Northing }

fn extract_coordinate(t: &str, kind: CoordKind) -> Option<f64> {
    let patterns: Vec<&str> = match kind {
        CoordKind::Easting => vec![
            // Standard English
            r"(?i)(?:easting|east)[\s:=]*(\d{4,7}\.?\d*)",
            // E= or E: format (Indonesian logs)
            r"(?m)(?:^|\s)E[\s:=]+(\d{4,7}\.?\d*)",
            // "X:" or "X :" or "X Coords :" format
            r"(?i)X\s*(?:Coords?\s*)?[:\s=]+(\d{4,7}\.?\d*)",
            // "Coordinate UTM" followed by "easting, northing" — capture first number
            r"(?i)Coordin\w*\s*(?:UTM)?\s*[:\s=]*(\d{4,7}\.\d+)\s*[,;]\s*\d{4,7}",
            // LOCA_NATE / HOLE_NATE
            r#"(?i)(?:LOCA_NATE|HOLE_NATE)[\s:,"]*(\d{4,7}\.?\d*)"#,
            // Longitude
            r"(?i)(?:longitude|lon|lng)[\s:=]*(-?\d{1,3}\.\d{3,})",
        ],
        CoordKind::Northing => vec![
            r"(?i)(?:northing|north)[\s:=]*(\d{4,7}\.?\d*)",
            // N= format (but must be followed by digits to avoid N:6 SPT matches)
            r"(?m)(?:^|\s)N[\s:=]+(\d{4,7}\.?\d*)",
            // "Y:" or "Y Coords :" format
            r"(?i)Y\s*(?:Coords?\s*)?[:\s=]+(\d{4,7}\.?\d*)",
            // "Coordinate UTM" — capture second number after comma
            r"(?i)Coordin\w*\s*(?:UTM)?\s*[:\s=]*\d{4,7}\.\d+\s*[,;]\s*(\d{4,7}\.\d+)",
            r#"(?i)(?:LOCA_NATN|HOLE_NATN)[\s:,"]*(\d{4,7}\.?\d*)"#,
            r"(?i)(?:latitude|lat)[\s:=]*(-?\d{1,3}\.\d{3,})",
        ],
    };
    for pat in &patterns {
        if let Some(re) = cached_regex(pat) {
            if let Some(caps) = re.captures(t) {
                if let Some(val) = caps.get(1).and_then(|m| m.as_str().parse::<f64>().ok()) {
                    return Some(val);
                }
            }
        }
    }
    None
}

// ── Elevation ────────────────────────────────────────────────

fn extract_elevation(t: &str) -> Option<f64> {
    let patterns = [
        r"(?i)(?:ground\s*level|elevation|GL|RL|surface\s*level|ELEVASI)[\s:=]*([+-]?\d+\.?\d*)\s*(?:m|M|mAOD|mRL|masl)?",
        r#"(?i)(?:LOCA_GL|HOLE_GL)[\s:,"]*([+-]?\d+\.?\d*)"#,
    ];
    for pat in &patterns {
        if let Some(re) = cached_regex(pat) {
            if let Some(caps) = re.captures(t) {
                return caps.get(1).and_then(|m| m.as_str().parse().ok());
            }
        }
    }
    None
}

// ── Dates ────────────────────────────────────────────────────

fn extract_date(t: &str, is_start: bool) -> Option<String> {
    let keywords = if is_start {
        // English + Indonesian (TANGGAL MULAI = date started)
        r"(?i)(?:date\s*(?:started|commenced|drilled|start|from|begin)|start\s*date|commenced|tanggal\s*mulai)"
    } else {
        r"(?i)(?:date\s*(?:completed|finished|ended|end|to)|end\s*date|completed|tanggal\s*(?:berakhir|selesai))"
    };
    let date_pat = r"(\d{1,2}[\s/\-\.]\s*(?:\w+|\d{1,2})[\s/\-\.]\s*\d{2,4})";
    let pat = format!(r"{}[\s:=]*{}", keywords, date_pat);
    if let Some(re) = cached_regex(&pat) {
        if let Some(caps) = re.captures(t) {
            return caps.get(1).map(|m| crate::models::geoterms::normalize_date(m.as_str()));
        }
    }
    // Fallback: single TANGGAL : dd/mm/yyyy (common in Indonesian reports)
    if is_start {
        let fallback = r"(?i)tanggal[\s:=]*(\d{1,2}[\s/\-\.]\s*\w+\s*\d{2,4})";
        if let Some(re) = cached_regex(fallback) {
            if let Some(caps) = re.captures(t) {
                return caps.get(1).map(|m| crate::models::geoterms::normalize_date(m.as_str()));
            }
        }
    }
    None
}

// ── Method ───────────────────────────────────────────────────

fn extract_method(t: &str) -> Option<String> {
    let patterns = [
        r"(?i)(?:method|type\s*of\s*investigation|investigation\s*type|drilling\s*method|metode)[\s:=]*((?:cable\s*percussion|rotary|(?:light\s*)?percussive|window\s*sampl\w*|trial\s*pit|hand\s*auger|sonic|CPT|CPTU|SPT|dynamic\s*probing|pemboran\s*inti|core\s*drilling)[A-Za-z\s]*)",
    ];
    for pat in &patterns {
        if let Some(re) = cached_regex(pat) {
            if let Some(caps) = re.captures(t) {
                return caps.get(1).map(|m| m.as_str().trim().to_string());
            }
        }
    }
    // Infer from hole ID prefix or keywords
    let tl = t.to_lowercase();
    if tl.contains("tp-") || tl.contains("trial pit") { return Some("TP".into()); }
    if tl.contains("ws-") || tl.contains("window sampl") { return Some("WS".into()); }
    if tl.contains("cp-") || tl.contains("cable percuss") { return Some("CP".into()); }
    if tl.contains("cpt") || tl.contains("sondir") { return Some("CPT".into()); }
    if tl.contains("pemboran") || tl.contains("deep boring") { return Some("Rotary".into()); }
    None
}

// ── CRS (Coordinate Reference System) ───────────────────────

fn extract_crs(t: &str) -> Option<String> {
    let patterns = [
        // "UTM Zone 48N" / "UTM Zone 50S" / "UTM 48N"
        r"(?i)UTM\s*(?:Zone\s*)?(\d{1,2}[NS])",
        // "WGS[ -]?84" / "WGS 1984"
        r"(?i)(WGS[\s\-]?(?:84|1984))",
        // "EPSG:32748" / "EPSG 32748"
        r"(?i)EPSG[\s:]*(\d{4,5})",
        // Indonesian: "Sistem Koordinat UTM 48S"
        r"(?i)(?:sistem\s*)?koordinat\s+(?:UTM\s*)?(\d{1,2}[NS])",
    ];
    for pat in &patterns {
        if let Some(re) = cached_regex(pat) {
            if let Some(caps) = re.captures(t) {
                return caps.get(1).map(|m| {
                    let v = m.as_str().to_uppercase();
                    if v.chars().all(|c| c.is_ascii_digit() || c == 'N' || c == 'S') && v.len() <= 3 {
                        format!("UTM Zone {}", v)
                    } else {
                        v
                    }
                });
            }
        }
    }
    None
}


// ── Geology ──────────────────────────────────────────────────

fn extract_geology(t: &str) -> Vec<GeologyLayer> {
    let mut layers: Vec<GeologyLayer> = Vec::new();

    // Load user-defined depth patterns first (they take priority)
    let dict = crate::models::userdict::get();
    let user_patterns = dict.depth_patterns.clone();
    drop(dict);
    for user_pat in &user_patterns {
        if let Some(re) = cached_regex(user_pat) {
            for caps in re.captures_iter(t) {
                let top: f64 = match caps.get(1).and_then(|m| m.as_str().parse().ok()) { Some(v) => v, None => continue };
                let base: f64 = match caps.get(2).and_then(|m| m.as_str().parse().ok()) { Some(v) => v, None => continue };
                if base <= top || base > 200.0 || top < 0.0 { continue; }
                let desc = caps.get(3).map(|m| m.as_str().trim().to_string()).unwrap_or_default();
                if desc.len() < 3 { continue; }
                if layers.iter().any(|l| (l.top - top).abs() < 0.01 && (l.base - base).abs() < 0.01) { continue; }
                let legend = infer_legend_code(&desc);
                layers.push(GeologyLayer {
                    top, base, description: desc, legend_code: legend,
                    confidence: 0.80,
                });
            }
        }
        if !layers.is_empty() { break; }
    }

    // Built-in patterns (used if user patterns didn't match)
    let patterns = [
        // Pattern 1: "0.00 - 1.50 m Description" or "0.00-1.50 Description"
        r"(?m)(\d+\.?\d*)\s*(?:[-~]+|to)\s*(\d+\.?\d*)\s*(?:m\b|M\b)?\s+([A-Z][^\n]{5,120})",
        // Pattern 2: "(00.00-04.00) Description" — Indonesian parenthesized format
        r"(?m)^\s*\((\d+\.?\d*)\s*[-~]+\s*(\d+\.?\d*)\)\s*([A-Za-z][^\n]{5,120})",
        // Pattern 3: "0.00  1.50  Description" (table format, tab/multi-space)
        r"(?m)^\s*(\d+\.?\d*)\s{2,}(\d+\.?\d*)\s{2,}([A-Z][^\n]{5,120})",
        // Pattern 4: depth pair then description on next line
        r"(?m)(\d+\.?\d*)\s*m?\s*(?:[-~]+|to)\s*(\d+\.?\d*)\s*m?\s*\n\s*([A-Z][a-z][^\n]{5,120})",
        // Pattern 5: "From 0.00m To 1.50m: Description"
        r"(?mi)from\s*(\d+\.?\d*)\s*m?\s*to\s*(\d+\.?\d*)\s*m?\s*[:\-]?\s*([^\n]{5,120})",
        // Pattern 6: Indonesian table — standalone integer depths with description nearby
        // Matches: "1\nLEMPUNG lanauan..." where depth numbers are on their own line
        r"(?m)^\s*(\d{1,2})\s*\n\s*(\d{1,2})\s*\n[^\n]*?((?:LEMPUNG|PASIR|LANAU|KERIKIL|GAMBUT|BATU|TANAH)[^\n]{3,120})",
    ];

    for pat in &patterns {
        if let Some(re) = cached_regex(pat) {
            for caps in re.captures_iter(t) {
                let top: f64 = match caps[1].parse() { Ok(v) => v, Err(_) => continue };
                let base: f64 = match caps[2].parse() { Ok(v) => v, Err(_) => continue };
                if base <= top || base > 200.0 || top < 0.0 { continue; }
                let desc = caps[3].trim().to_string();
                if desc.len() < 3 { continue; }
                if layers.iter().any(|l| (l.top - top).abs() < 0.01 && (l.base - base).abs() < 0.01) {
                    continue;
                }
                let legend = infer_legend_code(&desc);
                layers.push(GeologyLayer {
                    top, base, description: desc, legend_code: legend,
                    confidence: 0.85,
                });
            }
        }
        if !layers.is_empty() { break; }
    }
    // Fallback: if no depth-range patterns matched, try keyword-based extraction
    // Find lines containing soil type keywords and assign 1m layers sequentially
    if layers.is_empty() {
        let soil_keywords = [
            "LEMPUNG", "PASIR", "LANAU", "KERIKIL", "GAMBUT", "BATU", "TANAH",
            "CLAY", "SAND", "SILT", "GRAVEL", "PEAT", "FILL", "TOPSOIL", "ROCK",
            "MUDSTONE", "SANDSTONE", "LIMESTONE",
        ];
        let mut last_top = 0.0f64;
        for line in t.lines() {
            let upper = line.trim().to_uppercase();
            if upper.len() < 5 || upper.len() > 200 { continue; }
            // Skip lines excluded by user dictionary (metadata, headers, etc.)
            let dict = crate::models::userdict::get();
            if dict.should_exclude_line(line.trim()) { continue; }
            drop(dict);
            let has_keyword = soil_keywords.iter().any(|kw| upper.contains(kw));
            if !has_keyword { continue; }
            // Skip lines that are just numbers or headers
            if upper.chars().all(|c| c.is_ascii_digit() || c.is_whitespace() || c == '.' || c == '%') { continue; }
            // Try to find a nearby depth number on the same line (e.g., "100%  PASIR lanauan...")
            // Avoid matching percentages as depths
            let desc = line.trim().to_string();
            // Try to extract depth from numbers at start of line
            let depth_re = cached_regex(r"^\s*(\d{1,2}(?:\.\d+)?)\s").unwrap();
            let top = if let Some(caps) = depth_re.captures(line.trim()) {
                if let Ok(d) = caps[1].parse::<f64>() {
                    if d >= last_top && d < 100.0 { d } else { last_top }
                } else { last_top }
            } else { last_top };
            let base = top + 1.0; // Assume 1m layers if no explicit base depth
            if layers.iter().any(|l| (l.top - top).abs() < 0.01) { continue; }
            let legend = infer_legend_code(&desc);
            layers.push(GeologyLayer {
                top, base, description: desc, legend_code: legend,
                confidence: 0.5, // Lower confidence for keyword-inferred layers
            });
            last_top = base;
        }
    }

    layers.sort_by(|a, b| a.top.partial_cmp(&b.top).unwrap_or(std::cmp::Ordering::Equal));
    layers
}

// ── Legend Code Inference (English + Indonesian) ──────────────

fn infer_legend_code(desc: &str) -> Option<String> {
    // 1. Check user dictionary first (user terms always win)
    let dict = crate::models::userdict::get();
    if let Some(user_term) = dict.lookup_term(desc) {
        return Some(user_term);
    }
    // 2. Check user legend codes (USCS codes etc)
    if let Some(user_legend) = dict.lookup_legend(desc) {
        return Some(user_legend);
    }
    drop(dict);
    // 3. Fall back to hardcoded multilingual dictionary
    crate::models::geoterms::lookup_legend(desc).map(|(code, _)| code.to_string())
}

// ── Samples ──────────────────────────────────────────────────

fn extract_samples(t: &str) -> Vec<Sample> {
    let mut samples: Vec<Sample> = Vec::new();

    let patterns = [
        // "Sample at 3.50m" / "sample taken at 5.0 m"
        r"(?mi)sample\w*\s*(?:at|taken\s*at|from)?\s*(\d+\.?\d*)\s*(?:m\b|M\b)",
        // "D 3.50-4.00" / "U 5.00-5.45" (sample type + depth range)
        r"(?m)\b([DUBW])\s+(\d+\.?\d*)\s*[-~]\s*(\d+\.?\d*)",
        // "UDS 1" or "DS 1" near a depth — Indonesian format
        r"(?mi)\b(UDS|DS)\s*\d*\s*[^\n]*?(\d+\.?\d*)\s*(?:m|M)\b",
        // "SPT/U/D at 3.50m" in tables
        r"(?mi)\b(SPT|[DUBW])\b[^\n]*?(\d+\.?\d*)\s*m",
        // "3.50  D  Sample" (table format)
        r"(?m)^\s*(\d+\.?\d*)\s{2,}([DUBW])\b",
    ];

    for (pi, pat) in patterns.iter().enumerate() {
        if let Some(re) = cached_regex(pat) {
            for caps in re.captures_iter(t) {
                let (depth_top, depth_base, stype) = match pi {
                    1 => {
                        let top: f64 = match caps[2].parse() { Ok(v) => v, Err(_) => continue };
                        let base: f64 = match caps[3].parse() { Ok(v) => v, Err(_) => continue };
                        (top, Some(base), caps[1].to_string())
                    },
                    2 => {
                        // UDS/DS near depth
                        let top: f64 = match caps[2].parse() { Ok(v) => v, Err(_) => continue };
                        let st = if caps[1].contains("UDS") { "U" } else { "D" };
                        (top, None, st.to_string())
                    },
                    4 => {
                        let top: f64 = match caps[1].parse() { Ok(v) => v, Err(_) => continue };
                        (top, None, caps[2].to_string())
                    },
                    3 => {
                        let top: f64 = match caps[2].parse() { Ok(v) => v, Err(_) => continue };
                        (top, None, caps[1].to_string())
                    },
                    _ => {
                        let top: f64 = match caps[1].parse() { Ok(v) => v, Err(_) => continue };
                        (top, None, "D".to_string())
                    },
                };
                if depth_top < 0.0 || depth_top > 200.0 { continue; }
                if samples.iter().any(|s| (s.depth_top - depth_top).abs() < 0.01) { continue; }
                samples.push(Sample {
                    depth_top, depth_base, sample_type: stype,
                    sample_id: None, confidence: 0.75,
                });
            }
        }
        if !samples.is_empty() { break; }
    }
    samples.sort_by(|a, b| a.depth_top.partial_cmp(&b.depth_top).unwrap_or(std::cmp::Ordering::Equal));
    samples
}

// ── SPT Results ──────────────────────────────────────────────

fn extract_spts(t: &str) -> Vec<SptResult> {
    let mut spts: Vec<SptResult> = Vec::new();

    let patterns = [
        // "SPT 1. (1.55 - 2.00) (2,3,3) N:6" — Indonesian borehole log format
        r"(?mi)SPT\s*\d*\.?\s*\((\d+\.?\d*)\s*[-~]\s*\d+\.?\d*\)\s*\((\d+)\s*,\s*(\d+)\s*,\s*(\d+(?:/\d+)?)\)\s*N\s*[=:>]*\s*(\d+)",
        // "SPT at 3.50m: N=15" / "SPT 3.50m N = 15"
        r"(?mi)SPT\s*(?:at\s*)?(\d+\.?\d*)\s*m?[^\n]*?N\s*[=:]\s*(\d+)",
        // "N=15 at 3.50m" (reversed order)
        r"(?mi)N\s*[=:]\s*(\d+)[^\n]*?(?:at\s*)?(\d+\.?\d*)\s*m",
        // Seating/main: "3.50m  3/4/5  N=12"
        r"(?mi)(\d+\.?\d*)\s*m?\s+(\d+/\d+/\d+(?:/\d+)*)\s+(?:N\s*[=:]\s*)?(\d+)",
        // Table format: "N1  N2  N3  Ntotal" where Ntotal is sum of last two
        // Common in Indonesian logs: "1  1  1  2" or "5  7  7  14"
        r"(?m)^\s*(\d{1,2})\s+(\d{1,2})\s+(\d{1,2})\s+(\d{1,3})\s*$",
    ];

    for (pi, pat) in patterns.iter().enumerate() {
        if let Some(re) = cached_regex(pat) {
            for caps in re.captures_iter(t) {
                let (depth, n_val, seating, main_drive) = match pi {
                    0 => {
                        // Indonesian format: SPT X. (depth_top - depth_base) (n1,n2,n3) N:value
                        let d: f64 = match caps[1].parse() { Ok(v) => v, Err(_) => continue };
                        let nv: u32 = match caps[5].parse() { Ok(v) => v, Err(_) => continue };
                        let n1 = caps[2].to_string();
                        let seat = Some(n1);
                        let main = Some(format!("{},{}", &caps[3], &caps[4]));
                        (d, Some(nv), seat, main)
                    },
                    2 => {
                        let nv: u32 = match caps[1].parse() { Ok(v) => v, Err(_) => continue };
                        let d: f64 = match caps[2].parse() { Ok(v) => v, Err(_) => continue };
                        (d, Some(nv), None, None)
                    },
                    3 => {
                        let d: f64 = match caps[1].parse() { Ok(v) => v, Err(_) => continue };
                        let blows = caps[2].to_string();
                        let nv: u32 = match caps[3].parse() { Ok(v) => v, Err(_) => continue };
                        let parts: Vec<&str> = blows.split('/').collect();
                        let seat = if parts.len() >= 2 { Some(parts[..parts.len()/2].join("/")) } else { None };
                        let main = if parts.len() >= 2 { Some(parts[parts.len()/2..].join("/")) } else { None };
                        (d, Some(nv), seat, main)
                    },
                    4 => {
                        // Table format: N1 N2 N3 Ntotal — no depth on this line
                        // Skip this pattern in the main loop; it needs post-processing
                        continue;
                    },
                    _ => {
                        let d: f64 = match caps[1].parse() { Ok(v) => v, Err(_) => continue };
                        let nv: u32 = match caps[2].parse() { Ok(v) => v, Err(_) => continue };
                        (d, Some(nv), None, None)
                    },
                };
                if depth < 0.0 || depth > 200.0 { continue; }
                if n_val.map(|n| n > 400).unwrap_or(false) { continue; }
                if spts.iter().any(|s| (s.depth - depth).abs() < 0.01) { continue; }
                spts.push(SptResult {
                    depth, n_value: n_val, seating, main: main_drive,
                    confidence: 0.80,
                });
            }
        }
        if !spts.is_empty() { break; }
    }
    spts.sort_by(|a, b| a.depth.partial_cmp(&b.depth).unwrap_or(std::cmp::Ordering::Equal));
    spts
}

/// Extract a value from header lines like "CLIENT: ACME Corp" or "PROJECT : Site A".
/// Searches the first 30 lines for known keywords.
fn extract_header_field(text: &str, keywords: &[&str]) -> Option<String> {
    // Also check user dictionary metadata_keys
    let dict = crate::models::userdict::get();

    for line in text.lines().take(30) {
        let upper = line.to_uppercase();
        for kw in keywords {
            if upper.contains(kw) {
                // Try "KEYWORD: VALUE" or "KEYWORD = VALUE" patterns
                if let Some(pos) = upper.find(kw) {
                    let rest = &line[pos + kw.len()..];
                    let trimmed = rest.trim_start_matches(|c: char| c == ':' || c == '=' || c == ' ' || c == '\t');
                    let value = trimmed.trim();
                    if value.len() >= 2 && value.len() <= 120 {
                        return Some(value.to_string());
                    }
                }
            }
        }
        // Check user dictionary metadata_keys
        for (dict_key, standard) in &dict.metadata_keys {
            if upper.contains(&dict_key.to_uppercase()) {
                if let Some(pos) = upper.find(&dict_key.to_uppercase()) {
                    let rest = &line[pos + dict_key.len()..];
                    let trimmed = rest.trim_start_matches(|c: char| c == ':' || c == '=' || c == ' ' || c == '\t');
                    let value = trimmed.trim();
                    if value.len() >= 2 && value.len() <= 120 {
                        match standard.as_str() {
                            "project_name" | "client" | "contractor" | "location" => {
                                return Some(value.to_string());
                            }
                            _ => {}
                        }
                    }
                }
            }
        }
    }
    None
}

/// Extract water level from text (e.g., "Water Level: 3.50m" or "GWL = 2.1 m").
fn extract_water_level(text: &str) -> Option<f64> {
    let patterns = [
        r"(?i)(?:water\s*level|gwl|muka\s*air|ketinggian\s*air)[\s:=]+(\d+\.?\d*)\s*m?",
        r"(?i)(?:water\s*table|ground\s*water)[\s:=]+(\d+\.?\d*)\s*m?",
    ];
    for pat in &patterns {
        if let Some(re) = cached_regex(pat) {
            if let Some(caps) = re.captures(text) {
                if let Some(val) = caps.get(1).and_then(|m| m.as_str().parse::<f64>().ok()) {
                    if val >= 0.0 && val < 100.0 {
                        return Some(val);
                    }
                }
            }
        }
    }
    None
}

