use std::path::Path;
use std::fs;
use crate::models::borehole::Borehole;
use crate::models::ags;

/// Escape a value for CSV: wrap in quotes if it contains comma, quote, or newline
fn csv_escape(s: &str) -> String {
    if s.contains(',') || s.contains('"') || s.contains('\n') || s.contains('\r') {
        format!("\"{}\"", s.replace('"', "\"\""))
    } else {
        s.to_string()
    }
}

/// Sanitize hole_id to prevent path traversal attacks.
fn sanitize_hole_id(raw: &str) -> String {
    let safe: String = raw.chars()
        .map(|c| match c {
            '/' | '\\' | ':' | '*' | '?' | '"' | '<' | '>' | '|' => '_',
            _ => c,
        })
        .collect();
    safe.replace("..", "_")
        .trim_matches(|c: char| c == '.' || c == ' ')
        .to_string()
}

pub fn write_outputs(bh: &Borehole, out: &Path, _u: &str, _d: &str) -> Result<(), String> {
    let safe_id = sanitize_hole_id(&bh.hole_id);
    if safe_id.is_empty() {
        return Err("hole_id is empty after sanitization".to_string());
    }
    let dir = out.join(&safe_id);
    log::info!("Writing outputs to: {}", dir.display());
    fs::create_dir_all(&dir).map_err(|e| format!("mkdir {}: {}", dir.display(), e))?;

    // Verify resolved path is under output directory (path traversal guard)
    let resolved = dir.canonicalize().unwrap_or(dir.clone());
    let out_resolved = out.canonicalize().unwrap_or(out.to_path_buf());
    if !resolved.starts_with(&out_resolved) {
        return Err(format!("SECURITY: Path traversal for hole_id '{}'", bh.hole_id));
    }

    // AGS4 output (spec-compliant)
    let ags_content = ags::borehole_to_ags4(bh);
    fs::write(dir.join("output.ags"), &ags_content).map_err(|e| e.to_string())?;

    // ── CSV outputs (template-aware) ─────────────────────────────
    // Uses output template from dictionary if set, else OpenGround defaults.
    let tmpl = crate::models::userdict::get().active_output_template();
    let c = |field: &str, default: &str| -> String {
        tmpl.as_ref().map(|t| t.col(field, default)).unwrap_or_else(|| default.to_string())
    };

    // Location header
    let mut loca_csv = format!("{},{},{},{},{},LOCA_TYPE,LOCA_STAR,LOCA_ENDD,LOCA_CRS\n",
        c("hole_id","LOCA_ID"), c("easting","LOCA_NATE"), c("northing","LOCA_NATN"),
        c("elevation","LOCA_GL"), c("depth","LOCA_FDEP"));
    loca_csv.push_str(&format!("{},{},{},{},{},{},{},{},{}\n",
        csv_escape(&safe_id),
        bh.easting.map(|v| format!("{:.2}", v)).unwrap_or_default(),
        bh.northing.map(|v| format!("{:.2}", v)).unwrap_or_default(),
        bh.elevation.map(|v| format!("{:.2}", v)).unwrap_or_default(),
        bh.final_depth.map(|v| format!("{:.2}", v)).unwrap_or_default(),
        csv_escape(bh.method.as_deref().unwrap_or("")),
        csv_escape(bh.date_start.as_deref().unwrap_or("")),
        csv_escape(bh.date_end.as_deref().unwrap_or("")),
        csv_escape(bh.crs.as_deref().unwrap_or("")),
    ));
    fs::write(dir.join("loca.csv"), loca_csv).map_err(|e| e.to_string())?;

    // Geology (GEOL group equivalent)
    let mut geol_csv = format!("{},{},{},{},{},GEOL_CONF\n",
        c("hole_id","LOCA_ID"), c("geol_top","GEOL_TOP"), c("geol_base","GEOL_BASE"),
        c("geol_desc","GEOL_DESC"), c("geol_leg","GEOL_LEG"));
    for l in &bh.layers {
        geol_csv.push_str(&format!("{},{:.2},{:.2},{},{},{:.2}\n",
            csv_escape(&safe_id), l.top, l.base,
            csv_escape(&l.description),
            csv_escape(l.legend_code.as_deref().unwrap_or("")),
            l.confidence,
        ));
    }
    fs::write(dir.join("geol.csv"), geol_csv).map_err(|e| e.to_string())?;

    // Samples (SAMP group equivalent)
    if !bh.samples.is_empty() {
        let mut samp_csv = format!("{},{},SAMP_BASE,{},SAMP_REF\n",
            c("hole_id","LOCA_ID"), c("samp_top","SAMP_TOP"), c("samp_type","SAMP_TYPE"));
        for s in &bh.samples {
            samp_csv.push_str(&format!("{},{:.2},{},{},{}\n",
                csv_escape(&safe_id), s.depth_top,
                s.depth_base.map(|v| format!("{:.2}", v)).unwrap_or_default(),
                csv_escape(&s.sample_type),
                csv_escape(s.sample_id.as_deref().unwrap_or("")),
            ));
        }
        fs::write(dir.join("samp.csv"), samp_csv).map_err(|e| e.to_string())?;
    }

    // SPT results (ISPT group equivalent)
    if !bh.spts.is_empty() {
        let mut ispt_csv = format!("{},{},{},ISPT_SEAT,ISPT_MAIN\n",
            c("hole_id","LOCA_ID"), c("spt_top","ISPT_TOP"), c("spt_nval","ISPT_NVAL"));
        for t in &bh.spts {
            ispt_csv.push_str(&format!("{},{:.2},{},{},{}\n",
                csv_escape(&safe_id), t.depth,
                t.n_value.map(|v| v.to_string()).unwrap_or_default(),
                csv_escape(t.seating.as_deref().unwrap_or("")),
                csv_escape(t.main.as_deref().unwrap_or("")),
            ));
        }
        fs::write(dir.join("ispt.csv"), ispt_csv).map_err(|e| e.to_string())?;
    }

    // Manifest
    // ── Completeness report ────────────────────────────────
    let mut missing: Vec<&str> = Vec::new();
    if bh.layers.is_empty() { missing.push("geology layers"); }
    if bh.easting.is_none() || bh.northing.is_none() { missing.push("coordinates"); }
    if bh.elevation.is_none() { missing.push("elevation"); }
    if bh.samples.is_empty() { missing.push("samples"); }
    if bh.spts.is_empty() { missing.push("SPT results"); }
    if bh.date_start.is_none() { missing.push("start date"); }
    if bh.method.is_none() { missing.push("drilling method"); }
    if bh.project_name.is_none() { missing.push("project name"); }
    let completeness = if missing.is_empty() { "COMPLETE".to_string() }
        else { format!("PARTIAL — missing: {}", missing.join(", ")) };
    if !missing.is_empty() {
        log::warn!("{}: {}", safe_id, completeness);
    }

    let mf = serde_json::json!({
        "hole_id": safe_id,
        "quality_score": bh.quality_score,
        "completeness": completeness,
        "missing_fields": missing,
        "layers": bh.layers.len(),
        "samples": bh.samples.len(),
        "spts": bh.spts.len(),
        "outputs": {
            "ags4": "output.ags",
            "csv_loca": "loca.csv",
            "csv_geol": "geol.csv",
            "csv_samp": if bh.samples.is_empty() { serde_json::Value::Null } else { serde_json::Value::String("samp.csv".into()) },
            "csv_ispt": if bh.spts.is_empty() { serde_json::Value::Null } else { serde_json::Value::String("ispt.csv".into()) },
        }
    });
    fs::write(dir.join("manifest.json"),
        serde_json::to_string_pretty(&mf).unwrap_or_default())
        .map_err(|e| e.to_string())?;

    // ── Provenance / audit trail ─────────────────────────────
    let provenance = serde_json::json!({
        "source_file": bh.hole_id,
        "extraction_timestamp": chrono::Utc::now().to_rfc3339(),
        "app_version": "2.0.0-R27",
        "quality_score": bh.quality_score,
        "layers_extracted": bh.layers.len(),
        "samples_extracted": bh.samples.len(),
        "spts_extracted": bh.spts.len(),
        "avg_confidence": if bh.layers.is_empty() { 0.0 } else {
            bh.layers.iter().map(|l| l.confidence).sum::<f64>() / bh.layers.len() as f64
        },
        "has_coordinates": bh.easting.is_some() && bh.northing.is_some(),
        "project_name": bh.project_name,
        "client": bh.client,
        "contractor": bh.contractor,
        "water_level": bh.water_level,
        "dictionary_version": chrono::Utc::now().format("%Y-%m-%d").to_string(),
    });
    fs::write(dir.join("provenance.json"),
        serde_json::to_string_pretty(&provenance).unwrap_or_default())
        .map_err(|e| e.to_string())?;

    // OpenGround CSV mapping file
    if let Err(e) = write_openground_mapping(bh, out) {
        log::warn!("Could not write OpenGround mapping: {}", e);
    }

    // DIGGS XML output (US market)
    let diggs_content = crate::models::diggs::borehole_to_diggs(bh);
    fs::write(dir.join("output.diggs.xml"), &diggs_content).map_err(|e| e.to_string())?;

    // ── AGS4 validation ──────────────────────────────────────
    let ags_content = fs::read_to_string(dir.join("output.ags")).unwrap_or_default();
    let validation = super::ags_validator::validate_ags4(&ags_content);
    if !validation.valid {
        for e in &validation.errors {
            log::warn!("AGS4 validation error: {}", e);
        }
    }
    for w in &validation.warnings {
        log::info!("AGS4 validation note: {}", w);
    }

    Ok(())
}

/// Write a combined multi-hole AGS4 file for batch import into OpenGround.
/// Called once after all individual boreholes have been processed.
pub fn write_batch_ags4(boreholes: &[Borehole], out: &Path) -> Result<String, String> {
    if boreholes.is_empty() {
        return Ok("No boreholes to merge".to_string());
    }
    let content = ags::boreholes_to_ags4(boreholes);
    let dest = out.join("project.ags");
    fs::write(&dest, &content).map_err(|e| format!("write project.ags: {}", e))?;
    log::info!("Wrote combined AGS4: {} ({} holes, {} bytes)",
        dest.display(), boreholes.len(), content.len());
    Ok(format!("project.ags: {} holes merged", boreholes.len()))
}

