  </Groups>
</ImportMapping>
"#,
        samp = if bh.samples.is_empty() { String::new() } else { r#"
    <Group name="SAMP" file="samp.csv">
      <Field source="LOCA_ID" target="LOCA_ID" key="true"/>
      <Field source="SAMP_TOP" target="SAMP_TOP" type="number" key="true"/>
      <Field source="SAMP_TYPE" target="SAMP_TYPE"/>
      <Field source="SAMP_REF" target="SAMP_REF"/>
    </Group>"#.to_string() },
