use std::path::{Path, PathBuf};
use std::process::Command;

/// Default Poppler install path (matches 02_prerequisites.py installer).
const DEFAULT_POPPLER_BIN: &str = r"C:\Tools\poppler\bin";

/// Find pdftoppm executable: env var > PATH > hardcoded fallback.
fn pdftoppm_exe() -> String {
    // 1. Check env var override
    if let Ok(p) = std::env::var("BOREHOLEIQ_PDFTOPPM") {
        return p;
    }
    // 2. Check PATH
    if let Ok(output) = Command::new("where").arg("pdftoppm").output() {
        if output.status.success() {
            let found = String::from_utf8_lossy(&output.stdout);
            if let Some(line) = found.lines().next() {
                let trimmed = line.trim();
                if !trimmed.is_empty() {
                    return trimmed.to_string();
                }
            }
        }
    }
    // 3. Hardcoded fallback
    let fallback = format!(r"{}\pdftoppm.exe", DEFAULT_POPPLER_BIN);
    if Path::new(&fallback).exists() {
        return fallback;
    }
    // 4. Last resort: hope it's in PATH
    "pdftoppm".to_string()
}

/// Result of preprocessing — holds page paths and cleans up temp dir on drop.
pub struct PreprocessResult {
    pub pages: Vec<PathBuf>,
    temp_dir: Option<PathBuf>,
}

impl Drop for PreprocessResult {
    fn drop(&mut self) {
        if let Some(ref dir) = self.temp_dir {
            let _ = std::fs::remove_dir_all(dir);
        }
    }
}

pub fn preprocess(input: &Path) -> Result<PreprocessResult, String> {
    let ext = input.extension().and_then(|e| e.to_str()).unwrap_or("").to_lowercase();

    match ext.as_str() {
        "pdf" => {
            let exe = pdftoppm_exe();

            // UUID-isolated temp directory per invocation
            let session_id = uuid::Uuid::new_v4().to_string();
            let tmp = std::env::temp_dir().join(format!("boreholeiq_{}", session_id));
            std::fs::create_dir_all(&tmp).map_err(|e| format!("tmpdir create: {}", e))?;

            let stem = input.file_stem().unwrap_or_default().to_string_lossy();
            let pfx = tmp.join(stem.as_ref());
            let st = Command::new(&exe)
                .args(["-png", "-r", "300"])
                .arg(input)
                .arg(&pfx)
                .status()
                .map_err(|e| format!("pdftoppm failed: {} (path: {})", e, exe))?;
            if !st.success() {
                return Err(format!("pdftoppm exited with error (path: {})", exe));
            }

            let mut pgs: Vec<PathBuf> = std::fs::read_dir(&tmp)
                .map_err(|e| e.to_string())?
                .filter_map(|e| e.ok().map(|e| e.path()))
                .filter(|p| p.extension().and_then(|x| x.to_str()) == Some("png"))
                .collect();
            pgs.sort();
            if pgs.is_empty() { return Err("No pages extracted from PDF".into()); }
            Ok(PreprocessResult { pages: pgs, temp_dir: Some(tmp) })
        }
        "png" | "jpg" | "jpeg" | "tif" | "tiff" | "bmp" | "webp" => {
            Ok(PreprocessResult { pages: vec![input.to_path_buf()], temp_dir: None })
        }
        _ => Err(format!("Unsupported file type: .{}", ext)),
    }
}

