use std::path::Path;
use std::process::Command;

/// Default Tesseract install path (matches 02_prerequisites.py installer).
const DEFAULT_TESS_DIR: &str = r"C:\Program Files\Tesseract-OCR";

fn tesseract_exe() -> String {
    std::env::var("BOREHOLEIQ_TESSERACT")
        .unwrap_or_else(|_| format!(r"{}\tesseract.exe", DEFAULT_TESS_DIR))
}

fn tessdata_dir() -> String {
    std::env::var("BOREHOLEIQ_TESSDATA")
        .unwrap_or_else(|_| format!(r"{}\tessdata", DEFAULT_TESS_DIR))
}

/// Run Tesseract CLI on a single page image and return the extracted text.
/// Uses: tesseract.exe <image> stdout -l <lang> --tessdata-dir <dir>
pub fn ocr_page(img: &Path, lang: &str) -> Result<String, String> {
    let exe = tesseract_exe();
    let td = tessdata_dir();

    let img_str = img.to_str().unwrap_or_default();

    let output = Command::new(&exe)
        .args([
            img_str,
            "stdout",           // output to stdout instead of file
            "-l", lang,
            "--tessdata-dir", &td,
        ])
        .output()
        .map_err(|e| format!("Failed to run tesseract: {} (path: {})", e, exe))?;

    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        return Err(format!("Tesseract failed (exit {}): {}", output.status, stderr));
    }

    String::from_utf8(output.stdout)
        .map_err(|e| format!("Tesseract output not valid UTF-8: {}", e))
}

/// Try extracting text directly from a born-digital PDF using pdftotext (Poppler).
/// Returns Some(text) if meaningful text was found, None otherwise.
pub fn try_pdf_text_layer(pdf_path: &std::path::Path) -> Option<String> {
    // Find pdftotext next to pdftoppm (same Poppler install)
    let pdftotext = if let Ok(p) = std::env::var("BOREHOLEIQ_PDFTOTEXT") {
        p
    } else {
        // Check common locations
        let candidates = [
            r"C:\Tools\poppler\bin\pdftotext.exe",
        ];
        match candidates.iter().find(|p| std::path::Path::new(p).exists()) {
            Some(p) => p.to_string(),
            None => {
                // Try PATH
                if let Ok(output) = std::process::Command::new("where").arg("pdftotext").output() {
                    if output.status.success() {
                        let found = String::from_utf8_lossy(&output.stdout);
                        if let Some(line) = found.lines().next() {
                            line.trim().to_string()
                        } else {
                            return None;
                        }
                    } else {
                        return None;
                    }
                } else {
                    return None;
                }
            }
        }
    };

    let output = std::process::Command::new(&pdftotext)
        .args(["-layout", "-enc", "UTF-8"])
        .arg(pdf_path)
        .arg("-") // stdout
        .output()
        .ok()?;

    if !output.status.success() {
        return None;
    }

    let text = String::from_utf8_lossy(&output.stdout).to_string();

    // Heuristic: if text has fewer than 50 non-whitespace chars, it's probably
    // a scanned PDF with no real text layer — fall through to OCR
    let meaningful_chars = text.chars().filter(|c| !c.is_whitespace()).count();
    if meaningful_chars < 50 {
        return None;
    }

    Some(text)
}

/// Auto-detect the dominant language of extracted text.
/// Returns a Tesseract language code (e.g., "eng", "ind", "tha").
pub fn detect_language(text: &str) -> Option<String> {
    if text.len() < 50 { return None; }
    let info = whatlang::detect(text)?;
    let code = match info.lang() {
        whatlang::Lang::Eng => "eng",
        whatlang::Lang::Ind => "ind",
        // Note: Malay (msa) not available in whatlang — uses Ind for Indonesian/Malay family
        whatlang::Lang::Tha => "tha",
        whatlang::Lang::Vie => "vie",
        whatlang::Lang::Jpn => "jpn",
        whatlang::Lang::Kor => "kor",
        whatlang::Lang::Cmn => "chi_sim",
        whatlang::Lang::Hin => "hin",
        whatlang::Lang::Ara => "ara",
        whatlang::Lang::Fra => "fra",
        whatlang::Lang::Deu => "deu",
        whatlang::Lang::Spa => "spa",
        whatlang::Lang::Por => "por",
        whatlang::Lang::Ita => "ita",
        whatlang::Lang::Nld => "nld",
        whatlang::Lang::Rus => "rus",
        whatlang::Lang::Ben => "ben",
        whatlang::Lang::Tam => "tam",
        whatlang::Lang::Jav => "jav",
        _ => return None,
    };
    log::info!("Auto-detected language: {} (confidence: {:.2})", code, info.confidence());
    if info.confidence() > 0.5 { Some(code.to_string()) } else { None }
}

