use crate::models::borehole::Borehole;

pub fn validate_and_repair(bh: &mut Borehole) -> Vec<String> {
    let mut warnings = Vec::new();

    // ── Sort layers by depth ────────────────────────────────
    bh.layers.sort_by(|a, b| a.top.partial_cmp(&b.top).unwrap_or(std::cmp::Ordering::Equal));

    // ── Remove duplicate layers (same top+base within 0.01m) ──
    let before_dedup = bh.layers.len();
    bh.layers.dedup_by(|a, b| {
        (a.top - b.top).abs() < 0.01 && (a.base - b.base).abs() < 0.01
    });
    if bh.layers.len() < before_dedup {
        warnings.push(format!("Removed {} duplicate layer(s)", before_dedup - bh.layers.len()));
    }

    // ── Fix depth inversions ────────────────────────────────
    for i in 1..bh.layers.len() {
        if bh.layers[i].top < bh.layers[i - 1].base {
            warnings.push(format!(
                "Layer {}: top {:.2}m < prev base {:.2}m (corrected)",
                i, bh.layers[i].top, bh.layers[i - 1].base
            ));
            bh.layers[i].top = bh.layers[i - 1].base;
        }
    }

    // ── Remove zero-thickness layers ────────────────────────
    let before = bh.layers.len();
    bh.layers.retain(|l| (l.base - l.top).abs() > 0.001);
    if bh.layers.len() < before {
        warnings.push(format!("Removed {} zero-thickness layer(s)", before - bh.layers.len()));
    }

    // ── Validate reasonable depth ranges ─────────────────────
    for l in &bh.layers {
        if l.base > 150.0 {
            warnings.push(format!("Deep layer {:.2}-{:.2}m (>150m) — verify", l.top, l.base));
        }
    }

    // ── Verify samples fall within geology ───────────────────
    if !bh.layers.is_empty() {
        let max_depth = bh.layers.last().map(|l| l.base).unwrap_or(0.0);
        for s in &bh.samples {
            if s.depth_top > max_depth + 1.0 {
                warnings.push(format!(
                    "Sample at {:.2}m beyond max geology depth {:.2}m",
                    s.depth_top, max_depth
                ));
            }
        }
        for s in &bh.spts {
            if s.depth > max_depth + 1.0 {
                warnings.push(format!(
                    "SPT at {:.2}m beyond max geology depth {:.2}m",
                    s.depth, max_depth
                ));
            }
        }
    }

    // ── Low confidence warnings ──────────────────────────────
    for l in &bh.layers {
        if l.confidence < 0.60 {
            warnings.push(format!(
                "Low confidence geology {:.2}-{:.2}m: {:.0}%", l.top, l.base, l.confidence * 100.0
            ));
        }
    }
    for s in &bh.spts {
        if s.confidence < 0.60 {
            warnings.push(format!(
                "Low confidence SPT at {:.2}m: {:.0}%", s.depth, s.confidence * 100.0
            ));
        }
    }

    // ── Update final depth ──────────────────────────────────
    bh.final_depth = bh.layers.last().map(|l| l.base);

    // ── Coordinate validation ────────────────────────────────
    if let (Some(e), Some(n)) = (bh.easting, bh.northing) {
        // UTM range check
        if e >= 100_000.0 && e <= 999_999.0 && n >= 0.0 && n <= 10_000_000.0 {
            // Valid UTM — infer zone if not set
            if bh.crs.is_none() {
                // Southern hemisphere if northing < 10M (using false northing)
                let hemisphere = if n < 5_000_000.0 { "S" } else { "N" };
                // Cannot determine zone from coords alone, but tag as UTM
                bh.crs = Some(format!("UTM {}", hemisphere));
            }
        } else if e.abs() <= 180.0 && n.abs() <= 90.0 {
            // Likely lat/lon
            if bh.crs.is_none() {
                bh.crs = Some("WGS84".to_string());
            }
        } else if n >= 100_000.0 && n <= 999_999.0 && e >= 0.0 && e <= 10_000_000.0 {
            // Easting/Northing appear swapped
            warnings.push(format!(
                "Coordinates may be swapped: E={:.2} N={:.2} — northing looks like easting",
                e, n
            ));
            let tmp = bh.easting;
            bh.easting = bh.northing;
            bh.northing = tmp;
            warnings.push("Auto-swapped easting/northing".to_string());
        } else {
            warnings.push(format!("Unusual coordinates: E={:.2} N={:.2} — verify CRS", e, n));
        }
    }

    // ── Empty data warnings ──────────────────────────────────
    if bh.layers.is_empty() {
        warnings.push("No geology layers extracted — check OCR quality".into());
    }
    if bh.samples.is_empty() {
        warnings.push("No samples extracted".into());
    }

    // ── Depth calibration validation ─────────────────────────
    // Cross-check: does the maximum extracted layer depth match the
    // header's total depth? A mismatch indicates depth calibration error
    // (the most dangerous failure mode per enterprise research).
    if let Some(header_depth) = bh.final_depth {
        let max_extracted = bh.layers.last().map(|l| l.base).unwrap_or(0.0);
        if max_extracted > 0.0 && header_depth > 0.0 {
            let diff = (max_extracted - header_depth).abs();
            if diff > 1.0 {
                warnings.push(format!(
                    "DEPTH CALIBRATION WARNING: extracted max depth {:.2}m vs header total depth {:.2}m (diff {:.2}m). Verify depth assignments.",
                    max_extracted, header_depth, diff
                ));
            } else if diff > 0.5 {
                warnings.push(format!(
                    "Depth note: extracted max {:.2}m vs header {:.2}m (diff {:.2}m — within tolerance)",
                    max_extracted, header_depth, diff
                ));
            }
        }
    }

    // ── Depth continuity check ──────────────────────────────
    // Verify no gaps > 2m between consecutive layers (suggests missing data)
    for i in 1..bh.layers.len() {
        let gap = bh.layers[i].top - bh.layers[i-1].base;
        if gap > 2.0 {
            warnings.push(format!(
                "Gap in geology: {:.2}m to {:.2}m ({:.2}m missing) — possible extraction gap",
                bh.layers[i-1].base, bh.layers[i].top, gap
            ));
        }
    }

    // ── Compute quality score (0-100) ───────────────────────
    let mut score: f64 = 0.0;
    // Layer count (max 30 pts: 3 pts per layer up to 10)
    score += (bh.layers.len().min(10) as f64) * 3.0;
    // Average confidence (max 30 pts)
    if !bh.layers.is_empty() {
        let avg_conf = bh.layers.iter().map(|l| l.confidence).sum::<f64>() / bh.layers.len() as f64;
        score += avg_conf * 30.0;
    }
    // Has coordinates (10 pts)
    if bh.easting.is_some() && bh.northing.is_some() { score += 10.0; }
    // Has elevation (5 pts)
    if bh.elevation.is_some() { score += 5.0; }
    // Has SPTs (10 pts)
    if !bh.spts.is_empty() { score += 10.0; }
    // Has samples (5 pts)
    if !bh.samples.is_empty() { score += 5.0; }
    // Has dates (5 pts)
    if bh.date_start.is_some() { score += 3.0; }
    if bh.date_end.is_some() { score += 2.0; }
    // Penalty for warnings (minus 2 per warning, min 0)
    score = (score - warnings.len() as f64 * 2.0).max(0.0);
    bh.quality_score = Some(score.min(100.0) as u8);
    log::info!("Quality score: {}/100 ({} layers, {} warnings)", 
        bh.quality_score.unwrap_or(0), bh.layers.len(), warnings.len());

    warnings
}

