use crate::models::borehole::*;
use std::time::Duration;

const OLLAMA_URL: &str = "http://127.0.0.1:11434/api/generate";
const DEFAULT_MODEL: &str = "phi3:mini";
const DEFAULT_TIMEOUT_SECS: u64 = 600;
const DEFAULT_CONTEXT_CHARS: usize = 6000;

/// Runtime AI configuration loaded from %LOCALAPPDATA%/BoreholeIQ/ai_config.json
struct AiConfig {
    model: String,
    timeout_secs: u64,
    context_chars: usize,
}

fn load_ai_config() -> AiConfig {
    let base_dir = std::env::var_os("LOCALAPPDATA")
        .map(|d| std::path::PathBuf::from(d).join("BoreholeIQ"))
        .unwrap_or_else(|| std::path::PathBuf::from("."));

    // Try ai_config.json first (user override)
    if let Ok(content) = std::fs::read_to_string(base_dir.join("ai_config.json")) {
        if let Ok(v) = serde_json::from_str::<serde_json::Value>(&content) {
            return AiConfig {
                model: v["model"].as_str().unwrap_or(DEFAULT_MODEL).to_string(),
                timeout_secs: v["timeout_secs"].as_u64().unwrap_or(DEFAULT_TIMEOUT_SECS),
                context_chars: v["context_chars"].as_u64().unwrap_or(DEFAULT_CONTEXT_CHARS as u64) as usize,
            };
        }
    }

    // Fallback: read model from hw_profile.json (written by deploy script)
    let mut model = DEFAULT_MODEL.to_string();
    if let Ok(content) = std::fs::read_to_string(base_dir.join("hw_profile.json")) {
        if let Ok(v) = serde_json::from_str::<serde_json::Value>(&content) {
            if let Some(m) = v["model"].as_str() {
                if !m.is_empty() {
                    model = m.to_string();
                    log::info!("AI model from hw_profile.json: {}", model);
                }
            }
        }
    }

    AiConfig {
        model,
        timeout_secs: DEFAULT_TIMEOUT_SECS,
        context_chars: DEFAULT_CONTEXT_CHARS,
    }
}

/// Check if Ollama is running and the model is available.
/// Also checks if the machine has enough power for useful LLM inference.
pub async fn is_available() -> bool {
    // Quick check: if ai_config says tier 1 (regex-only), skip LLM entirely
    let cfg = load_ai_config();
    if cfg.model.is_empty() || cfg.model == "none" {
        return false;
    }

    let model = cfg.model.clone();
    // Use blocking HTTP to avoid async runtime conflicts with Tauri
    match tokio::task::spawn_blocking(move || {
        let client = reqwest::blocking::Client::builder()
            .timeout(Duration::from_secs(3))
            .no_proxy()
            .build().ok()?;
        let resp = client.get("http://127.0.0.1:11434/api/tags").send().ok()?;
        if !resp.status().is_success() { return None; }
        let text = resp.text().ok()?;
        let model_base = model.split(':').next().unwrap_or(&model);
        if text.contains(model_base) { Some(true) } else { None }
    }).await {
        Ok(Some(true)) => true,
        _ => false,
    }
}

/// Extract borehole data from OCR text using the local LLM.
/// Returns a Borehole struct or an error string.
pub async fn extract_with_llm(ocr_text: &str, file_name: &str) -> Result<Borehole, String> {
    let cfg = load_ai_config();

    // Pre-flight: ensure Ollama is running before we try to call it
    if !is_available().await {
        // Try to start it
        if crate::pipeline::ollama::is_installed() {
            let _ = crate::pipeline::ollama::start();
            // Give it a moment
            tokio::time::sleep(Duration::from_secs(3)).await;
            if !is_available().await {
                return Err("Ollama not responding after restart attempt".to_string());
            }
        } else {
            return Err("Ollama not installed".to_string());
        }
    }
    let max_chars = cfg.context_chars;

    // Truncate OCR text to fit model context (tier-dependent)
    let text_raw = if ocr_text.len() > max_chars {
        ocr_text[..max_chars].to_string()
    } else {
        ocr_text.to_string()
    };
    // Escape chars that would break the JSON prompt structure
    let text_escaped = text_raw
        .replace('\\', "\\\\")
        .replace('"', "'")
        .replace('\n', " ")
        .replace('\r', "")
        .replace('\t', " ");

    let prompt = format!(r#"You are a geotechnical data extractor. Extract ALL data from this borehole log OCR text into JSON.

RULES:
- Return ONLY valid JSON, no explanation, no markdown backticks
- Use null for missing values
- Legend codes must be English: CLAY, SAND, SILT, GRAVEL, PEAT, FILL, etc
- Translate Indonesian soil names: LEMPUNG=CLAY, PASIR=SAND, LANAU=SILT, GAMBUT=PEAT, KERIKIL=GRAVEL
- depth values in meters as numbers

JSON SCHEMA:
{{"hole_id":"string","easting":number|null,"northing":number|null,"elevation":number|null,"date_start":"string"|null,"date_end":"string"|null,"method":"string"|null,"layers":[{{"top":0.0,"base":1.5,"description":"string","legend":"string|null"}}],"samples":[{{"depth_top":0.0,"depth_base":null,"type":"D","id":null}}],"spts":[{{"depth":0.0,"n_value":6,"seating":"2","main":"3,3"}}]}}

OCR TEXT:
{}"#, text_escaped);

    // Augment prompt with few-shot examples from past successful extractions
    let examples = load_examples(3);
    let final_prompt = if examples.is_empty() {
        prompt.clone()
    } else {
        let ex_text: String = examples.iter().enumerate().map(|(i, ex)| {
            format!("\nPAST EXAMPLE {}:\n{}\n", i + 1, &ex[..ex.len().min(500)])
        }).collect();
        format!("{}\n\nHere are examples of previous successful extractions:\n{}", prompt, ex_text)
    };

    let body = serde_json::json!({
        "model": cfg.model,
        "prompt": final_prompt,
        "stream": false,
        "options": {
            "temperature": 0.1,
            "num_predict": 4096
        }
    });

    // Use blocking HTTP in a spawn_blocking task to avoid async runtime conflicts
    let timeout_secs = cfg.timeout_secs;
    let resp_json: serde_json::Value = tokio::task::spawn_blocking(move || {
        let client = reqwest::blocking::Client::builder()
            .timeout(Duration::from_secs(timeout_secs))
            .no_proxy()
            .build()
            .map_err(|e| format!("HTTP client: {}", e))?;

        let resp = client.post(OLLAMA_URL)
            .json(&body)
            .send()
            .map_err(|e| format!("Ollama request failed: {}", e))?;

        if !resp.status().is_success() {
            return Err(format!("Ollama returned status {}", resp.status()));
        }

        resp.json::<serde_json::Value>()
            .map_err(|e| format!("Ollama response parse: {}", e))
    }).await.map_err(|e| format!("Task join error: {}", e))??;

    let response_text = resp_json["response"].as_str()
        .ok_or("No response field from Ollama")?;

    // Clean response: strip markdown fences if present
    let cleaned = response_text
        .trim()
        .strip_prefix("```json").unwrap_or(response_text.trim())
        .strip_prefix("```").unwrap_or(response_text.trim())
        .strip_suffix("```").unwrap_or(response_text.trim())
        .trim();

    parse_llm_json(cleaned, file_name)
}

/// Parse the LLM JSON response into a Borehole struct.
fn parse_llm_json(json_str: &str, fallback_name: &str) -> Result<Borehole, String> {
    let v: serde_json::Value = serde_json::from_str(json_str)
        .map_err(|e| format!("LLM returned invalid JSON: {} — raw: {}", e, &json_str[..json_str.len().min(200)]))?;

    let hole_id = v["hole_id"].as_str().unwrap_or(fallback_name).to_string();
    let mut bh = Borehole::new(hole_id);

    bh.easting = v["easting"].as_f64();
    bh.northing = v["northing"].as_f64();
    bh.elevation = v["elevation"].as_f64();
    bh.date_start = v["date_start"].as_str().map(|s| s.to_string());
    bh.date_end = v["date_end"].as_str().map(|s| s.to_string());
    bh.method = v["method"].as_str().map(|s| s.to_string());

    // Layers
    if let Some(layers) = v["layers"].as_array() {
        for l in layers {
            let top = match l["top"].as_f64() { Some(v) => v, None => continue };
            let base = match l["base"].as_f64() { Some(v) => v, None => continue };
            if base <= top { continue; }
            bh.layers.push(GeologyLayer {
                top,
                base,
                description: l["description"].as_str().unwrap_or("").to_string(),
                legend_code: l["legend"].as_str().map(|s| s.to_string()),
                confidence: 0.90,
            });
        }
    }

    // Samples
    if let Some(samples) = v["samples"].as_array() {
        for s in samples {
            let depth_top = match s["depth_top"].as_f64() { Some(v) => v, None => continue };
            bh.samples.push(Sample {
                depth_top,
                depth_base: s["depth_base"].as_f64(),
                sample_type: s["type"].as_str().unwrap_or("D").to_string(),
                sample_id: s["id"].as_str().map(|s| s.to_string()),
                confidence: 0.90,
            });
        }
    }

    // SPTs
    if let Some(spts) = v["spts"].as_array() {
        for s in spts {
            let depth = match s["depth"].as_f64() { Some(v) => v, None => continue };
            bh.spts.push(SptResult {
                depth,
                n_value: s["n_value"].as_u64().map(|n| n as u32),
                seating: s["seating"].as_str().map(|s| s.to_string()),
                main: s["main"].as_str().map(|s| s.to_string()),
                confidence: 0.90,
            });
        }
    }

    bh.final_depth = bh.layers.last().map(|l| l.base);
    Ok(bh)
}

// ── Few-Shot Learning: Save and Load Examples ────────────────

fn examples_dir() -> std::path::PathBuf {
    let base = if let Some(d) = std::env::var_os("LOCALAPPDATA") {
        std::path::PathBuf::from(d).join("BoreholeIQ")
    } else {
        std::path::PathBuf::from(".")
    };
    base.join("examples")
}

/// Save a successful extraction as a few-shot example for future LLM calls.
pub fn save_example(ocr_text: &str, borehole: &Borehole) {
    let dir = examples_dir();
    if std::fs::create_dir_all(&dir).is_err() { return; }

    // Use first 200 chars of OCR as context snippet
    let snippet: String = ocr_text.chars().take(200).collect();
    let example = serde_json::json!({
        "ocr_snippet": snippet,
        "output": borehole,
        "timestamp": chrono_now(),
    });
    // Filename: timestamp-based to allow sorting by recency
    let fname = format!("{}.json", std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|d| d.as_secs()).unwrap_or(0));
    let _ = std::fs::write(dir.join(fname),
        serde_json::to_string_pretty(&example).unwrap_or_default());

    // Keep only the 20 most recent examples (prune old ones)
    if let Ok(entries) = std::fs::read_dir(&dir) {
        let mut files: Vec<_> = entries.filter_map(|e| e.ok())
            .filter(|e| e.path().extension().map(|x| x == "json").unwrap_or(false))
            .collect();
        files.sort_by_key(|e| std::cmp::Reverse(e.path()));
        for old in files.iter().skip(20) {
            let _ = std::fs::remove_file(old.path());
        }
    }
}

/// Load the N most recent examples as few-shot context for the LLM prompt.
pub fn load_examples(n: usize) -> Vec<String> {
    let dir = examples_dir();
    let mut files: Vec<_> = match std::fs::read_dir(&dir) {
        Ok(entries) => entries.filter_map(|e| e.ok())
            .filter(|e| e.path().extension().map(|x| x == "json").unwrap_or(false))
            .collect(),
        Err(_) => return vec![],
    };
    files.sort_by_key(|e| std::cmp::Reverse(e.path()));
    files.iter().take(n).filter_map(|e| std::fs::read_to_string(e.path()).ok()).collect()
}

fn chrono_now() -> String {
    // Simple timestamp without chrono crate
    let d = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default();
    format!("{}", d.as_secs())
}

