static RE_DDMMYYYY: Lazy<Regex> = Lazy::new(|| Regex::new(r"^(\d{1,2})[/\-\.](\d{1,2})[/\-\.](\d{4})$").unwrap());
static RE_DD_MONTH: Lazy<Regex> = Lazy::new(|| Regex::new(r"(?i)(\d{1,2})\s+(\w+)\s+(\d{4})").unwrap());
/// Multilingual geotechnical soil/rock dictionary.
/// Returns (AGS4 legend code, English description) for any recognized term.
/// Covers: English, Indonesian, Malay, Japanese, Korean, Thai, Vietnamese, Filipino.

/// Lookup a soil/rock description and return (legend_code, english_name).
/// Input is case-insensitive for Latin scripts; CJK is exact match.
pub fn lookup_legend(desc: &str) -> Option<(&'static str, &'static str)> {
    let upper = desc.to_uppercase();
    // Check longest matches first (compound terms before simple)
    for &(term, legend, eng) in TERMS.iter() {
        if upper.contains(term) {
            return Some((legend, eng));
        }
    }
    None
}

/// Normalize a date string to ISO yyyy-mm-dd format.
/// Handles: "16 Juli 2025", "19 Juni 2025", "3/7/2025", "2025-07-16", "5 7月 2025"
pub fn normalize_date(raw: &str) -> String {
    let s = raw.trim();
    // Already ISO?
    if let Some(caps) = RE_ISO.captures(s) {
        return format!("{}-{:02}-{:02}",
            &caps[1], caps[2].parse::<u32>().unwrap_or(1), caps[3].parse::<u32>().unwrap_or(1));
    }
    // dd/mm/yyyy or dd-mm-yyyy
    if let Some(caps) = RE_DDMMYYYY.captures(s) {
        let d: u32 = caps[1].parse().unwrap_or(1);
        let m: u32 = caps[2].parse().unwrap_or(1);
        let y: u32 = caps[3].parse().unwrap_or(2025);
        // Heuristic: if first number > 12, it's dd/mm/yyyy; else ambiguous, assume dd/mm/yyyy
        return format!("{}-{:02}-{:02}", y, m.min(12), d.min(31));
    }
    // mm/dd/yyyy (US style — if month <= 12 and day > 12)
    if let Some(caps) = regex::Regex::new(r"^(\d{1,2})/(\d{1,2})/(\d{4})$").ok().and_then(|re| re.captures(s)) {
        let a: u32 = caps[1].parse().unwrap_or(1);
        let b: u32 = caps[2].parse().unwrap_or(1);
        let y: u32 = caps[3].parse().unwrap_or(2025);
        if a <= 12 && b > 12 { return format!("{}-{:02}-{:02}", y, a, b); }
    }
    // "dd Month yyyy" — multilingual month names
    if let Some(caps) = RE_DD_MONTH.captures(s) {
        let d: u32 = caps[1].parse().unwrap_or(1);
        let y: u32 = caps[3].parse().unwrap_or(2025);
        if let Some(m) = month_to_num(&caps[2]) {
            return format!("{}-{:02}-{:02}", y, m, d.min(31));
        }
    }
    // "yyyy年mm月dd日" (Japanese)
    if let Some(caps) = regex::Regex::new(r"(\d{4})年(\d{1,2})月(\d{1,2})日").ok().and_then(|re| re.captures(s)) {
        return format!("{}-{:02}-{:02}",
            &caps[1], caps[2].parse::<u32>().unwrap_or(1), caps[3].parse::<u32>().unwrap_or(1));
    }
    // Couldn't parse — return raw trimmed
    s.to_string()
}

fn month_to_num(m: &str) -> Option<u32> {
    let ml = m.to_lowercase();
    match ml.as_str() {
        // English
        "january" | "jan" => Some(1), "february" | "feb" => Some(2),
        "march" | "mar" => Some(3), "april" | "apr" => Some(4),
        "may" => Some(5), "june" | "jun" => Some(6),
        "july" | "jul" => Some(7), "august" | "aug" => Some(8),
        "september" | "sep" | "sept" => Some(9), "october" | "oct" => Some(10),
        "november" | "nov" => Some(11), "december" | "dec" => Some(12),
        // Indonesian / Malay (only unique spellings — shared ones like "april" handled above)
        "januari" => Some(1), "februari" => Some(2), "maret" => Some(3),
        "mei" => Some(5), "juni" => Some(6),
        "juli" => Some(7), "agustus" => Some(8),
        "oktober" => Some(10), "desember" => Some(12),
        // Vietnamese
        "th\u{00e1}ng 1" | "th\u{00e1}ng 01" => Some(1),
        // Thai (transliterated)
        "makarakom" => Some(1), "kumphaphan" => Some(2), "minakhom" => Some(3),
        "mesayon" => Some(4), "phritsaphakhom" => Some(5), "mithunayon" => Some(6),
        "karakadakhom" => Some(7), "singhakhom" => Some(8), "kanyayon" => Some(9),
        "tulakhom" => Some(10), "phritsachikayon" => Some(11), "thanwakhom" => Some(12),
        // Korean (transliterated)
        "1\u{c6d4}" => Some(1), "2\u{c6d4}" => Some(2), "3\u{c6d4}" => Some(3),
        "4\u{c6d4}" => Some(4), "5\u{c6d4}" => Some(5), "6\u{c6d4}" => Some(6),
        "7\u{c6d4}" => Some(7), "8\u{c6d4}" => Some(8), "9\u{c6d4}" => Some(9),
        "10\u{c6d4}" => Some(10), "11\u{c6d4}" => Some(11), "12\u{c6d4}" => Some(12),
        _ => None,
    }
}

