/// User-managed dictionary system.
/// Reads JSON files from %LOCALAPPDATA%/BoreholeIQ/dictionary/
/// User terms override hardcoded geoterms. Files are optional —
/// missing files are silently ignored (app falls back to hardcoded).
///
/// Dictionary files:
///   terms.json        — Soil/rock terms → English legend (e.g., "TANAH KERAS": "HARD CLAY")
///   ocr_fixes.json    — OCR error corrections (e.g., "CLAV": "CLAY")
///   legends.json      — USCS/local codes → AGS4 legend (e.g., "CL": "CLAY")
///   defaults.json     — Project/company defaults (CRS, method, company, etc.)
///   depth_patterns.json — Custom regex patterns for depth extraction
///   hole_id_patterns.json — Custom regex patterns for hole ID extraction
///   metadata_keys.json — Localized header field names for metadata extraction
///   exclude_terms.json — Lines containing these terms are NOT geology descriptions

use std::collections::HashMap;
use std::path::PathBuf;
use std::sync::RwLock;


/// User-defined output format template.
/// Allows users to customize CSV column names for different target systems.
#[derive(Debug, Clone, serde::Serialize, serde::Deserialize)]
pub struct OutputTemplate {
    pub name: String,
    pub description: Option<String>,
    /// Column name for hole ID (default: "LOCA_ID")
    pub col_hole_id: Option<String>,
    /// Geology columns
    pub col_geol_top: Option<String>,
    pub col_geol_base: Option<String>,
    pub col_geol_desc: Option<String>,
    pub col_geol_leg: Option<String>,
    /// Location columns
    pub col_easting: Option<String>,
    pub col_northing: Option<String>,
    pub col_elevation: Option<String>,
    pub col_depth: Option<String>,
    /// SPT columns
    pub col_spt_top: Option<String>,
    pub col_spt_nval: Option<String>,
    /// Sample columns
    pub col_samp_top: Option<String>,
    pub col_samp_type: Option<String>,
    /// CSV delimiter (default: comma)
    pub delimiter: Option<String>,
    /// Whether to include AGS4 output (default: true)
    pub include_ags: Option<bool>,
}

impl OutputTemplate {
    pub fn col(&self, field: &str, default: &str) -> String {
        match field {
            "hole_id" => self.col_hole_id.as_deref().unwrap_or(default).to_string(),
            "geol_top" => self.col_geol_top.as_deref().unwrap_or(default).to_string(),
            "geol_base" => self.col_geol_base.as_deref().unwrap_or(default).to_string(),
            "geol_desc" => self.col_geol_desc.as_deref().unwrap_or(default).to_string(),
            "geol_leg" => self.col_geol_leg.as_deref().unwrap_or(default).to_string(),
            "easting" => self.col_easting.as_deref().unwrap_or(default).to_string(),
            "northing" => self.col_northing.as_deref().unwrap_or(default).to_string(),
            "elevation" => self.col_elevation.as_deref().unwrap_or(default).to_string(),
            "depth" => self.col_depth.as_deref().unwrap_or(default).to_string(),
            "spt_top" => self.col_spt_top.as_deref().unwrap_or(default).to_string(),
            "spt_nval" => self.col_spt_nval.as_deref().unwrap_or(default).to_string(),
            "samp_top" => self.col_samp_top.as_deref().unwrap_or(default).to_string(),
            "samp_type" => self.col_samp_type.as_deref().unwrap_or(default).to_string(),
            _ => default.to_string(),
        }
    }
    pub fn delim(&self) -> &str {
        self.delimiter.as_deref().unwrap_or(",")
    }
}

static DICT: once_cell::sync::Lazy<RwLock<UserDictionary>> =
    once_cell::sync::Lazy::new(|| RwLock::new(UserDictionary::load()));

#[derive(Debug, Clone)]
pub struct UserDictionary {
    pub terms: HashMap<String, String>,
    pub ocr_fixes: HashMap<String, String>,
    pub legends: HashMap<String, String>,
    pub defaults: ProjectDefaults,
    /// Custom depth extraction regex patterns (user adds their own)
    pub depth_patterns: Vec<String>,
    /// Custom hole ID regex patterns
    pub hole_id_patterns: Vec<String>,
    /// Localized metadata field names → standard key
    /// e.g., "LOKASI": "location", "TANGGAL MULAI": "date_start"
    pub metadata_keys: HashMap<String, String>,
    /// Lines containing any of these terms are excluded from geology extraction
    /// e.g., "Operator", "Diperiksa", "Koordinat", "Tanggal"
    pub exclude_terms: Vec<String>,
    pub folder: PathBuf,
}

#[derive(Debug, Clone, Default, serde::Serialize, serde::Deserialize)]
pub struct ProjectDefaults {
    /// AGS output variant: "4.0" (default), "4.1.0_AU", "4_NZ", "3.1"
    pub ags_variant: Option<String>,
    pub crs: Option<String>,
    pub company: Option<String>,
    pub default_method: Option<String>,
    pub date_format: Option<String>,
    pub coordinate_order: Option<String>,
    pub default_units: Option<String>,
    pub project_name: Option<String>,
    pub project_location: Option<String>,
}

impl UserDictionary {
    pub fn load() -> Self {
        let folder = dictionary_folder();
        let terms = load_json_map(&folder.join("terms.json"));
        let ocr_fixes = load_json_map(&folder.join("ocr_fixes.json"));
        let legends = load_json_map(&folder.join("legends.json"));
        let defaults = load_defaults(&folder.join("defaults.json"));
        let depth_patterns = load_json_list(&folder.join("depth_patterns.json"));
        let hole_id_patterns = load_json_list(&folder.join("hole_id_patterns.json"));
        let metadata_keys = load_json_map(&folder.join("metadata_keys.json"));
        let exclude_terms = load_json_list(&folder.join("exclude_terms.json"));

        // Also load any additional dictionary files (geotech_dict_add.json, etc.)
        // These are bulk term additions in the same format as terms.json
        let mut all_terms = terms;
        if let Ok(entries) = std::fs::read_dir(&folder) {
            for entry in entries.filter_map(|e| e.ok()) {
                let path = entry.path();
                let name = path.file_name().unwrap_or_default().to_string_lossy().to_string();
                // Load any file matching *_add.json or *_terms.json or *_dict*.json
                if (name.ends_with("_add.json") || name.contains("_terms") || name.contains("_dict"))
                    && name != "terms.json"
                {
                    let extra = load_json_map(&path);
                    if !extra.is_empty() {
                        log::info!("Loaded {} extra terms from {}", extra.len(), name);
                        all_terms.extend(extra);
                    }
                }
            }
        }

        Self {
            terms: all_terms, ocr_fixes, legends, defaults,
            depth_patterns, hole_id_patterns, metadata_keys, exclude_terms,
            folder,
        }
    }

    /// Apply OCR fixes to raw text before parsing.
    pub fn apply_ocr_fixes(&self, text: &str) -> String {
        if self.ocr_fixes.is_empty() { return text.to_string(); }
        let mut result = text.to_string();
        let mut fixes: Vec<_> = self.ocr_fixes.iter().collect();
        fixes.sort_by(|a, b| b.0.len().cmp(&a.0.len()));
        for (wrong, correct) in fixes {
            let wrong_upper = wrong.to_uppercase();
            let mut i = 0;
            let mut new_result = String::with_capacity(result.len());
            let upper_result = result.to_uppercase();
            while i < result.len() {
                if i + wrong_upper.len() <= upper_result.len()
                    && &upper_result[i..i + wrong_upper.len()] == wrong_upper.as_str()
                {
                    new_result.push_str(correct);
                    i += wrong_upper.len();
                } else {
                    if let Some(ch) = result[i..].chars().next() {
                        new_result.push(ch);
                        i += ch.len_utf8();
                    } else {
                        break;
                    }
                }
            }
            result = new_result;
        }
        result
    }

    /// Check if a line should be excluded from geology extraction.
    pub fn should_exclude_line(&self, line: &str) -> bool {
        if self.exclude_terms.is_empty() { return false; }
        let upper = line.to_uppercase();
        self.exclude_terms.iter().any(|term| upper.contains(term.as_str()))
    }

    /// Look up a user-defined term.
    pub fn lookup_term(&self, desc: &str) -> Option<String> {
        let upper = desc.to_uppercase();
        let mut terms: Vec<_> = self.terms.iter().collect();
        terms.sort_by(|a, b| b.0.len().cmp(&a.0.len()));
        for (key, val) in terms {
            if upper.contains(key.as_str()) {
                return Some(val.clone());
            }
        }
        None
    }

    /// Look up a user-defined legend code mapping.
    pub fn lookup_legend(&self, code: &str) -> Option<String> {
        let upper = code.to_uppercase();
        self.legends.get(&upper).cloned()
    }

    /// Look up a localized metadata key → standard name.
    pub fn lookup_metadata_key(&self, key: &str) -> Option<String> {
        let upper = key.trim().to_uppercase();
        self.metadata_keys.get(&upper).cloned()
    }

    // ── Auto-Learning: Frequency Tracking ─────────────────────────
    /// Record a successful term match for frequency tracking.
    /// Max entries in auto-learning files to prevent unbounded growth.
    const MAX_DICT_ENTRIES: usize = 10_000;

    pub fn record_match(&self, term: &str) {
        let freq_path = self.folder.join("_frequency.json");
        let mut freq: HashMap<String, u64> = match std::fs::read_to_string(&freq_path) {
            Ok(c) => serde_json::from_str(&c).unwrap_or_default(),
            Err(_) => HashMap::new(),
        };
        // Cap at MAX_DICT_ENTRIES: if full, drop the least-frequent entry
        if freq.len() >= Self::MAX_DICT_ENTRIES && !freq.contains_key(&term.to_uppercase()) {
            if let Some(min_key) = freq.iter().min_by_key(|(_, v)| *v).map(|(k, _)| k.clone()) {
                freq.remove(&min_key);
            }
        }
        *freq.entry(term.to_uppercase()).or_insert(0) += 1;
        let _ = std::fs::write(&freq_path, serde_json::to_string_pretty(&freq).unwrap_or_default());
    }

    /// Get terms sorted by frequency (most common first).
    pub fn terms_by_frequency(&self) -> Vec<(String, String)> {
        let freq_path = self.folder.join("_frequency.json");
        let freq: HashMap<String, u64> = match std::fs::read_to_string(&freq_path) {
            Ok(c) => serde_json::from_str(&c).unwrap_or_default(),
            Err(_) => HashMap::new(),
        };
        let mut terms: Vec<_> = self.terms.iter()
            .map(|(k, v)| (k.clone(), v.clone(), freq.get(k).copied().unwrap_or(0)))
            .collect();
        terms.sort_by(|a, b| b.2.cmp(&a.2));
        terms.into_iter().map(|(k, v, _)| (k, v)).collect()
    }

    // ── OCR Feedback Loop ─────────────────────────────────────────
    /// Check if a word is a near-miss for any dictionary term (edit distance 1-2).
    /// Auto-adds to ocr_fixes.json for future correction.
    pub fn check_ocr_near_miss(&self, word: &str) -> Option<String> {
        let upper = word.to_uppercase();
        if upper.len() < 4 { return None; }
        for (term, _) in &self.terms {
            if term == &upper { return None; }
            if Self::edit_distance(&upper, term) <= 2 {
                self.auto_add_ocr_fix(&upper, term);
                return Some(term.clone());
            }
        }
        let soil_terms = [
            "CLAY", "SAND", "SILT", "GRAVEL", "PEAT", "FILL", "TOPSOIL", "ROCK",
            "LEMPUNG", "PASIR", "LANAU", "KERIKIL", "GAMBUT", "TANAH",
            "MUDSTONE", "SANDSTONE", "LIMESTONE",
        ];
        for &soil in &soil_terms {
            if Self::edit_distance(&upper, soil) <= 1 && upper != soil {
                self.auto_add_ocr_fix(&upper, soil);
                return Some(soil.to_string());
            }
        }
        None
    }

    fn auto_add_ocr_fix(&self, wrong: &str, correct: &str) {
        let fixes_path = self.folder.join("ocr_fixes.json");
        let mut fixes: HashMap<String, String> = match std::fs::read_to_string(&fixes_path) {
            Ok(c) => {
                let stripped = strip_comments(&c);
                serde_json::from_str(&stripped).unwrap_or_default()
            }
            Err(_) => HashMap::new(),
        };
        let key = wrong.to_uppercase();
        if !fixes.contains_key(&key) {
            // Cap at MAX_DICT_ENTRIES to prevent unbounded growth
            if fixes.len() >= Self::MAX_DICT_ENTRIES {
                log::warn!("OCR fixes at capacity ({} entries) — skipping new fix", Self::MAX_DICT_ENTRIES);
                return;
            }
            fixes.insert(key.clone(), correct.to_string());
            if let Ok(json) = serde_json::to_string_pretty(&fixes) {
                let _ = std::fs::write(&fixes_path, json);
                log::info!("Auto-added OCR fix: '{}' -> '{}'", key, correct);
            }
        }
    }

    fn edit_distance(a: &str, b: &str) -> usize {
        let a: Vec<char> = a.chars().collect();
        let b: Vec<char> = b.chars().collect();
        let (m, n) = (a.len(), b.len());
        let mut dp = vec![vec![0usize; n + 1]; m + 1];
        for i in 0..=m { dp[i][0] = i; }
        for j in 0..=n { dp[0][j] = j; }
        for i in 1..=m {
            for j in 1..=n {
                let cost = if a[i-1] == b[j-1] { 0 } else { 1 };
                dp[i][j] = (dp[i-1][j] + 1).min(dp[i][j-1] + 1).min(dp[i-1][j-1] + cost);
            }
        }
        dp[m][n]
    }

    // ── Column Header Detection ───────────────────────────────────
    /// Given header text, identify which standard field it maps to.
    pub fn identify_header(&self, text: &str) -> Option<String> {
        let upper = text.trim().to_uppercase();
        if let Some(standard) = self.metadata_keys.get(&upper) {
            return Some(standard.clone());
        }
        for (key, standard) in &self.metadata_keys {
            if upper.contains(key.as_str()) {
                return Some(standard.clone());
            }
        }
        None
    }


    // ── Output Templates ──────────────────────────────────────────
    /// Load output templates from output_templates.json.
    pub fn load_output_templates(&self) -> Vec<OutputTemplate> {
        let path = self.folder.join("output_templates.json");
        match std::fs::read_to_string(&path) {
            Ok(c) => {
                let stripped = strip_comments(&c);
                serde_json::from_str(&stripped).unwrap_or_default()
            }
            Err(_) => Vec::new(),
        }
    }

    /// Get the active output template name from defaults.json.
    pub fn active_template_name(&self) -> Option<String> {
        let val = serde_json::to_value(&self.defaults).ok()?;
        val.get("output_template")?.as_str().map(|s| s.to_string())
    }

    /// Get the active output template, or None for built-in defaults.
    pub fn active_output_template(&self) -> Option<OutputTemplate> {
        let name = self.active_template_name()?;
        let templates = self.load_output_templates();
        templates.into_iter().find(|t| t.name == name)
    }

    // ── Cross-File Defaults Propagation ───────────────────────────
    /// Auto-fill defaults from a successfully extracted borehole.
    pub fn propagate_defaults(&self, crs: Option<&str>, project: Option<&str>, company: Option<&str>) {
        let defaults_path = self.folder.join("defaults.json");
        let mut defaults: serde_json::Value = match std::fs::read_to_string(&defaults_path) {
            Ok(c) => {
                let stripped = strip_comments(&c);
                serde_json::from_str(&stripped).unwrap_or(serde_json::json!({}))
            }
            Err(_) => serde_json::json!({}),
        };
        let mut changed = false;
        if let Some(c) = crs {
            if defaults.get("crs").and_then(|v| v.as_str()).map_or(true, |v| v.is_empty()) {
                defaults["crs"] = serde_json::Value::String(c.to_string());
                changed = true;
            }
        }
        if let Some(p) = project {
            if defaults.get("project_name").and_then(|v| v.as_str()).map_or(true, |v| v.is_empty()) {
                defaults["project_name"] = serde_json::Value::String(p.to_string());
                changed = true;
            }
        }
        if let Some(co) = company {
            if defaults.get("company").and_then(|v| v.as_str()).map_or(true, |v| v.is_empty()) {
                defaults["company"] = serde_json::Value::String(co.to_string());
                changed = true;
            }
        }
        if changed {
            if let Ok(json) = serde_json::to_string_pretty(&defaults) {
                let _ = std::fs::write(&defaults_path, json);
                log::info!("Auto-propagated project defaults");
            }
        }
    }

}

pub fn get() -> std::sync::RwLockReadGuard<'static, UserDictionary> {
    DICT.read().unwrap_or_else(|e| e.into_inner())
}

pub fn reload() -> Result<usize, String> {
    let new_dict = UserDictionary::load();
    let count = new_dict.terms.len() + new_dict.ocr_fixes.len()
        + new_dict.legends.len() + new_dict.depth_patterns.len()
        + new_dict.metadata_keys.len() + new_dict.exclude_terms.len();
    let mut w = DICT.write().unwrap_or_else(|e| e.into_inner());
    *w = new_dict;
    Ok(count)
}

pub fn dictionary_folder() -> PathBuf {
    if let Some(d) = std::env::var_os("LOCALAPPDATA") {
        PathBuf::from(d).join("BoreholeIQ").join("dictionary")
    } else {
        PathBuf::from(".").join("dictionary")
    }
}

pub fn ensure_folder() {
    let dir = dictionary_folder();
    if std::fs::create_dir_all(&dir).is_err() { return; }
    let examples = [
        ("terms.json", EXAMPLE_TERMS),
        ("ocr_fixes.json", EXAMPLE_OCR_FIXES),
        ("legends.json", EXAMPLE_LEGENDS),
        ("defaults.json", EXAMPLE_DEFAULTS),
        ("depth_patterns.json", EXAMPLE_DEPTH_PATTERNS),
        ("hole_id_patterns.json", EXAMPLE_HOLE_ID_PATTERNS),
        ("metadata_keys.json", EXAMPLE_METADATA_KEYS),
        ("exclude_terms.json", EXAMPLE_EXCLUDE_TERMS),
    ];
    for (name, content) in &examples {
        let path = dir.join(name);
        if !path.exists() {
            let _ = std::fs::write(path, content);
        }
    }

    // Always update the README (it may have new content from updates)
    let _ = std::fs::write(dir.join("README.txt"), DICT_README);
}

// ── Internal helpers ──────────────────────────────────────────

const MAX_DICT_FILE_SIZE: u64 = 10 * 1024 * 1024;

fn load_json_map(path: &std::path::Path) -> HashMap<String, String> {
    if let Ok(meta) = std::fs::metadata(path) {
        if meta.len() > MAX_DICT_FILE_SIZE { return HashMap::new(); }
    }
    let content = match std::fs::read_to_string(path) {
        Ok(c) => c,
        Err(_) => return HashMap::new(),
    };
    let stripped = strip_comments(&content);
    let map: HashMap<String, String> = match serde_json::from_str(&stripped) {
        Ok(m) => m,
        Err(_) => return HashMap::new(),
    };
    map.into_iter()
        .map(|(k, v)| (k.trim().to_uppercase(), v.trim().to_string()))
        .filter(|(k, v)| !k.is_empty() && !v.is_empty())
        .collect()
}

fn load_json_list(path: &std::path::Path) -> Vec<String> {
    if let Ok(meta) = std::fs::metadata(path) {
        if meta.len() > MAX_DICT_FILE_SIZE { return Vec::new(); }
    }
    let content = match std::fs::read_to_string(path) {
        Ok(c) => c,
        Err(_) => return Vec::new(),
    };
    let stripped = strip_comments(&content);
    let list: Vec<String> = match serde_json::from_str(&stripped) {
        Ok(l) => l,
        Err(_) => return Vec::new(),
    };
    list.into_iter()
        .map(|s| s.trim().to_uppercase())
        .filter(|s| !s.is_empty())
        .collect()
}

fn load_defaults(path: &std::path::Path) -> ProjectDefaults {
    if let Ok(meta) = std::fs::metadata(path) {
        if meta.len() > MAX_DICT_FILE_SIZE { return ProjectDefaults::default(); }
    }
    let content = match std::fs::read_to_string(path) {
        Ok(c) => c,
        Err(_) => return ProjectDefaults::default(),
    };
    let stripped = strip_comments(&content);
    let v: serde_json::Value = match serde_json::from_str(&stripped) {
        Ok(v) => v,
        Err(_) => return ProjectDefaults::default(),
    };
    ProjectDefaults {
        ags_variant: v["ags_variant"].as_str().map(|s| s.to_string()),
        crs: v["crs"].as_str().map(|s| s.to_string()),
        company: v["company"].as_str().map(|s| s.to_string()),
        default_method: v["default_method"].as_str().map(|s| s.to_string()),
        date_format: v["date_format"].as_str().map(|s| s.to_string()),
        coordinate_order: v["coordinate_order"].as_str().map(|s| s.to_string()),
        default_units: v["default_units"].as_str().map(|s| s.to_string()),
        project_name: v["project_name"].as_str().map(|s| s.to_string()),
        project_location: v["project_location"].as_str().map(|s| s.to_string()),
    }
}

/// Strip // comments from JSON content (allows user annotations).
fn strip_comments(content: &str) -> String {
    content.lines()
        .map(|line| {
            if let Some(idx) = line.find("//") {
                let before = &line[..idx];
                if before.matches('"').count() % 2 == 0 { before } else { line }
            } else { line }
        })
        .collect::<Vec<_>>().join("\n")
}

