use std::process::{Command, Child};
use std::sync::Mutex;
use std::time::Duration;
use once_cell::sync::Lazy;

/// Manages the Ollama process lifecycle.
/// Starts headlessly, health-checks, and shuts down on app exit.

static OLLAMA_PROCESS: Lazy<Mutex<Option<Child>>> = Lazy::new(|| Mutex::new(None));

/// Find the Ollama executable path.
fn ollama_exe() -> Option<String> {
    // 1. Check env var
    if let Ok(p) = std::env::var("BOREHOLEIQ_OLLAMA") {
        if std::path::Path::new(&p).exists() { return Some(p); }
    }
    // 2. Check common install locations
    let candidates = [
        std::env::var("LOCALAPPDATA").ok().map(|d| format!(r"{}\Programs\Ollama\ollama.exe", d)),
        Some(r"C:\Program Files\Ollama\ollama.exe".to_string()),
        std::env::var("USERPROFILE").ok().map(|d| format!(r"{}\AppData\Local\Programs\Ollama\ollama.exe", d)),
    ];
    for c in &candidates {
        if let Some(ref path) = c {
            if std::path::Path::new(path).exists() {
                return Some(path.clone());
            }
        }
    }
    // 3. Check PATH via `where`
    if let Ok(output) = Command::new("where").arg("ollama").output() {
        if output.status.success() {
            let found = String::from_utf8_lossy(&output.stdout);
            if let Some(line) = found.lines().next() {
                let trimmed = line.trim();
                if !trimmed.is_empty() {
                    return Some(trimmed.to_string());
                }
            }
        }
    }
    None
}

/// Start Ollama in headless serve mode (no GUI window).
/// Safe to call multiple times — only starts if not already running.
pub fn start() -> Result<(), String> {
    // Step 1: Kill the Ollama tray/GUI app if it's running.
    // "ollama app.exe" is the Electron tray wrapper — NOT the server CLI.
    // We use /T (tree kill) so its child "ollama.exe serve" also dies.
    // This is safe: we immediately start our own headless server after.
    #[cfg(target_os = "windows")]
    {
        use std::os::windows::process::CommandExt;
        const CREATE_NO_WINDOW: u32 = 0x08000000;
        let kill_result = std::process::Command::new("taskkill")
            .args(&["/F", "/T", "/IM", "ollama app.exe"])
            .creation_flags(CREATE_NO_WINDOW)
            .output();
        if let Ok(ref output) = kill_result {
            if output.status.success() {
                log::info!("Killed Ollama tray app — replacing with headless server");
                // Wait for the port to be released after the tree kill
                for _ in 0..10 {
                    std::thread::sleep(Duration::from_millis(300));
                    if !is_server_running() { break; }
                }
            }
        }
    }

    // Step 2: If a server is STILL running on :11434 after killing the tray app,
    // it's either: (a) our headless server from a previous app launch that didn't
    // shut down cleanly, or (b) an external Ollama instance the user started manually.
    // Either way, it's a working Ollama server — just use it.
    if is_server_running() {
        log::info!("Ollama server already running on :11434 — using existing instance");
        return Ok(());
    }

    // Step 3: No server running — start our own headless "ollama serve".
    let exe = ollama_exe().ok_or("Ollama not found")?;
    log::info!("Starting Ollama headless: {}", exe);

    #[cfg(target_os = "windows")]
    let child = {
        use std::os::windows::process::CommandExt;
        const CREATE_NO_WINDOW: u32 = 0x08000000;
        Command::new(&exe)
            .arg("serve")
            .creation_flags(CREATE_NO_WINDOW)
            .stdout(std::process::Stdio::null())
            .stderr(std::process::Stdio::null())
            .spawn()
            .map_err(|e| format!("Failed to start Ollama: {}", e))?
    };

    #[cfg(not(target_os = "windows"))]
    let child = Command::new(&exe)
        .arg("serve")
        .stdout(std::process::Stdio::null())
        .stderr(std::process::Stdio::null())
        .spawn()
        .map_err(|e| format!("Failed to start Ollama: {}", e))?;

    let pid = child.id();
    *OLLAMA_PROCESS.lock().unwrap() = Some(child);
    log::info!("Ollama started (PID: {})", pid);

    // Step 4: Wait for the server to be ready (up to 10 seconds).
    for attempt in 0..20 {
        std::thread::sleep(Duration::from_millis(500));
        if is_server_running() {
            log::info!("Ollama server ready (took {}ms)", (attempt + 1) * 500);
            return Ok(());
        }
    }

    // Server started but not responding yet — might need more time on slow machines.
    // Don't fail — the pipeline will retry when it actually needs Ollama.
    log::warn!("Ollama started but not yet responding — may need more time");
    Ok(())
}

/// Send a tiny prompt to pre-load the model into RAM.
/// This avoids the 60-90s cold-start penalty on the first real extraction.
pub fn warm_up() {
    let base_dir = std::env::var_os("LOCALAPPDATA")
        .map(|d| std::path::PathBuf::from(d).join("BoreholeIQ"))
        .unwrap_or_else(|| std::path::PathBuf::from("."));

    // Read model name from hw_profile.json
    let model = if let Ok(content) = std::fs::read_to_string(base_dir.join("hw_profile.json")) {
        if let Ok(v) = serde_json::from_str::<serde_json::Value>(&content) {
            v["model"].as_str().unwrap_or("phi3:mini").to_string()
        } else { "phi3:mini".to_string() }
    } else if let Ok(content) = std::fs::read_to_string(base_dir.join("ai_config.json")) {
        if let Ok(v) = serde_json::from_str::<serde_json::Value>(&content) {
            v["model"].as_str().unwrap_or("phi3:mini").to_string()
        } else { "phi3:mini".to_string() }
    } else { "phi3:mini".to_string() };

    if model.is_empty() || model == "none" { return; }

    log::info!("Warming up AI model: {} (this loads the model into RAM)...", model);

    // Spawn a background thread so we don't block the UI
    std::thread::spawn(move || {
        let body = serde_json::json!({
            "model": model,
            "prompt": "hello",
            "stream": false
        });
        // Use a blocking HTTP client (we're in a thread, not async)
        match std::net::TcpStream::connect_timeout(
            &"127.0.0.1:11434".parse().expect("addr"),
            Duration::from_secs(5),
        ) {
            Ok(_) => {
                // Server is up, send the warm-up request
                // Use a simple HTTP POST via reqwest blocking
                let client = reqwest::blocking::Client::builder()
                    .timeout(Duration::from_secs(180))
                    .no_proxy()
                    .build();
                match client {
                    Ok(c) => {
                        match c.post("http://127.0.0.1:11434/api/generate")
                            .json(&body)
                            .send() {
                            Ok(resp) => {
                                if resp.status().is_success() {
                                    log::info!("AI model warm-up complete — ready for extraction");
                                } else {
                                    log::warn!("AI model warm-up got status {}", resp.status());
                                }
                            }
                            Err(e) => log::warn!("AI model warm-up failed: {}", e),
                        }
                    }
                    Err(e) => log::warn!("AI warm-up HTTP client error: {}", e),
                }
            }
            Err(_) => log::warn!("Ollama not responding for warm-up — model will load on first use"),
        }
    });
}

/// Stop the managed Ollama process (only if WE started it).
/// Does NOT kill external Ollama instances the user may have started.
pub fn stop() {
    let mut guard = OLLAMA_PROCESS.lock().unwrap();
    if let Some(ref mut child) = *guard {
        log::info!("Stopping Ollama (PID: {})...", child.id());
        let _ = child.kill();
        let _ = child.wait();
        log::info!("Ollama stopped");
    }
    *guard = None;
}

/// Check if the Ollama HTTP server is responding on localhost:11434.
fn is_server_running() -> bool {
    std::net::TcpStream::connect_timeout(
        &"127.0.0.1:11434".parse().expect("hardcoded address"),
        Duration::from_secs(1),
    ).is_ok()
}

/// Check if Ollama is installed on this machine.
pub fn is_installed() -> bool {
    ollama_exe().is_some()
}

/// Get the path to the Ollama executable (for display).
pub fn exe_path() -> Option<String> {
    ollama_exe()
}

