/// Deterministic error advisor.
/// Pattern-matches on error strings to produce actionable suggestions.
/// No LLM, no network, no async — works on every machine, every tier.

#[derive(Clone, serde::Serialize)]
pub struct Advice {
    pub suggestions: Vec<String>,
    pub explanation: String,
}

/// Analyze an error and return actionable suggestions.
pub fn advise(
    error_msg: &str,
    file_ext: &str,
    extraction_mode: &str,
    ocr_text_len: usize,
    layer_count: usize,
    warnings: &[String],
) -> Advice {
    let err = error_msg.to_lowercase();
    let ext = file_ext.to_lowercase();
    let mut suggestions: Vec<String> = Vec::new();
    let mut explanation = String::new();

    // ── OCR failures ────────────────────────────────────────
    if err.contains("ocr") || err.contains("tesseract") {
        if err.contains("failed after retry") {
            suggestions.push(
                "Tesseract crashed on this page. The scan may be corrupted or an unsupported format. Try converting to PNG first.".into()
            );
        }
        if err.contains("language") || err.contains("traineddata") {
            suggestions.push(
                "Missing OCR language pack. Go to C:\\Program Files\\Tesseract-OCR\\tessdata and check if the required .traineddata file exists. Re-run deploy.bat to download missing packs.".into()
            );
        }
        if ocr_text_len == 0 {
            suggestions.push(
                "OCR produced no text. The file may be a blank page, an image-only PDF with no scannable content, or the wrong file type.".into()
            );
        }
        explanation = "OCR (Optical Character Recognition) converts scanned images to text. These errors usually mean Tesseract could not read the input.".into();
    }

    // ── Preprocessing failures ──────────────────────────────
    if err.contains("pre:") || err.contains("pdftoppm") || err.contains("preprocess") {
        if ext == "pdf" {
            suggestions.push(
                "PDF conversion failed. The file may be password-protected, corrupted, or use an unsupported PDF feature. Try opening it in a PDF viewer and re-saving as a standard PDF.".into()
            );
        } else {
            suggestions.push(
                format!("Image preprocessing failed for .{} file. Ensure the file is not corrupted. Try opening and re-saving it in an image editor.", ext)
            );
        }
        if err.contains("not found") || err.contains("no such file") {
            suggestions.push(
                "Poppler (pdftoppm) not found. Check that C:\\Tools\\poppler\\bin is in your system PATH, or re-run deploy.bat.".into()
            );
        }
        explanation = "Preprocessing converts PDFs to images for OCR. This step requires Poppler to be installed.".into();
    }

    // ── Parse / regex failures ──────────────────────────────
    if err.contains("parse:") || err.contains("pattern") {
        if ocr_text_len < 100 {
            suggestions.push(
                "Very little text was extracted from this document. The scan quality may be too low, or the document may not be a borehole log.".into()
            );
        } else if layer_count == 0 {
            suggestions.push(
                "No geology layers were found. This document may use a non-standard format that the pattern matcher does not recognize. If Ollama is installed, try switching to AUTO or AI ONLY mode.".into()
            );
        }
        explanation = "Pattern matching uses regular expressions to find borehole data in the OCR text. Non-standard log formats may not be recognized.".into();
    }

    // ── LLM / Ollama failures ───────────────────────────────
    if err.contains("ollama") || err.contains("llm") || err.contains("local ai") {
        if err.contains("timeout") {
            suggestions.push(
                "AI extraction timed out. Your machine may not have enough RAM/CPU for this model. Switch to REGEX mode in the header dropdown for instant results.".into()
            );
        }
        if err.contains("request failed") || err.contains("connection") {
            suggestions.push(
                "Cannot connect to Ollama. It may not be running. The app tries to start it automatically, but you can also run 'ollama serve' manually in a terminal.".into()
            );
        }
        if err.contains("invalid json") || err.contains("no response") {
            suggestions.push(
                "The AI model returned unusable output. This happens with smaller models on complex logs. Switch to REGEX mode for reliable results.".into()
            );
        }
        explanation = "Local AI uses Ollama to extract data. If it fails, the app falls back to pattern matching automatically in AUTO mode.".into();
    }

    // ── Write failures ──────────────────────────────────────
    if err.contains("write:") || err.contains("output") || err.contains("permission") {
        suggestions.push(
            "Cannot write output files. Check that the output folder exists, is not read-only, and has enough disk space.".into()
        );
        explanation = "The app writes AGS4, CSV, and JSON files to the output folder you selected.".into();
    }

    // ── File too large ──────────────────────────────────────
    if err.contains("too large") || err.contains("max 500 mb") {
        suggestions.push(
            "This file exceeds the 500 MB safety limit. Split the PDF into smaller parts (e.g., one borehole per file) and process them individually.".into()
        );
        explanation = "Large files can cause out-of-memory crashes. The 500 MB limit protects system stability.".into();
    }

    // ── Cannot read file ────────────────────────────────────
    if err.contains("cannot read file") {
        suggestions.push(
            "The file could not be opened. It may have been moved, deleted, or is locked by another program. Close any other apps using this file and try again.".into()
        );
    }

    // ── Aborted ─────────────────────────────────────────────
    if err.contains("aborted") {
        suggestions.push("Processing was cancelled. Click PROCESS to try again.".into());
        explanation = "You clicked the abort button during processing.".into();
    }

    // ── Validation warnings ─────────────────────────────────
    if !warnings.is_empty() {
        let warn_text: Vec<&str> = warnings.iter()
            .filter(|w| w.contains("missing") || w.contains("invalid") || w.contains("overlap"))
            .map(|w| w.as_str())
            .collect();
        if !warn_text.is_empty() {
            suggestions.push(
                "Some extracted data has validation warnings. Check the output files — the data was saved but may need manual review.".into()
            );
        }
    }

    // ── Fallback ────────────────────────────────────────────
    if suggestions.is_empty() {
        suggestions.push(
            "Check the extraction log for details. If the issue persists, try a different extraction mode (AUTO/AI ONLY/REGEX) or re-scan the document at higher quality.".into()
        );
        explanation = "An unexpected error occurred during processing.".into();
    }

    // Cap at 3 suggestions
    suggestions.truncate(3);

    Advice { suggestions, explanation }
}

