use std::path::Path;
use std::process::Command;
use std::collections::BTreeMap;
use regex::Regex;
use once_cell::sync::Lazy;

/// A word with its bounding box from pdftotext -bbox output.
#[derive(Debug, Clone)]
pub struct BboxWord {
    pub text: String,
    pub x1: f64,
    pub y1: f64,
    pub x2: f64,
    pub y2: f64,
    pub page: usize,
}

/// A detected column in a table.
#[derive(Debug, Clone)]
pub struct TableColumn {
    pub x_center: f64,
    pub x_min: f64,
    pub x_max: f64,
    pub header: Option<String>,
    pub role: ColumnRole,
}

#[derive(Debug, Clone, PartialEq)]
pub enum ColumnRole {
    Depth,
    Description,
    Spt,
    Sample,
    Unknown,
}

/// A row extracted from spatial table analysis.
#[derive(Debug, Clone)]
pub struct SpatialRow {
    pub y_center: f64,
    pub depth_top: Option<f64>,
    pub depth_base: Option<f64>,
    pub description: Option<String>,
    pub spt_n: Option<u32>,
    pub confidence: f64,
}

fn pdftotext_exe() -> String {
    if let Ok(p) = std::env::var("BOREHOLEIQ_PDFTOTEXT") { return p; }
    let fallback = r"C:\Tools\poppler\bin\pdftotext.exe";
    if Path::new(fallback).exists() { return fallback.to_string(); }
    "pdftotext".to_string()
}

/// Extract word bounding boxes from a PDF using pdftotext -bbox-layout.
pub fn extract_bbox(pdf_path: &Path) -> Result<Vec<BboxWord>, String> {
    let exe = pdftotext_exe();
    let output = Command::new(&exe)
        .args(["-bbox-layout", "-enc", "UTF-8"])
        .arg(pdf_path)
        .arg("-")
        .output()
        .map_err(|e| format!("pdftotext -bbox failed: {} (path: {})", e, exe))?;
    if !output.status.success() {
        return Err("pdftotext -bbox exited with error".to_string());
    }
    let text = String::from_utf8_lossy(&output.stdout);
    parse_bbox_xml(&text)
}

fn parse_bbox_xml(html: &str) -> Result<Vec<BboxWord>, String> {
    static RE_WORD: Lazy<Regex> = Lazy::new(|| {
        Regex::new(r#"<word xMin="([^"]+)" yMin="([^"]+)" xMax="([^"]+)" yMax="([^"]+)">([^<]+)</word>"#).unwrap()
    });
    static RE_PAGE: Lazy<Regex> = Lazy::new(|| {
        Regex::new(r#"<page width="[^"]+" height="[^"]+">"#).unwrap()
    });
    let mut words = Vec::new();
    let mut page_num = 0usize;
    for line in html.lines() {
        if RE_PAGE.is_match(line) { page_num += 1; }
        for caps in RE_WORD.captures_iter(line) {
            let x1: f64 = caps[1].parse().unwrap_or(0.0);
            let y1: f64 = caps[2].parse().unwrap_or(0.0);
            let x2: f64 = caps[3].parse().unwrap_or(0.0);
            let y2: f64 = caps[4].parse().unwrap_or(0.0);
            let text = caps[5].trim().to_string();
            if !text.is_empty() {
                words.push(BboxWord { text, x1, y1, x2, y2, page: page_num });
            }
        }
    }
    Ok(words)
}

/// Cluster words into columns by x-coordinate proximity.
pub fn detect_columns(words: &[BboxWord], tolerance: f64) -> Vec<TableColumn> {
    if words.is_empty() { return vec![]; }
    let mut x_centers: Vec<f64> = words.iter().map(|w| (w.x1 + w.x2) / 2.0).collect();
    x_centers.sort_by(|a, b| a.partial_cmp(b).unwrap());
    let mut clusters: Vec<Vec<f64>> = Vec::new();
    for &x in &x_centers {
        if let Some(last) = clusters.last_mut() {
            let mean: f64 = last.iter().sum::<f64>() / last.len() as f64;
            if (x - mean).abs() < tolerance { last.push(x); continue; }
        }
        clusters.push(vec![x]);
    }
    let mut columns: Vec<TableColumn> = clusters.iter()
        .filter(|c| c.len() >= 3)
        .map(|c| {
            let mean = c.iter().sum::<f64>() / c.len() as f64;
            let min = c.iter().cloned().fold(f64::MAX, f64::min);
            let max = c.iter().cloned().fold(f64::MIN, f64::max);
            TableColumn { x_center: mean, x_min: min, x_max: max, header: None, role: ColumnRole::Unknown }
        })
        .collect();
    columns.sort_by(|a, b| a.x_center.partial_cmp(&b.x_center).unwrap());
    identify_column_roles(&mut columns, words);
    columns
}

fn identify_column_roles(columns: &mut [TableColumn], words: &[BboxWord]) {
    let min_y = words.iter().map(|w| w.y1).fold(f64::MAX, f64::min);
    let max_y = words.iter().map(|w| w.y2).fold(f64::MIN, f64::max);
    let header_threshold = min_y + (max_y - min_y) * 0.15;
    let header_words: Vec<&BboxWord> = words.iter().filter(|w| w.y1 < header_threshold).collect();

    let depth_kw = ["DEPTH", "KEDALAMAN", "TOP", "BASE", "METER"];
    let desc_kw = ["DESCRIPTION", "DESKRIPSI", "SOIL", "TANAH", "GEOLOGI", "JENIS"];
    let spt_kw = ["SPT", "N-VALUE", "BLOW", "PUKULAN"];

    for col in columns.iter_mut() {
        let col_headers: Vec<String> = header_words.iter()
            .filter(|w| { let wx = (w.x1 + w.x2) / 2.0; wx >= col.x_min - 20.0 && wx <= col.x_max + 20.0 })
            .map(|w| w.text.to_uppercase())
            .collect();
        let joined = col_headers.join(" ");
        col.header = if joined.is_empty() { None } else { Some(joined.clone()) };
        if depth_kw.iter().any(|k| joined.contains(k)) { col.role = ColumnRole::Depth; }
        else if desc_kw.iter().any(|k| joined.contains(k)) { col.role = ColumnRole::Description; }
        else if spt_kw.iter().any(|k| joined.contains(k)) { col.role = ColumnRole::Spt; }
    }
    // Heuristic fallback
    let has_depth = columns.iter().any(|c| c.role == ColumnRole::Depth);
    if !has_depth && columns.len() >= 2 {
        if let Some(first) = columns.first_mut() { first.role = ColumnRole::Depth; }
        if let Some(widest) = columns.iter_mut()
            .max_by(|a, b| (a.x_max - a.x_min).partial_cmp(&(b.x_max - b.x_min)).unwrap()) {
            if widest.role == ColumnRole::Unknown { widest.role = ColumnRole::Description; }
        }
    }
}

/// Extract rows by grouping words at similar y-coordinates.
pub fn extract_spatial_rows(words: &[BboxWord], columns: &[TableColumn]) -> Vec<SpatialRow> {
    if columns.is_empty() || words.is_empty() { return vec![]; }
    let min_y = words.iter().map(|w| w.y1).fold(f64::MAX, f64::min);
    let max_y = words.iter().map(|w| w.y2).fold(f64::MIN, f64::max);
    let header_threshold = min_y + (max_y - min_y) * 0.15;
    let data_words: Vec<&BboxWord> = words.iter().filter(|w| w.y1 >= header_threshold).collect();

    let mut y_groups: BTreeMap<i64, Vec<&BboxWord>> = BTreeMap::new();
    for w in &data_words {
        let y_key = ((w.y1 + w.y2) / 2.0 * 2.0).round() as i64;
        y_groups.entry(y_key).or_default().push(w);
    }
    let mut merged_rows: Vec<Vec<&BboxWord>> = Vec::new();
    let mut current_row: Vec<&BboxWord> = Vec::new();
    let mut last_y: Option<i64> = None;
    for (y_key, group_words) in &y_groups {
        if let Some(prev_y) = last_y {
            if (y_key - prev_y).abs() > 16 {
                if !current_row.is_empty() { merged_rows.push(std::mem::take(&mut current_row)); }
            }
        }
        current_row.extend(group_words.iter());
        last_y = Some(*y_key);
    }
    if !current_row.is_empty() { merged_rows.push(current_row); }

    let mut rows = Vec::new();
    for row_words in &merged_rows {
        let y_center = row_words.iter().map(|w| (w.y1 + w.y2) / 2.0).sum::<f64>() / row_words.len() as f64;
        let mut depth_top = None; let mut depth_base = None;
        let mut description = None; let mut spt_n = None;
        for col in columns {
            let col_words: Vec<&&BboxWord> = row_words.iter()
                .filter(|w| { let wx = (w.x1 + w.x2) / 2.0; wx >= col.x_min - 10.0 && wx <= col.x_max + 10.0 })
                .collect();
            let text: String = col_words.iter().map(|w| w.text.as_str()).collect::<Vec<_>>().join(" ");
            if text.trim().is_empty() { continue; }
            match col.role {
                ColumnRole::Depth => {
                    let nums: Vec<f64> = text.split_whitespace()
                        .filter_map(|s| s.replace(',', ".").parse::<f64>().ok())
                        .filter(|&n| n >= 0.0 && n < 200.0).collect();
                    if nums.len() >= 2 { depth_top = Some(nums[0]); depth_base = Some(nums[1]); }
                    else if nums.len() == 1 { depth_top = Some(nums[0]); }
                }
                ColumnRole::Description => { description = Some(text.trim().to_string()); }
                ColumnRole::Spt => {
                    spt_n = text.split_whitespace().filter_map(|s| s.parse::<u32>().ok()).filter(|&n| n <= 400).last();
                }
                _ => {}
            }
        }
        if depth_top.is_some() || description.is_some() {
            let conf = if depth_top.is_some() && description.is_some() { 0.90 } else { 0.60 };
            rows.push(SpatialRow {
                y_center, depth_top, depth_base, description, spt_n,
                confidence: conf,
            });
        }
    }
    rows
}

/// High-level: try spatial extraction on a PDF.
pub fn try_spatial_extraction(pdf_path: &Path) -> Option<Vec<SpatialRow>> {
    let words = extract_bbox(pdf_path).ok()?;
    if words.len() < 20 { return None; }
    let columns = detect_columns(&words, 30.0);
    if columns.len() < 2 { return None; }
    let has_depth = columns.iter().any(|c| c.role == ColumnRole::Depth);
    let has_desc = columns.iter().any(|c| c.role == ColumnRole::Description);
    if !has_depth || !has_desc { return None; }
    let rows = extract_spatial_rows(&words, &columns);
    if rows.is_empty() { return None; }
    log::info!("Spatial extraction: {} columns, {} rows", columns.len(), rows.len());
    for col in &columns {
        log::info!("  Column: x={:.0} role={:?} header={:?}", col.x_center, col.role, col.header);
    }
    Some(rows)
}

/// Convert spatial rows into Borehole geology layers.
pub fn spatial_rows_to_layers(rows: &[SpatialRow]) -> Vec<crate::models::borehole::GeologyLayer> {
    let mut layers = Vec::new();
    for (i, row) in rows.iter().enumerate() {
        let depth_top = row.depth_top.unwrap_or(if i > 0 { rows[i-1].depth_base.unwrap_or(0.0) } else { 0.0 });
        let depth_base = row.depth_base.unwrap_or(depth_top + 1.0);
        let desc = row.description.clone().unwrap_or_default();
        if desc.is_empty() && row.depth_top.is_none() { continue; }
        layers.push(crate::models::borehole::GeologyLayer {
            top: depth_top, base: depth_base,
            description: desc.clone(),
            legend_code: crate::models::geoterms::lookup_legend(&desc).map(|(code, _)| code.to_string()),
            confidence: row.confidence,
        });
    }
    layers
}

