/// AGS4 self-validation: checks the generated AGS4 content for structural
/// correctness before writing to disk. Catches issues that would cause
/// OpenGround's import validator to reject the file.

pub struct AgsValidationResult {
    pub valid: bool,
    pub errors: Vec<String>,
    pub warnings: Vec<String>,
}

/// Validate AGS4 content string. Returns errors (blocking) and warnings (informational).
pub fn validate_ags4(content: &str) -> AgsValidationResult {
    let mut errors = Vec::new();
    let mut warnings = Vec::new();

    let lines: Vec<&str> = content.lines().collect();
    if lines.is_empty() {
        errors.push("AGS4 content is empty".into());
        return AgsValidationResult { valid: false, errors, warnings };
    }

    let mut current_group: Option<String> = None;
    let mut has_heading = false;
    let mut has_unit = false;
    let mut has_type = false;
    let mut has_data = false;
    let mut groups_found: Vec<String> = Vec::new();
    let mut heading_count = 0usize;

    for (i, line) in lines.iter().enumerate() {
        let line = line.trim();
        if line.is_empty() { continue; }

        // Parse the first field
        let fields: Vec<&str> = line.split(',')
            .map(|f| f.trim().trim_matches('"'))
            .collect();
        if fields.is_empty() { continue; }

        match fields[0] {
            "GROUP" => {
                // Validate previous group was complete
                if let Some(ref grp) = current_group {
                    if !has_heading { errors.push(format!("Group {} missing HEADING row", grp)); }
                    if !has_unit { warnings.push(format!("Group {} missing UNIT row", grp)); }
                    if !has_type { warnings.push(format!("Group {} missing TYPE row", grp)); }
                    if !has_data { warnings.push(format!("Group {} has no DATA rows", grp)); }
                }
                current_group = fields.get(1).map(|s| s.to_string());
                if let Some(ref g) = current_group { groups_found.push(g.clone()); }
                has_heading = false; has_unit = false; has_type = false; has_data = false;
            }
            "HEADING" => {
                has_heading = true;
                heading_count = fields.len() - 1; // Exclude the "HEADING" field itself
            }
            "UNIT" => {
                has_unit = true;
                if fields.len() - 1 != heading_count && heading_count > 0 {
                    errors.push(format!("Line {}: UNIT field count ({}) != HEADING count ({})",
                        i+1, fields.len()-1, heading_count));
                }
            }
            "TYPE" => {
                has_type = true;
                if fields.len() - 1 != heading_count && heading_count > 0 {
                    errors.push(format!("Line {}: TYPE field count ({}) != HEADING count ({})",
                        i+1, fields.len()-1, heading_count));
                }
            }
            "DATA" => {
                has_data = true;
                if fields.len() - 1 != heading_count && heading_count > 0 {
                    warnings.push(format!("Line {}: DATA field count ({}) != HEADING count ({})",
                        i+1, fields.len()-1, heading_count));
                }
            }
            _ => {
                warnings.push(format!("Line {}: Unknown row type '{}'", i+1, fields[0]));
            }
        }
    }

    // Validate final group
    if let Some(ref grp) = current_group {
        if !has_heading { errors.push(format!("Group {} missing HEADING row", grp)); }
        if !has_data { warnings.push(format!("Group {} has no DATA rows", grp)); }
    }

    // Check required groups
    let required = ["PROJ", "LOCA", "GEOL"];
    for req in &required {
        if !groups_found.iter().any(|g| g == req) {
            warnings.push(format!("Recommended group {} not found", req));
        }
    }

    // Check LOCA_ID cross-references
    let mut loca_ids: Vec<String> = Vec::new();
    let mut in_loca = false;
    for line in &lines {
        let fields: Vec<&str> = line.split(',').map(|f| f.trim().trim_matches('"')).collect();
        if fields.first() == Some(&"GROUP") && fields.get(1) == Some(&"LOCA") { in_loca = true; continue; }
        if fields.first() == Some(&"GROUP") { in_loca = false; continue; }
        if in_loca && fields.first() == Some(&"DATA") {
            if let Some(id) = fields.get(1) {
                if !id.is_empty() { loca_ids.push(id.to_string()); }
            }
        }
    }

    // Check GEOL references valid LOCA_IDs
    let mut in_geol = false;
    for line in &lines {
        let fields: Vec<&str> = line.split(',').map(|f| f.trim().trim_matches('"')).collect();
        if fields.first() == Some(&"GROUP") && fields.get(1) == Some(&"GEOL") { in_geol = true; continue; }
        if fields.first() == Some(&"GROUP") { in_geol = false; continue; }
        if in_geol && fields.first() == Some(&"DATA") {
            if let Some(id) = fields.get(1) {
                if !id.is_empty() && !loca_ids.contains(&id.to_string()) {
                    errors.push(format!("GEOL references unknown LOCA_ID '{}'", id));
                }
            }
        }
    }

    let valid = errors.is_empty();
    AgsValidationResult { valid, errors, warnings }
}

