/// XLSX input: parse borehole data from Excel spreadsheets.
/// Uses calamine crate for native .xlsx/.xls reading without external dependencies.

use calamine::{Reader, open_workbook, Xlsx, DataType};
use std::path::Path;
use crate::models::borehole::*;

/// Try to parse a borehole from an Excel file.
/// Looks for columns with names matching known geotechnical headers.
pub fn try_parse_xlsx(path: &Path) -> Result<Borehole, String> {
    let mut workbook: Xlsx<_> = open_workbook(path)
        .map_err(|e| format!("Cannot open Excel file: {}", e))?;

    let sheet_name = workbook.sheet_names().first()
        .ok_or("No sheets in workbook")?.clone();
    let range = workbook.worksheet_range(&sheet_name)
        .map_err(|e| format!("Cannot read sheet '{}': {}", sheet_name, e))?;

    let mut rows_iter = range.rows();
    let header_row = rows_iter.next().ok_or("Empty sheet")?;
    let headers: Vec<String> = header_row.iter()
        .map(|c| c.to_string().trim().to_uppercase())
        .collect();

    // Map column indices to known fields
    let col_idx = |names: &[&str]| -> Option<usize> {
        for name in names {
            if let Some(i) = headers.iter().position(|h| h.contains(name)) {
                return Some(i);
            }
        }
        None
    };

    let hole_col = col_idx(&["HOLE", "LOCA_ID", "BH_ID", "BOREHOLE", "ID"]);
    let top_col = col_idx(&["TOP", "DEPTH_FROM", "GEOL_TOP", "FROM", "KEDALAMAN"]);
    let base_col = col_idx(&["BASE", "DEPTH_TO", "GEOL_BASE", "TO", "BOTTOM"]);
    let desc_col = col_idx(&["DESC", "DESCRIPTION", "GEOL_DESC", "SOIL", "DESKRIPSI", "TANAH"]);
    let leg_col = col_idx(&["LEG", "LEGEND", "GEOL_LEG", "USCS", "CODE"]);
    let spt_col = col_idx(&["SPT", "N_VALUE", "ISPT_NVAL", "N-VALUE", "NVAL"]);
    let east_col = col_idx(&["EAST", "LOCA_NATE", "EASTING", "X"]);
    let north_col = col_idx(&["NORTH", "LOCA_NATN", "NORTHING", "Y"]);
    let elev_col = col_idx(&["ELEV", "LOCA_GL", "GL", "RL", "Z"]);

    if top_col.is_none() || desc_col.is_none() {
        return Err("Cannot find depth (TOP) and description (DESC) columns".into());
    }

    let mut hole_id = path.file_stem().unwrap_or_default().to_string_lossy().to_string();
    let mut layers = Vec::new();
    let mut spts = Vec::new();
    let mut easting = None;
    let mut northing = None;
    let mut elevation = None;

    for row in rows_iter {
        // Helper: get cell as string
        let cell_str = |idx: Option<usize>| -> String {
            idx.and_then(|i| row.get(i))
                .map(|c| c.to_string().trim().to_string())
                .unwrap_or_default()
        };
        // Helper: get cell as f64 using DataType trait
        let cell_num = |idx: Option<usize>| -> Option<f64> {
            idx.and_then(|i| row.get(i)).and_then(|c| {
                // Try get_float first, then get_int, then parse string
                c.get_float()
                    .or_else(|| c.get_int().map(|i| i as f64))
                    .or_else(|| c.as_string().and_then(|s| s.trim().replace(',', ".").parse().ok()))
            })
        };

        // Extract hole ID from first data row
        if let Some(hc) = hole_col {
            let hid = cell_str(Some(hc));
            if !hid.is_empty() && hole_id == path.file_stem().unwrap_or_default().to_string_lossy().as_ref() {
                hole_id = hid;
            }
        }

        // Extract coordinates from first row that has them
        if easting.is_none() { easting = cell_num(east_col); }
        if northing.is_none() { northing = cell_num(north_col); }
        if elevation.is_none() { elevation = cell_num(elev_col); }

        // Extract geology layer
        let top = cell_num(top_col);
        let base = cell_num(base_col);
        let desc = cell_str(desc_col);
        if let Some(t) = top {
            if !desc.is_empty() {
                let b = base.unwrap_or(t + 1.0);
                let leg_str = cell_str(leg_col);
                let leg = if leg_str.is_empty() { None } else { Some(leg_str) };
                layers.push(GeologyLayer {
                    top: t, base: b, description: desc, legend_code: leg, confidence: 0.95,
                });
            }
        }

        // Extract SPT if column exists
        if let Some(n) = cell_num(spt_col) {
            if let Some(t) = top {
                if n >= 0.0 && n <= 400.0 {
                    spts.push(SptResult {
                        depth: t, n_value: Some(n as u32), confidence: 0.95, ..Default::default()
                    });
                }
            }
        }
    }

    if layers.is_empty() {
        return Err("No geology layers found in spreadsheet".into());
    }

    let final_depth = layers.iter().map(|l| l.base).fold(0.0f64, f64::max);

    Ok(Borehole {
        hole_id, layers, spts, easting, northing, elevation,
        final_depth: Some(final_depth),
        samples: vec![], date_start: None, date_end: None,
        method: None, crs: None,
        project_name: None, client: None, contractor: None,
        location_desc: None, water_level: None, quality_score: None,
    })
}

