/// AGS4 reader: parse an existing AGS4 file into Borehole structs.
/// Enables round-trip editing: load bad AGS → fix in app → re-export clean AGS.

use std::path::Path;
use crate::models::borehole::*;

pub fn parse_ags4_file(path: &Path) -> Result<Vec<Borehole>, String> {
    let content = std::fs::read_to_string(path)
        .map_err(|e| format!("Cannot read AGS file: {}", e))?;
    parse_ags4(&content)
}

pub fn parse_ags4(content: &str) -> Result<Vec<Borehole>, String> {
    let mut holes: std::collections::HashMap<String, Borehole> = std::collections::HashMap::new();
    let mut current_group = String::new();
    let mut headings: Vec<String> = Vec::new();

    for line in content.lines() {
        let line = line.trim();
        if line.is_empty() { continue; }
        let fields: Vec<String> = line.split(',')
            .map(|f| f.trim().trim_matches('"').to_string())
            .collect();
        if fields.is_empty() { continue; }

        match fields[0].as_str() {
            "GROUP" => {
                current_group = fields.get(1).cloned().unwrap_or_default();
                headings.clear();
            }
            "HEADING" => {
                headings = fields[1..].to_vec();
            }
            "DATA" => {
                let data = &fields[1..];
                let get = |name: &str| -> Option<String> {
                    headings.iter().position(|h| h == name)
                        .and_then(|i| data.get(i))
                        .map(|s| s.to_string())
                        .filter(|s| !s.is_empty())
                };
                let get_f64 = |name: &str| -> Option<f64> {
                    get(name).and_then(|s| s.replace(',', ".").parse().ok())
                };

                match current_group.as_str() {
                    "LOCA" => {
                        if let Some(id) = get("LOCA_ID") {
                            let bh = holes.entry(id.clone()).or_insert_with(|| Borehole::new(id.clone()));
                            bh.easting = get_f64("LOCA_NATE").or(bh.easting);
                            bh.northing = get_f64("LOCA_NATN").or(bh.northing);
                            bh.elevation = get_f64("LOCA_GL").or(bh.elevation);
                            bh.final_depth = get_f64("LOCA_FDEP").or(bh.final_depth);
                            bh.date_start = get("LOCA_STAR").or(bh.date_start.clone());
                            bh.date_end = get("LOCA_ENDD").or(bh.date_end.clone());
                        }
                    }
                    "GEOL" => {
                        if let Some(id) = get("LOCA_ID") {
                            let bh = holes.entry(id.clone()).or_insert_with(|| Borehole::new(id));
                            if let (Some(top), Some(base)) = (get_f64("GEOL_TOP"), get_f64("GEOL_BASE")) {
                                bh.layers.push(GeologyLayer {
                                    top, base,
                                    description: get("GEOL_DESC").unwrap_or_default(),
                                    legend_code: get("GEOL_LEG"),
                                    confidence: 1.0,
                                });
                            }
                        }
                    }
                    "SAMP" => {
                        if let Some(id) = get("LOCA_ID") {
                            let bh = holes.entry(id.clone()).or_insert_with(|| Borehole::new(id));
                            if let Some(top) = get_f64("SAMP_TOP") {
                                bh.samples.push(Sample {
                                    depth_top: top,
                                    depth_base: get_f64("SAMP_BASE"),
                                    sample_type: get("SAMP_TYPE").unwrap_or_default(),
                                    sample_id: get("SAMP_REF"),
                                    confidence: 1.0,
                                });
                            }
                        }
                    }
                    "ISPT" => {
                        if let Some(id) = get("LOCA_ID") {
                            let bh = holes.entry(id.clone()).or_insert_with(|| Borehole::new(id));
                            if let Some(top) = get_f64("ISPT_TOP") {
                                bh.spts.push(SptResult {
                                    depth: top,
                                    n_value: get_f64("ISPT_NVAL").map(|v| v as u32),
                                    seating: get("ISPT_SEAT"),
                                    main: get("ISPT_MAIN"),
                                    confidence: 1.0,
                                });
                            }
                        }
                    }
                    _ => {} // Skip other groups
                }
            }
            _ => {} // UNIT, TYPE rows — skip
        }
    }

    let mut result: Vec<Borehole> = holes.into_values().collect();
    result.sort_by(|a, b| a.hole_id.cmp(&b.hole_id));
    if result.is_empty() {
        return Err("No LOCA records found in AGS file".into());
    }
    Ok(result)
}

