/// DIGGS (Data Interchange for Geotechnical and Geoenvironmental Specialists)
/// XML output format. ASCE standard gaining adoption in the US market.
/// Generates DIGGS 2.5.x compatible XML from a Borehole struct.

use crate::models::borehole::*;

pub fn borehole_to_diggs(bh: &Borehole) -> String {
    let mut xml = String::new();
    xml.push_str(r#"<?xml version="1.0" encoding="UTF-8"?>
<Diggs xmlns="http://diggsml.org/schema/2.5.a"
       xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance"
       xmlns:gml="http://www.opengis.net/gml/3.2">
"#);

    // Project
    xml.push_str(&format!(r#"  <project>
    <name>BoreholeIQ Export</name>
    <description>Auto-generated by BoreholeIQ v2</description>
  </project>
"#));

    // Borehole / Sampling Feature
    xml.push_str(&format!(r#"  <samplingFeature>
    <SamplingPoint gml:id="{}">
      <gml:name>{}</gml:name>
"#, xml_escape(&bh.hole_id), xml_escape(&bh.hole_id)));

    // Location
    if let (Some(e), Some(n)) = (bh.easting, bh.northing) {
        xml.push_str(&format!(r#"      <location>
        <gml:Point>
          <gml:pos>{:.6} {:.6}</gml:pos>
        </gml:Point>
      </location>
"#, e, n));
    }

    if let Some(el) = bh.elevation {
        xml.push_str(&format!("      <elevation>{:.2}</elevation>\n", el));
    }
    if let Some(fd) = bh.final_depth {
        xml.push_str(&format!("      <totalDepth>{:.2}</totalDepth>\n", fd));
    }

    xml.push_str("    </SamplingPoint>\n  </samplingFeature>\n\n");

    // Geology observations
    for (i, layer) in bh.layers.iter().enumerate() {
        xml.push_str(&format!(r#"  <observation>
    <LithologyDescription gml:id="{}-GEOL-{}">
      <relatedSamplingFeature>{}</relatedSamplingFeature>
      <depthTop>{:.2}</depthTop>
      <depthBase>{:.2}</depthBase>
      <description>{}</description>
"#, xml_escape(&bh.hole_id), i+1, xml_escape(&bh.hole_id),
        layer.top, layer.base, xml_escape(&layer.description)));
        if let Some(ref leg) = layer.legend_code {
            xml.push_str(&format!("      <classificationCode>{}</classificationCode>\n", xml_escape(leg)));
        }
        xml.push_str("    </LithologyDescription>\n  </observation>\n\n");
    }

    // SPT results
    for (i, spt) in bh.spts.iter().enumerate() {
        xml.push_str(&format!(r#"  <observation>
    <StandardPenetrationTest gml:id="{}-SPT-{}">
      <relatedSamplingFeature>{}</relatedSamplingFeature>
      <depth>{:.2}</depth>
"#, xml_escape(&bh.hole_id), i+1, xml_escape(&bh.hole_id), spt.depth));
        if let Some(n) = spt.n_value {
            xml.push_str(&format!("      <nValue>{}</nValue>\n", n));
        }
        xml.push_str("    </StandardPenetrationTest>\n  </observation>\n\n");
    }

    xml.push_str("</Diggs>\n");
    xml
}

fn xml_escape(s: &str) -> String {
    s.replace('&', "&amp;").replace('<', "&lt;").replace('>', "&gt;")
     .replace('"', "&quot;").replace('\'', "&apos;")
}

