/// Page classifier: identifies the type of each page in a geotechnical report
/// before extraction begins. Prevents narrative text from being interpreted
/// as depth-interval records (the most common source of garbage data).
///
/// Based on validated enterprise research recommendations (Stage 2 of pipeline).

#[derive(Debug, Clone, PartialEq)]
pub enum PageType {
    BoreholeLog,        // Multi-column depth-structured log sheet
    ContinuationSheet,  // Continuation of a borehole log (Sheet X of Y)
    LabCertificate,     // Laboratory test certificate
    NarrativeText,      // Prose sections (geological interpretation, etc.)
    CoverPage,          // Title page, table of contents
    SitePlan,           // Map or plan view
    Unknown,            // Cannot classify — treat as potential borehole log
}

/// Classification result for a single page.
#[derive(Debug, Clone)]
pub struct PageClassification {
    pub page_number: usize,
    pub page_type: PageType,
    pub confidence: f64,
    pub reason: String,
}

/// Classify a page based on its OCR text content.
/// Uses keyword density and structural signals to determine page type.
pub fn classify_page(text: &str, page_number: usize) -> PageClassification {
    let upper = text.to_uppercase();
    let line_count = text.lines().count();
    let char_count = text.len();

    // Score accumulators
    let mut borehole_score: f64 = 0.0;
    let mut narrative_score: f64 = 0.0;
    let mut cover_score: f64 = 0.0;
    let mut lab_score: f64 = 0.0;

    // ── Borehole log signals ─────────────────────────────────
    let bh_keywords = [
        // English
        "DEPTH", "STRATIGRAPHY", "LITHOLOGY", "SPT", "N-VALUE", "BLOW COUNT",
        "SAMPLE", "BOREHOLE", "BH-", "BH ", "GEOL", "LEGEND", "DESCRIPTION",
        "SOIL", "CLAY", "SAND", "SILT", "GRAVEL", "ROCK", "FILL",
        "DRILLING METHOD", "GROUND LEVEL", "WATER LEVEL",
        // Indonesian / Malay
        "KEDALAMAN", "LEMPUNG", "PASIR", "LANAU", "KERIKIL", "GAMBUT",
        "TANAH", "BATUAN", "PEMBORAN", "TITIK BOR", "HASIL UJI",
        "DESKRIPSI TANAH", "JENIS TANAH", "PENGEBORAN",
        // Vietnamese
        "DO SAU", "DAT SET", "CAT", "SOI", "DA", "MUC NUOC",
        "KHOAN", "LO KHOAN", "MO TA DIA CHAT",
        // Thai (romanized keywords that appear in English-language Thai reports)
        "BOREHOLE LOG", "SOIL PROFILE", "SOIL DESCRIPTION",
        // Filipino
        "LUPA", "BUHANGIN", "GRABA",
        // Singapore
        "AGS", "LOCA", "BCA",
    ];
    for kw in &bh_keywords {
        if upper.contains(kw) { borehole_score += 2.0; }
    }

    // Depth patterns (numbers that look like depth values)
    let depth_pattern_count = text.lines()
        .filter(|l| {
            let trimmed = l.trim();
            // Lines starting with a number followed by decimal (like "3.50" or "12.00")
            trimmed.len() > 2 && trimmed.chars().next().map(|c| c.is_ascii_digit()).unwrap_or(false)
                && trimmed.contains('.')
        })
        .count();
    borehole_score += (depth_pattern_count as f64).min(15.0);

    // Multi-column indicator: many short lines suggest tabular layout
    let short_lines = text.lines().filter(|l| l.trim().len() < 40 && l.trim().len() > 2).count();
    if short_lines > line_count / 2 && line_count > 10 {
        borehole_score += 10.0;
    }

    // Continuation sheet signals
    let is_continuation = upper.contains("SHEET") && (upper.contains(" OF ") || upper.contains("/"))
        && !upper.contains("DATA SHEET");

    // ── Narrative signals ────────────────────────────────────
    let narrative_keywords = [
        "INTRODUCTION", "CONCLUSION", "RECOMMENDATION", "SUMMARY",
        "GEOLOGICAL", "INTERPRETATION", "DISCUSSION", "METHODOLOGY",
        "SCOPE OF WORK", "REFERENCE", "APPENDIX",
    ];
    for kw in &narrative_keywords {
        if upper.contains(kw) { narrative_score += 3.0; }
    }
    // Long lines suggest prose
    let long_lines = text.lines().filter(|l| l.trim().len() > 80).count();
    if long_lines > line_count / 3 && line_count > 5 {
        narrative_score += 10.0;
    }

    // ── Cover page signals ───────────────────────────────────
    let cover_keywords = [
        "REPORT", "PREPARED FOR", "PREPARED BY", "TABLE OF CONTENTS",
        "SITE INVESTIGATION", "GROUND INVESTIGATION", "GEOTECHNICAL",
        "CONFIDENTIAL", "REVISION", "ISSUE DATE",
    ];
    for kw in &cover_keywords {
        if upper.contains(kw) { cover_score += 2.0; }
    }
    // Very few lines suggest a title page
    if line_count < 20 && char_count < 500 { cover_score += 5.0; }

    // ── Lab certificate signals ──────────────────────────────
    let lab_keywords = [
        "LABORATORY", "ATTERBERG", "LIQUID LIMIT", "PLASTIC LIMIT",
        "PARTICLE SIZE", "GRADING", "CONSOLIDATION", "TRIAXIAL",
        "COMPRESSIVE STRENGTH", "MOISTURE CONTENT", "SPECIFIC GRAVITY",
        "TEST CERTIFICATE", "TEST RESULT", "SAMPLE NO",
    ];
    for kw in &lab_keywords {
        if upper.contains(kw) { lab_score += 3.0; }
    }

    // ── Determine winner ─────────────────────────────────────
    let scores = [
        (borehole_score, PageType::BoreholeLog, "borehole log keywords + depth patterns"),
        (narrative_score, PageType::NarrativeText, "narrative prose signals"),
        (cover_score, PageType::CoverPage, "cover page / metadata signals"),
        (lab_score, PageType::LabCertificate, "laboratory test signals"),
    ];

    let (best_score, best_type, reason) = scores.iter()
        .max_by(|a, b| a.0.partial_cmp(&b.0).unwrap())
        .map(|(s, t, r)| (*s, t.clone(), r.to_string()))
        .unwrap_or((0.0, PageType::Unknown, "no classification signals".into()));

    // Confidence: how much the winner beats the runner-up
    let mut sorted_scores: Vec<f64> = scores.iter().map(|(s, _, _)| *s).collect();
    sorted_scores.sort_by(|a, b| b.partial_cmp(a).unwrap());
    let margin = if sorted_scores.len() >= 2 { sorted_scores[0] - sorted_scores[1] } else { sorted_scores[0] };
    let confidence = (margin / (best_score.max(1.0))).min(1.0);

    let final_type = if is_continuation {
        PageType::ContinuationSheet
    } else if best_score < 3.0 {
        PageType::Unknown
    } else {
        best_type
    };

    PageClassification {
        page_number,
        page_type: final_type,
        confidence,
        reason,
    }
}

/// Classify all pages and return only the ones suitable for borehole extraction.
/// Logs skipped pages so the user knows what was excluded.
pub fn filter_borehole_pages(page_texts: &[(usize, String)]) -> Vec<(usize, String, PageClassification)> {
    let mut results = Vec::new();
    for (page_num, text) in page_texts {
        let classification = classify_page(text, *page_num);
        match classification.page_type {
            PageType::BoreholeLog | PageType::ContinuationSheet | PageType::Unknown => {
                results.push((*page_num, text.clone(), classification));
            }
            _ => {
                log::info!("Page {}: classified as {:?} (confidence {:.0}%) — excluded from borehole extraction",
                    page_num, classification.page_type, classification.confidence * 100.0);
            }
        }
    }
    results
}
